/* techniques q03 (246 mục) — engine-API đợt 361-363 Ch.363 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]=window.__LIBQ["pham-nhan-tu-tien"]["q03"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]["techniques"]={"updatedAt":"2026-07-09","count":246,"techniques":[{"id":"song-tu-thuat","name":"Song tu thuật","cn":null,"loai":"cong-phap-can-ban","loaiLabel":"Công pháp căn bản — song tu","phamCap":"Không rõ cấp (bí thuật tông môn)","hePhai":"Yểm Nguyệt tông","soHuu":["Yểm Nguyệt tông (độc quyền)"],"blurb":"Công pháp tu luyện đặc trưng của Yểm Nguyệt tông — tu theo cặp nam nữ, tăng tiến nhanh hơn đơn tu. Là lý do Yểm Nguyệt tông thu đệ tử ít nhất phân nửa là nữ với dung mạo thượng đẳng. Chính-tà đều xem là công pháp tà đạo.","detail":"Đề cập c178: Lý Sư Tổ giải thích lý do đoàn Yểm Nguyệt tông có nhiều nữ tu dung mạo thượng đẳng — vì họ tu Song tu thuật, cần đệ tử nữ đẹp để song tu cùng đệ tử nam. Công pháp bí thuật tông môn không công bố chi tiết.","nguon":["c0178"]},{"id":"vo-hinh-don-phap","name":"Vô hình độn pháp","cn":null,"loai":"phap-thuat","loaiLabel":"Pháp thuật — ẩn hình cơ động","phamCap":"Cực cao (danh chấn tu tiên giới)","hePhai":"Khung tiền bối (độc sáng/độc luyện)","soHuu":["Khung tiền bối (sáng lập/sử dụng)"],"blurb":"Pháp thuật ẩn hình đỉnh cao do Khung tiền bối sáng lập hoặc độc luyện, danh chấn tu tiên giới. Kích hoạt tức thì — thân hình mơ hồ rồi biến mất hoàn toàn trong không trung, không để lại âm thanh hay khí tức. Ngay cả Nguyên Anh kỳ cũng khó truy tung.","detail":"Xuất hiện c176: Phù Vân Tử và Lý sư tổ nhắc Khung tiền bối nổi danh Vô hình độn pháp. Dùng c178: Khung tiền bối khẽ cười, thân hình mơ hồ biến mất trong không trung tức thì trước mắt mọi người; để lại giọng cười quái dị vang vọng. Đây cũng là nền tảng sáng lập Vô hình châm.","nguon":["c0176","c0177","c0178"]},{"id":"an-hinh-thuat","name":"Ẩn hình thuật","cn":null,"loai":"phap-thuat","loaiLabel":"Pháp thuật — ẩn hình","phamCap":"Trung cấp (Hàn Lập dùng trong cấm địa)","hePhai":"Không rõ (Hàn Lập tự luyện hoặc học từ Hoàng Phong cốc)","soHuu":["Hàn Lập"],"blurb":"Pháp thuật ẩn hình để tránh bị phát hiện. Hàn Lập dùng trong cấm địa Huyết Cấm để quan sát từ xa mà không lộ tung tích. Hiệu quả đủ để quan sát ván giết người giữa Linh Thú Sơn và đệ tử Thiên Khuyết Bảo mà không bị phát hiện.","detail":"Dùng c180: Hàn Lập dùng Ẩn hình thuật tàng hình, ẩn sau bụi cây quan sát từ xa khi phát hiện nhóm Vu sư huynh đang dụ-giết đệ tử Thiên Khuyết Bảo tại Ô Long đàm.","nguon":["c0180"]},{"id":"bang-truy-thuat","name":"Băng trùy thuật","cn":null,"loai":"phap-thuat","loaiLabel":"Pháp thuật — tấn công băng hệ","phamCap":"Trung cấp (Linh Thú Sơn tu sĩ dùng)","hePhai":"Linh Thú Sơn (hoặc băng hệ công pháp)","soHuu":["Vu sư huynh và đồng bọn Linh Thú Sơn"],"blurb":"Pháp thuật tấn công băng hệ của Linh Thú Sơn. Tạo ra trùy (chùy) băng đánh lén mục tiêu. Vu sư huynh dùng kết hợp với Khu thú phấn và Hàn băng thiềm để giết đệ tử Thiên Khuyết Bảo từ hai phía trong cấm địa.","detail":"Dùng c180: Vu sư huynh phát động Băng trùy thuật từ phía trước kết hợp đám Hàn băng thiềm (bị Khu thú phấn khống chế) tấn công từ sau lưng, cùng lúc đánh lén đệ tử Thiên Khuyết Bảo tại Ô Long đàm — giết chết hắn.","nguon":["c0180"]},{"id":"liem-khi-thuat","name":"Liễm khí thuật","loai":"cong-phap","loaiLabel":"Công pháp ẩn tức","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Thuật thu liễm khí tức, giúp người dùng giấu hoàn toàn hơi thở tu vi.","detail":"Thuật giúp thu liễm khí tức để tránh bị phát hiện. Trong cấm địa Huyết sắc thí luyện, Hàn Lập vận Liễm khí thuật đến cực hạn, thu hết khí tức không lộ ra chút nào, nhờ đó ẩn nấp bên cạnh hai đệ tử Linh thú sơn mà không bị lộ thân phận.","nguon":["@c0181"]},{"id":"thu-phap-khu-thu-linh-thu-son","name":"Thủ pháp khu thú Linh thú sơn","cn":"","loai":"than-thong","loaiLabel":"Thần thông khu sử","phamCap":"Không rõ","hePhai":"Linh thú sơn","soHuu":[],"blurb":"Thủ đoạn điều khiển thú-trùng cổ quái, bí truyền của đệ tử Linh thú sơn.","detail":"Thủ pháp khu sử thú vật và côn trùng cổ quái, quỷ dị, là sở trường bí mật của Linh thú sơn. Trong chương thể hiện qua việc hai đệ tử khu sử bầy bươm bướm biến màu làm lưới cảnh giới sống; Hàn Lập kiêng kị thủ đoạn này nên chọn đi vòng để tránh bị phát hiện.","nguon":["@c0181"]},{"id":"liem-tuc-thuat","name":"Liễm tức thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Thuật thu liễm pháp lực bản thân, khiến người khác dùng thần niệm cũng không tìm ra khí tức.","detail":"Thuật thu liễm khí tức: người dùng ém pháp lực khiến thần niệm đối phương không dò thấy dị thường. Hàn Lập dựa vào việc thần niệm không phát hiện linh khí bất thường để suy ra không có người dùng Liễm tức thuật nấp gần.","nguon":["@c0182"]},{"id":"khinh-cong-tuyet-the","name":"Khinh công tuyệt thế (thế tục)","cn":"","loai":"luyen-the","loaiLabel":"Võ công thế tục","phamCap":"Võ công thế tục","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Võ công khinh công thế tục của Hàn Lập; dù có cũng không đủ để trèo qua vách núi cao dựng đứng của Nhất tuyến thiên.","detail":"Được nhắc khi Hàn Lập cân nhắc thoát khỏi thế bị chặn — dù có khinh công thế tục cũng không dám trèo lên vách núi cao vòi vọi hai bên Nhất tuyến thiên.","nguon":["@c0183"]},{"id":"ti-tuyen-thu-doan-giet-vo-hinh","name":"Ti tuyến trong suốt (thủ đoạn giết vô hình)","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Thủ đoạn giết vô hình của Hàn Lập: cách không vung tay như chào hỏi, đối phương thấy cổ ngứa như muỗi cắn rồi đầu lìa, người chia hai.","detail":"Hàn Lập sử dụng ti tuyến trong suốt để cách không giết chết địch; từng dùng xử lý một người tầng mười hai, ở đây chém đầu người Thiên khuyết bảo chỉ trong nháy mắt.","nguon":["@c0184"]},{"id":"khien-dan-thuat","name":"Khiên dẫn thuật","loai":"than-thong","loaiLabel":"Pháp thuật cảm ứng","phamCap":"Không rõ","hePhai":"Hoàng Phong cốc","soHuu":["Chung Linh Đạo"],"blurb":"Pháp thuật cảm ứng do Chưởng môn Chung Linh Đạo thi triển cho đệ tử Hoàng Phong cốc, giúp cảm ứng vị trí đồng môn trong phạm vi để trợ giúp nhau.","detail":"Trước khi xuất phát, Chưởng môn Chung Linh Đạo thi triển Khiên dẫn thuật cho đệ tử Hoàng Phong cốc, cho phép đệ tử trong phạm vi cảm ứng vị trí lẫn nhau nhằm hợp lực tăng khả năng chiến thắng; hiệu lực kéo dài mười ngày. Các phái khác cũng có pháp thuật tương tự. Chính nhờ pháp thuật này mà nữ áo vàng tìm được nơi ẩn thân của Hàn Lập.","nguon":["@c0186"]},{"id":"la-yen-bo","name":"La yên bộ","cn":"","loai":"cong-phap","loaiLabel":"Thân pháp","phamCap":"Võ công giang hồ","hePhai":"Võ công thế tục","soHuu":["Hàn Lập"],"blurb":"Thân pháp khinh linh dùng làm mốc so sánh tốc độ; thân pháp nhanh như tia chớp của Phong Nhạc được đánh giá không dưới La yên bộ.","detail":"La yên bộ là một loại thân pháp được Hàn Lập lấy làm mốc so sánh khi đánh giá tốc độ di chuyển của Phong Nhạc. Trong trận đấu, thấy thân pháp của Phong Nhạc quỷ dị nhanh như tia chớp, Hàn Lập nhận định tốc độ ấy không dưới La yên bộ. Chính điều này khiến kế hoạch dùng số kim nhận bao vây thu hút chú ý rồi đánh lén bằng Kim quang chuyên trở thành vọng tưởng — đối phương né tránh quá dễ dàng. Việc cả hai cùng sở hữu thân pháp thuộc dạng võ công giang hồ khiến Hàn Lập nghi ngờ Phong Nhạc cũng là người mang võ công thế tục như mình.","nguon":["@c0188","@c0350"],"tabs":{"tienTrinh":[{"chuong":"@c0350","loai":"thi triển","importance":"normal","giaiDoan":"Tập kích hai tu sĩ Phó gia","text":"Hàn Lập thi triển La Yên Bộ phối hợp Thần Phong Chu để vòng ra sau hai tu sĩ Phó gia, phục vụ đòn ti tuyến tất sát.","anchor":"Còn mình thì sử dụng La Yên Bộ cùng với Thần Phong Chu"}]},"congNang":["Áp sát sau lưng đối thủ khi phối hợp với Thần Phong Chu @c0350"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0350","tangDatToi":"Không rõ","trangThai":"đang dùng"}]},{"id":"bang-mau-thuat","name":"Băng Mâu Thuật","loai":"bi-thuat","loaiLabel":"Phù lục thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Phong Nhạc"],"blurb":"Phù lục thuật của Phong Nhạc, hóa thành một mâu bằng băng trong suốt nghênh đón.","detail":"Phong Nhạc dùng phù lục Băng Mâu Thuật hóa thành một mâu bằng băng trong suốt, chấn bay ba bốn viên Hỗn Nguyên Châu; các viên vỡ đóng băng tạo thành mưa băng.","nguon":["@c0189"]},{"id":"hoa-dan-thuat","name":"Hỏa đạn thuật","loai":"bi-thuat","loaiLabel":"Pháp thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thuật hỏa cầu Hàn Lập dùng để thiêu hủy thi thể và đào hố mai táng.","detail":"Pháp thuật tạo hỏa cầu; Hàn Lập thả hai hỏa cầu thiêu nửa cặp chân còn lại của Phong Nhạc hủy thi diệt tích, mọi thứ hóa tro trừ đôi giày pháp khí; cũng dùng tiểu hỏa cầu đào hố mai táng nữ tử áo vàng.","nguon":["@c0190"]},{"id":"thien-nhan-thuat","name":"Thiên Nhãn thuật","loai":"bi-thuat","loaiLabel":"Pháp thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Lưu Tĩnh"],"blurb":"Thuật tăng nhãn lực của người tu tiên.","detail":"Thuật tăng cường nhãn lực; ngay cả khi dùng cũng chỉ thấy Hàn Lập như bóng nhàn nhạt khi hắn toàn lực thi triển thân pháp cực tốc kết hợp giày pháp khí, La Yên bộ và Ngự Phong quyết.","nguon":["@c0190","@c0320"]},{"id":"bang-truy-thuat-yem-nguyet-tong","name":"Băng Trùy thuật","loai":"bi-thuat","loaiLabel":"Bí thuật","hePhai":"Yểm Nguyệt tông","soHuu":["Nữ đệ tử Yểm Nguyệt tông (Yểm Nguyệt song kiều)","Nam đệ tử Yểm Nguyệt tông"],"blurb":"Thuật băng của đệ tử Yểm Nguyệt tông, tạo ra băng trùy đâm vào đất cát để lùng sục mục tiêu ẩn nấp.","detail":"Cặp đệ tử Yểm Nguyệt tông dùng Băng Trùy thuật đâm băng trùy vào đất cát vùng phía nam khu trung tâm suốt nửa ngày để tìm cô gái áo lục ẩn dưới cát, nhưng không phát hiện được nàng.","nguon":["@c0191"]},{"id":"ngu-phong-quyet","name":"Ngự phong quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Phong hệ","soHuu":["Hàn Lập"],"blurb":"Công pháp gia tốc giúp tăng tốc độ di chuyển.","detail":"Công pháp tăng tốc của Hàn Lập. Khi bị hai phi xà truy đuổi trong khu trung tâm, hắn cố tình không thi triển Ngự phong quyết để tránh gánh nặng lên thân thể vì thể lực chưa hồi phục sau hai trận ác đấu, đã có linh ngoa hỗ trợ tốc độ.","nguon":["@c0192"]},{"id":"thach-phu-thuat","name":"Thạch Phu thuật","cn":"","loai":"than-thong","loaiLabel":"Thuật trời sinh của yêu thú","phamCap":"Cấp thấp","hePhai":"Thôi Sơn thú (yêu thú)","soHuu":["Thôi Sơn thú"],"blurb":"Thuật trời sinh của yêu thú Thôi Sơn thú, phủ hộ giáp nham thạch trắng sáng lên toàn thân khi lâm chiến.","detail":"Thôi Sơn thú — yêu thú cấp thấp thường gặp trên núi lửa — trời sinh biết Thạch Phu thuật. Khi lâm chiến, toàn thân nó phủ một lớp hộ giáp nham thạch trắng sáng lên để phòng ngự.","nguon":["@c0196"]},{"id":"vong-bao-ho-tho-thuoc-tinh","name":"Vòng bảo hộ thổ thuộc tính","loai":"than-thong","loaiLabel":"Thần thông phòng hộ","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Vòng bảo hộ thuộc tính thổ tạo quanh người để phòng thân khi đi trong bóng tối, đổi lại giảm nhiều sự nhanh nhẹn.","detail":"Hàn Lập vỗ nhẹ tạo một vòng bảo hộ thổ thuộc tính quanh người khi đi trong động tối cho an tâm. Đổi lại, lớp phòng hộ này khiến hắn giảm nhiều sự linh hoạt, nên trước khi khiêu khích con rết hắn đã bỏ vòng bảo hộ để né tránh.","nguon":["@c0197"]},{"id":"linh-ho-bo","name":"Linh Hồ bộ","cn":"","loai":"than-thong","loaiLabel":"Thân pháp","phamCap":"Không rõ","hePhai":"Thanh Hư môn","soHuu":["Phù Vân Tử"],"blurb":"Thân pháp bộ pháp của trung niên đạo sĩ Thanh Hư môn, cực nhanh, chớp mắt vượt qua bám sát sau lưng đối phương ngoài một trượng.","detail":"Phù Vân Tử thi triển Linh Hồ bộ, chỉ trong chớp mắt đã vượt qua khoảng cách bám sau lưng thanh niên áo lam để cảnh cáo, được lão giả áo xanh khen xuất thần nhập hóa.","nguon":["@c0198"]},{"id":"ngan-phu-thuat-tran-dai-ca","name":"Ngân phù","cn":"","loai":"than-thong","loaiLabel":"Thần thông / phù pháp","phamCap":"Không rõ","hePhai":"Trần thị gia tộc / Hoàng Phong cốc","soHuu":["Trần đại công tử"],"blurb":"Phù pháp Trần đại ca thi triển bằng Ngân bút, tạo vô số điểm sáng như sao đầy trời phủ khắp thiên địa.","detail":"Trần đại công tử dùng Ngân bút thi triển ngân phù, kim quang khắp trời đất tạo vô số điểm sáng như sao đầy trời, kết hợp Kim thư tạo uy lực lớn dọa lui phe đối thủ tranh linh thảo.","nguon":["@c0199"]},{"id":"am-duong-khien-dan-thuat","name":"Âm Dương Khiên Dẫn thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật hợp kích","phamCap":"Bí pháp hợp kích Yểm Nguyệt tông","hePhai":"Yểm Nguyệt tông","soHuu":["Cô gái áo trắng (Sư tổ Yểm Nguyệt tông)"],"blurb":"Bí pháp hợp kích mới luyện thành của đệ tử Yểm Nguyệt tông: từng đôi đồng loạt ra tay, lực sát thương bằng đệ tử Trúc Cơ kỳ toàn lực tấn công một kích.","detail":"Pháp thuật hợp kích được đệ tử Yểm Nguyệt tông sử dụng theo cặp, phối hợp âm dương. Khi từng đôi đồng loạt ra tay, sức công kích tương đương một đòn toàn lực của đệ tử Trúc Cơ kỳ. Được dùng để hợp kích diệt yêu thú đỉnh cấp Bích Thủy ngạc dưới sự chỉ huy của Sư tổ.","nguon":["@c0200"]},{"id":"than-phap-bien-ao-han-lap","name":"Thân pháp biến ảo khó lường","loai":"than-thong","loaiLabel":"Thân pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thân pháp biến ảo mà Hàn Lập dựa vào để né tránh khi đối đầu ngân kiếm uy lực quá mạnh.","detail":"Trong trận đấu với Vũ Si, do cự kiếm màu bạc uy lực khủng khiếp có thể chém phá vòng bảo hộ bình thường, Hàn Lập cố ý không dùng phòng ngự phù lục mà chọn dựa vào thân pháp biến ảo khó lường để tránh né.","nguon":["@c0201"]},{"id":"phap-quyet-dieu-khien-ngan-kiem","name":"Pháp quyết điều khiển ngân kiếm","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cự kiếm môn","soHuu":["Hán tử áo đen chân trần (Cự Kiếm môn)"],"blurb":"Pháp quyết kỳ quái của đại hán Cự kiếm môn, xoay chuôi ngân kiếm biến thành vùng sáng bạc có hấp lực hút và nghiền nát pháp khí.","detail":"Đại hán chân trần dùng hai tay bay múa xoay vòng, biến cự kiếm màu bạc thành một vùng sáng bạc có hấp lực. Vùng sáng này hút pháp khí của địch vào lốc xoáy rồi nghiền nát, đồng thời có thể cắt đứt liên hệ điều khiển pháp khí của đối phương. Kim nhận đỉnh cấp của Hàn Lập bị hút không nhúc nhích, hai thượng phẩm pháp khí và một kim nhận bị cuốn hủy.","nguon":["@c0202"]},{"id":"vo-uu-cham-phap","name":"Vô ưu châm pháp","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Di vật Mặc đại phu","soHuu":["Hàn Lập"],"blurb":"Bộ châm pháp Hàn Lập học từ di vật Mặc đại phu, dùng ngân châm để xóa trí nhớ người khác trong một khoảng thời gian.","detail":"Vô ưu châm pháp là bộ châm pháp Hàn Lập lĩnh hội từ di vật của Mặc đại phu tại tu tiên giới. Khi thi triển, hắn dùng bộ ngân châm đâm vào các huyệt vị để xóa đi trí nhớ của đối phương trong một khoảng thời gian nhất định. Kết hợp với Vong Trần hoàn, châm pháp đạt tới mức hoàn mỹ, giúp Hàn Lập xóa sạch trí nhớ nửa ngày của Hạm Vân Chi nhằm bảo vệ bí mật của mình.","nguon":["@c0203"]},{"id":"nac-hinh-thuat","name":"Nặc hình thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật ẩn thân","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thuật ẩn thân giúp thu liễm khí tức và hòa thân vào mặt đất, từ xa nhìn không phát hiện được tung tích.","detail":"Hàn Lập thi triển Nặc hình thuật toàn lực khi đám Yểm Nguyệt tông tiến vào thế giới đầm lầy: hắn thu liễm khí tức, ép sát vào sau một mô đất, hòa mình vào mặt đất khiến từ xa nhìn không thể phát hiện. Nhờ thuật này hắn ẩn nấp an toàn thay vì mạo hiểm tranh đoạt hộp vàng bảo vật.","nguon":["@c0204"]},{"id":"cam-che-thach-dien-cam-dia","name":"Cấm chế thạch điện","cn":"","loai":"khac","loaiLabel":"Cấm chế / Trận pháp","phamCap":"Cao (bài xích thần thức Kết đan kỳ)","hePhai":"","soHuu":[],"blurb":"Cấm chế mạnh thi trên tòa thạch điện cổ trong cấm địa, thanh quang lờ mờ lưu động trên bề mặt và bài xích cả thần thức tu sĩ Kết đan kỳ.","detail":"Cấm chế bao phủ thạch điện cổ quái giữa vùng lòng chảo: bề mặt đá có thanh quang lờ mờ lưu động, ném pháp khí vào bị bắn xa mấy trượng còn điện thì bình yên vô sự. Khi sư tổ Yểm Nguyệt tông phóng thần thức khổng lồ đảo qua, thần thức bị một lực lượng bài xích không thể xuyên qua — lần đầu tiên nàng gặp cấm chế mạnh đến vậy, khiến nàng hưng phấn muốn tiến vào.","nguon":["@c0204"]},{"id":"than-phap-than-toc-han-lap","name":"Thân pháp thần tốc","cn":"","loai":"than-thong","loaiLabel":"Thân pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thân pháp thần tốc của Hàn Lập cho phép chớp thân di chuyển cực nhanh, nhưng tiêu hao thể lực lớn nên chỉ dùng được vài lần.","detail":"Thân pháp giúp Hàn Lập chớp biến thân hình di chuyển thần tốc. Trong thạch điện, do hai ngày qua thể lực đã tiêu hao quá nhiều, hắn chỉ còn có thể dùng được vài lần và chạy không xa, buộc phải tìm chỗ trốn xuống địa đạo.","nguon":["@c0204"]},{"id":"song-tu-yem-nguyet-tong","name":"Song tu Yểm Nguyệt tông","cn":"","loai":"cong-phap","loaiLabel":"Công pháp song tu","phamCap":"Không rõ","hePhai":"Yểm Nguyệt tông","soHuu":["Nữ tử áo dài trắng (Yểm Nguyệt tông)"],"blurb":"Công pháp song tu của Yểm Nguyệt tông: đệ tử nam nữ nắm tay đạo lữ phát hào quang lam hồng, tạo cột sáng hồng lam công kích.","detail":"Đệ tử nam nữ Yểm Nguyệt tông theo lệnh nắm tay đạo lữ song tu, phát ra hào quang hai sắc lam hồng — nam giới được màn hào quang màu hồng hộ thể, nữ tỏa lam quang. Nhờ song tu, họ hợp lực phóng ra những cột sáng hồng lam công kích yêu thú. Đệ tử mất đạo lữ song tu chỉ còn dùng vài pháp khí bình thường.","nguon":["@c0205"]},{"id":"ngu-tu-ngon-quyet-yem-nguyet-tong","name":"Ngũ tự ngôn quyết (Thu, tốc, câu, cấm, tỏa)","cn":"","loai":"bi-thuat","loaiLabel":"Khẩu quyết khống chế","phamCap":"Không rõ","hePhai":"Yểm Nguyệt tông","soHuu":["Cô gái áo trắng (Sư tổ Yểm Nguyệt tông)"],"blurb":"Khẩu quyết năm chữ “Thu, tốc, câu, cấm, tỏa” dùng điều khiển Chu tước hoàn biến mất rồi hiện tại đỉnh đầu yêu thú để giam thân nó.","detail":"Cô gái sư tổ Yểm Nguyệt tông đọc ngũ tự ngôn quyết “Thu, tốc, câu, cấm, tỏa” khiến pháp bảo Chu tước hoàn biến mất rồi lập tức hiện tại đỉnh đầu Mặc Giao, chụp và giam toàn bộ thân yêu thú trong lửa đỏ.","nguon":["@c0205"]},{"id":"hong-viem-thuat","name":"Hồng viêm thuật","cn":"","loai":"than-thong","loaiLabel":"Hỏa thuật","phamCap":"Không rõ","hePhai":"Yểm Nguyệt tông","soHuu":["Cô gái áo trắng (Sư tổ Yểm Nguyệt tông)"],"blurb":"Hỏa thuật cô gái sư tổ thúc dục trên Chu tước hoàn, làm ngọn lửa bao vây yêu thú bùng nổ mãnh liệt.","detail":"Cô gái sư tổ Yểm Nguyệt tông thúc dục Hồng viêm thuật trên pháp bảo Chu tước hoàn, khiến ngọn lửa đỏ giam yêu thú bùng nổ mạnh hơn, gia tăng sức khống chế và sát thương.","nguon":["@c0205"]},{"id":"lan-hoa-phap-quyet","name":"Lan hoa pháp quyết","cn":"","loai":"bi-thuat","loaiLabel":"Thủ ấn khu sử","phamCap":"Không rõ","hePhai":"Yểm Nguyệt tông","soHuu":["Cô gái áo trắng (Sư tổ Yểm Nguyệt tông)"],"blurb":"Thủ ấn cô gái sư tổ bắt để tâm thần tương liên với Chu tước hoàn khi khu sử pháp bảo.","detail":"Khi khu sử Chu tước hoàn, cô gái sư tổ Yểm Nguyệt tông kết Lan hoa pháp quyết để tâm thần tương liên với pháp bảo, điều khiển cột lửa lớn phun vào cột bùn yêu thú.","nguon":["@c0205"]},{"id":"mac-van-ho-the","name":"Mặc vân hộ thể","cn":"","loai":"than-thong","loaiLabel":"Hộ thể yêu thú","phamCap":"Không rõ","hePhai":"Mặc Giao","soHuu":["Mặc Giao"],"blurb":"Tầng hắc vụ nhạt bao phủ thân yêu thú Mặc Giao, cản được cột sáng hồng lam của đệ tử Yểm Nguyệt tông.","detail":"Mặc Giao có tầng hắc vụ nhạt (mặc vân) bao phủ thân, dùng làm hộ thể cản mười mấy cột sáng hồng lam. Sau bị đánh tan để lộ lân giáp bị đục lỗ máu to bằng bát.","nguon":["@c0205"]},{"id":"tieu-ngu-hanh-tu-di-cam-phap","name":"Tiểu ngũ hành tu di cấm pháp","cn":"","loai":"bi-thuat","loaiLabel":"Cấm pháp","phamCap":"Trung cấp","hePhai":"","soHuu":["Triệu sư muội (nữ tử áo trắng)"],"blurb":"Cấm pháp do Tiểu ngũ hành phù phát động, khiến hai bên thông đạo đá ép lại phong bế hoàn toàn.","detail":"Cấm chế phong bế: khi Tiểu ngũ hành phù được kích hoạt, thần quang xanh chấn động mạnh khiến hai bên thông đạo đá ép sát vào nhau kín mít, không còn một khe hở. Nam Cung sư tổ nhận ra và biết cách giải cấm pháp này.","nguon":["@c0206"]},{"id":"ngon-quyet-vay-khon-mac-giao","name":"Ngôn quyết vây khốn Mặc Giao","cn":"","loai":"kiem-quyet","loaiLabel":"Khẩu quyết điều khiển pháp bảo","phamCap":"Không rõ","hePhai":"Yểm Nguyệt tông","soHuu":["Nam Cung Uyển"],"blurb":"Khẩu quyết Nam Cung sư tổ thi triển để dùng Chu tước hoàn giữ chặt thân thể Mặc Giao.","detail":"Nam Cung sư tổ đọc ngôn quyết điều khiển pháp bảo Chu tước hoàn siết giữ yêu thú bất động, tạo điều kiện cho Hàn Lập chuẩn bị phù bảo công kích.","nguon":["@c0206"]},{"id":"the-luyen-ta-mon-ngan-kiem","name":"Phương pháp tế luyện tà môn của nguyên chủ ngân kiếm","loai":"bi-thuat","loaiLabel":"Bí thuật luyện khí","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Phương pháp cực kỳ tà môn dụng tâm luyện ngân kiếm khiến người ngoài không thể khu sử.","detail":"Nguyên chủ ngân kiếm (đại hán chân trần) đã tế luyện cự kiếm bạc bằng phương pháp cực tà môn, khiến với người ngoài kiếm chỉ là phế vật không khu sử được bằng pháp lực, trừ khi luyện lại từ đầu.","nguon":["@c0207"]},{"id":"chan-hoa-luyen-ngan-tinh","name":"Chân hỏa Kết đan kỳ luyện ngân tinh","loai":"bi-thuat","loaiLabel":"Thủ pháp luyện khí","phamCap":"Kết đan kỳ","hePhai":"Không rõ","soHuu":[],"blurb":"Chỉ tu sĩ Kết đan kỳ mới dùng chân hỏa chế luyện lượng lớn thuần ngân thành nguyên liệu ngân tinh trân quý.","detail":"Ngân tinh là nguyên liệu chỉ tu sĩ Kết đan kỳ mới luyện được: dùng chân hỏa nấu luyện lượng lớn thuần ngân, phi thường trân quý; ngân kiếm và Chu tước hoàn đều dùng loại nguyên liệu này.","nguon":["@c0207"]},{"id":"to-nu-luan-hoi-cong","name":"Tố nữ luân hồi công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Độc môn công pháp","hePhai":"","soHuu":["Nữ tử tuyệt sắc (nữ tu Kết đan kỳ)"],"blurb":"Độc môn công pháp của nữ tu Kết đan kỳ, có thể khiến xuân nhan vĩnh trú.","detail":"Độc môn công pháp nữ tử tu luyện, đã đại thành. Cứ cách mười năm luân hồi một lần khiến người biến về lúc nhỏ, giữ dung mạo trẻ trung. Khi bị phá thân xử nữ, công pháp bị phá đi một ít nên người luyện biến lớn lên, tổn thất khoảng năm sáu năm pháp lực.","nguon":["@c0208"]},{"id":"cam-che-tuyet-dia-bach-ngoc-dinh","name":"Cấm chế tuyệt địa (bạch ngọc đình)","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Cấm chế phong bế tuyệt địa nơi bạch ngọc đình, phải hai người hợp lực mới phá được.","detail":"Cấm chế phong bế tuyệt địa nơi Hàn Lập và nữ tử tỉnh dậy. Muốn phá cấm rời đi cần sự hợp lực của hai người, thiếu một người thì không thể rời khỏi nơi đây.","nguon":["@c0208"]},{"id":"phan-than-than-bi-thuat","name":"Phân thân thần bí thuật","aliases":["bí thuật phân thần"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Bí thuật rót một tia thần thức vào pháp khí để khu sử; chỉ tu sĩ Trúc cơ kỳ trở lên đủ thần thức chống đỡ.","detail":"Người tu luyện tách một tia thần thức nhập vào pháp khí để điều khiển. Chỉ tu sĩ từ Trúc cơ kỳ trở lên mới đủ thần thức chống đỡ, còn Luyện khí kỳ phân thần dễ tan biến. Phân thần càng nhiều thì thao túng pháp khí đồng thời càng nhiều; đệ tử Luyện khí kỳ thường chỉ dùng được hai kiện pháp khí cùng lúc.","nguon":["@c0213"]},{"id":"thanh-nguyen-kiem-quyet","name":"Thanh nguyên kiếm quyết","aliases":["Thanh Nguyên kiếm quyết"],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Lý Hóa Nguyên","soHuu":["Hàn Lập"],"blurb":"Quyển công pháp Lý Hóa Nguyên phái người đưa cho Hàn Lập, trên sách có bút tích của Lý sư tổ.","detail":"Công pháp do sư phụ mới Lý Hóa Nguyên phái ký danh đệ tử đưa đến cho Hàn Lập. Trên sách có chữ ký/bút tích của Lý sư tổ; Hàn Lập dùng chính bút tích này làm bằng chứng thân phận để đại hán giữ Nhạc lộc điện tin và an bài gian địa hỏa.","nguon":["@c0213","@c0263","@c0271"]},{"id":"phieu-phu-thuat","name":"Phiêu phù thuật","cn":"","loai":"bi-thuat","loaiLabel":"Pháp thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Pháp thuật khiến vật thể lơ lửng trong không trung.","detail":"Pháp thuật giúp giữ vật lơ lửng, Hàn Lập tu luyện riêng và tốn không ít thời gian để dùng nó treo Ngân ti đỉnh lửng trên bếp lò khi luyện chế Trúc cơ đan.","nguon":["@c0214"]},{"id":"phap-quyet-khu-su-dau-rong","name":"Pháp quyết khu sử đầu rồng","cn":"","loai":"khac","loaiLabel":"Pháp quyết","phamCap":"Không rõ","hePhai":"Địa Hỏa Chi Ốc","soHuu":["Hàn Lập"],"blurb":"Phương pháp điều khiển tám đầu rồng của bếp lò địa hỏa phun và điều tiết lửa.","detail":"Phương pháp khắc trên vách lò, người dùng đánh tám đạo hồng quang vào tám đầu rồng để chúng hấp nạp rồi phun ra địa hỏa, đồng thời điều tiết độ dày mỏng, cao thấp của ngọn lửa. Hàn Lập ghi lại và luyện tập tới thuần thục trước khi luyện đan.","nguon":["@c0214"]},{"id":"truyen-tong-tran-nhac-loc-dien","name":"Truyền tống trận","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Hoàng Phong Cốc","soHuu":[],"blurb":"Trận truyền tống đặt tại Nhạc Lộc điện, có hai người canh giữ luân phiên.","detail":"Trận truyền tống tại Nhạc Lộc điện của Hoàng Phong Cốc, luôn có hai người bảo vệ canh giữ. Khi Hàn Lập ra khỏi điện sau khi Trúc Cơ, ca canh giữ đã đổi thành hai người khác, nên không ai kinh ngạc khi thấy hắn từ Luyện khí kỳ đột nhiên tiến vào Trúc cơ kỳ.","nguon":["@c0216"]},{"id":"kiem-anh-phan-quang-thuat","name":"Kiếm ảnh phân quang thuật","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Pháp quyết ba tầng kiếm quyết cuối của Thanh nguyên kiếm quyết","hePhai":"Thanh nguyên kiếm quyết","soHuu":[],"blurb":"Thần thông từ ba tầng cuối của Thanh nguyên kiếm quyết, huyễn hóa kiếm ảnh giống hệt phi kiếm để mê hoặc tầm mắt địch nhân.","detail":"Pháp quyết của ba tầng kiếm quyết cuối cùng, điều kiện tu luyện là phải có phi kiếm hoặc phi đao. Sau khi thành, có thể từ kiếm quang huyễn hóa ra một đạo kiếm ảnh giống hệt phi kiếm để mê hoặc tầm mắt địch nhân. Kiếm ảnh sơ thành chỉ có một phần mười uy lực bản thể, tăng dần theo tầng, tới tầng thứ chín đạt một phần ba uy lực. Từ tầng thứ bảy trở đi, mỗi tầng có thể luyện thêm một đạo kiếm ảnh, luyện tới cực hạn xuất ra ba đạo kiếm ảnh.","nguon":["@c0217"]},{"id":"ho-the-kiem-thuan","name":"Hộ thể kiếm thuẫn","loai":"cong-phap","loaiLabel":"Công pháp phòng ngự","phamCap":"Pháp quyết trong Thanh nguyên kiếm quyết","hePhai":"Thanh nguyên kiếm quyết","soHuu":["Hàn Lập"],"blurb":"Pháp quyết phòng ngự trong Thanh nguyên kiếm quyết, tạo hộ thuẫn tự động phóng thích kiếm quang phản kích địch nhân.","detail":"Pháp quyết phòng ngự nằm trong Thanh nguyên kiếm quyết. Người tu luyện có thể tạo ra một hộ thuẫn màu xanh nước biển, bề mặt nhô ra những mũi nhọn như con nhím và ẩn chứa sát khí, có khả năng tự động phóng thích kiếm quang phản kích địch nhân khi bị tấn công. Hàn Lập luyện thành trong lúc bế quan tại phòng địa hỏa nhưng chưa có dịp thí nghiệm thực chiến.","nguon":["@c0217"]},{"id":"me-tung-phap-tran","name":"Mê tung pháp trận","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Hoàng phong cốc","soHuu":["Hàn Lập"],"blurb":"Trận pháp nhỏ đơn giản bày ra từ Mê tung kỳ, đủ ngăn phàm nhân và dã thú xâm nhiễm động phủ.","detail":"Loại trận pháp kích thước nhỏ đơn giản nhất, bày ra từ Mê tung kỳ để bảo vệ động phủ, đủ ngăn phàm nhân và dã thú xâm nhiễm. Thủ pháp bày và thao túng trận được ghi trong ngọc giản Chung Linh Đạo giao cho Hàn Lập.","nguon":["@c0219"]},{"id":"ho-trao-thuy-thuoc-tinh","name":"Hộ tráo thủy thuộc tính","loai":"bi-thuat","loaiLabel":"Bí thuật phòng ngự","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Lớp bảo hộ thủy thuộc tính Hàn Lập phóng ra bám thân, ngăn đá vụn và bụi bặm.","detail":"Khi khoét đá cứng để đào đường vào vách núi, Hàn Lập phóng ra một lớp hộ tráo thuộc tính thủy bám lấy thân, chắn đá vụn và bụi bặm bắn ra, giữ người sạch sẽ trong suốt hơn một canh giờ đục đá.","nguon":["@c0220"]},{"id":"cam-che-tran-phap-linh-thu-son","name":"Cấm chế trận pháp Linh thú sơn","loai":"khac","loaiLabel":"Trận pháp phong bế","phamCap":"Không rõ","hePhai":"Kỳ lân các","soHuu":["Kỳ lân các"],"blurb":"Các cấm chế đủ màu chia Linh thú sơn thành nhiều khối phong bế để tuần dưỡng linh thú riêng.","detail":"Linh thú sơn được bố trí nhiều cấm chế trận pháp đủ màu sắc, chia núi thành nhiều khối phong bế tách biệt, mỗi khối tuần dưỡng một loại linh thú, chỉ đệ tử Kỳ lân các mới được ra vào. Toàn sơn nuôi gần ngàn con linh thú nhờ hệ thống cấm chế này.","nguon":["@c0220"]},{"id":"tieu-me-tung-tran","name":"Tiểu mê tung trận","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Trận pháp che dấu cấp thấp","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận che dấu do Hàn Lập bày bằng năm lá cờ nhỏ và mười viên linh thạch cấp thấp, ẩn toàn bộ lối ra vào động phủ.","detail":"Tiểu mê tung trận là trận pháp che dấu Hàn Lập bố trí theo phương pháp ghi trong ngọc giản, dùng năm lá cờ nhỏ cùng mười viên linh thạch cấp thấp. Trận che phủ toàn bộ lối ra vào của động phủ Linh tuyền nham động khiến người bên ngoài chỉ thấy vách núi thông thường, giúp giữ kín mật thất luyện công của hắn.","nguon":["@c0221"]},{"id":"cam-phap-cam-phi-hanh","name":"Cấm pháp cấm phi hành","loai":"khac","loaiLabel":"Cấm pháp","phamCap":"Cấm pháp quy mô phường thị","hePhai":"Thiên Tinh Tông","soHuu":["Thiên Tinh Tông"],"blurb":"Trận cấm bao quanh phường thị Thiên Tinh Tông khiến pháp khí phi hành mất tác dụng.","detail":"Cấm pháp cấm phi hành là trận cấm được bố trí quanh phường thị Thiên Tinh Tông, khiến mọi pháp khí phi hành mất tác dụng và buộc tu sĩ phải hạ xuống đất khi tới gần. Chính dấu hiệu pháp khí hình lá trầm xuống, mất khả năng phi hành đã báo cho Hàn Lập biết hắn đã tới phụ cận phường thị.","nguon":["@c0221"]},{"id":"luc-dich","name":"Lục dịch","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Thủ đoạn thôi thúc dược thảo","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thủ đoạn Hàn Lập dùng để thôi thúc dược thảo sinh trưởng nhanh.","detail":"Lục dịch là thủ đoạn Hàn Lập dùng để thôi thúc dược thảo sinh trưởng vượt bậc. Nhờ nó, sau hai tháng ngắn ngủi hắn đã tạo ra được một gốc linh dược ngàn năm dùng làm vật trao đổi tại Thiên Tinh Tông.","nguon":["@c0221"]},{"id":"luyen-che-yeu-hoa","name":"Luyện chế yêu hỏa luyện khí","loai":"bi-thuat","loaiLabel":"Bí thuật luyện khí","phamCap":"Bàng môn tả đạo","hePhai":"Từ gia","soHuu":["Từ lão giả"],"blurb":"Tiểu thuật bàng môn tả đạo dùng yêu hỏa phun ra từ hỏa nha thay tiên thiên chân hỏa hoặc địa hỏa để luyện chế pháp khí.","detail":"Kỹ thuật luyện khí đặc biệt của Từ gia, dùng yêu hỏa do hỏa nha phun ra làm hỏa lực luyện chế thay cho tiên thiên chân hỏa hay địa hỏa. Cần kỹ xảo đặc biệt, cho phép cả tu sĩ Luyện Khí kỳ như Từ lão giả có thể luyện chế đỉnh cấp pháp khí. Đây là tiểu thuật bàng môn tả đạo, không được các đại phái thừa nhận và truyền bá nghiêm ngặt; Từ gia có được nhờ ngẫu nhiên sở hữu một con hỏa nha, chỉ cần nhị cấp sơ giai đã phun ra yêu hỏa lợi hại hơn tiên thiên chân hỏa vài phần.","nguon":["@c0222"]},{"id":"khoi-loi-co-quan-thuat","name":"Khôi lỗi cơ quan thuật","cn":"","loai":"khac","loaiLabel":"Đạo pháp luyện chế","phamCap":"Không rõ","hePhai":"Thiên Trúc giáo (vùng đất cực tây)","soHuu":[],"blurb":"Đạo pháp luyện chế khác hoàn toàn với pháp khí thông thường, lưu hành rộng ở vùng đất cực tây.","detail":"Khôi lỗi cơ quan thuật là một đạo pháp luyện chế riêng biệt, lưu hành cực kỳ rộng rãi tại vùng đất cực tây, có tông phái Thiên Trúc giáo lấy đó khai môn lập phái và phát huy tới cực điểm. Thành phẩm có phân cấp chính thức; khôi lỗi cơ quan nhân cao nhất có thể ganh đua với tu sĩ Trúc Cơ kỳ hậu kỳ. Cặp khôi lỗi cơ quan thú được rao bán tại bí điếm thuộc khôi lỗi thú cấp hai theo phân cấp này.","nguon":["@c0224"]},{"id":"dien-dao-ngu-hanh-tran","name":"Điên Đảo Ngũ Hành Trận","aliases":["Tiểu Cấm Đoạn Chi Trận","Điên đảo ngũ hành đại trận"],"loai":"khac","loaiLabel":"Cấm pháp / Trận pháp","phamCap":"Kỳ trận trứ danh","hePhai":"","soHuu":["Bằng hữu Trận pháp sư của Tề Vân Tiêu","Hàn Lập"],"blurb":"Kỳ trận cực nổi tiếng còn gọi Tiểu Cấm Đoạn Chi Trận; diện tích bao phủ nhỏ, không có công hiệu chủ động giết địch nhưng công hiệu ảo hóa, yểm hộ sơn môn, mê hoặc vây khốn địch nhân không thua kém hộ phái đại trận của đại môn phái.","detail":"Được các tu tiên gia tộc và môn phái xem trọng còn hơn cả thiên niên linh thảo. Bố trí kỳ trận bình thường cần một trận pháp đại sư tinh thông tốn khoảng một năm cùng nhiều nhân lực vật lực. Bộ khí cụ mà thanh niên đem ra đấu giá chỉ là tàn phẩm, phát huy được một phần mười uy lực nguyên trận, được hứa hẹn vài năm sẽ tăng lên tối thiểu nửa uy lực.","nguon":["@c0226","@c0272","@c0315","@c0331","@c0363"],"tabs":{"tienTrinh":[{"chuong":"@c0331","loai":"xuất hiện","importance":"normal","giaiDoan":"Thu hồi sau giao chiến","text":"Hàn Lập thu lại toàn bộ trận bàn và trận kỳ của Điên đảo ngũ hành trận sau khi đã thấy uy lực của nó.","anchor":"Đã kiến thức qua uy lực của “ Điên đảo ngũ hành trận”, Hàn Lập đối với món bảo bối này trân quý cực kỳ a"},{"chuong":"@c0363","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị công phá","text":"Điên đảo ngũ hành trận bị hoàng quang cổ Truyền tống trận xuyên qua và sau đó bị phe ma đạo đánh vỡ.","anchor":"Đại trận phát ra vài tiếng ông ông, rốt cuộc dưới áp lực của pháp bảo đó, ngũ sắc quang mạc bị bạo liệt vỡ ra"}]},"trangThai":"bị phá vỡ @c0363","congNang":["Tạo màn sáng che phủ và khống chế khu vực trong phạm vi trận pháp @c0331","Che chắn động quật chứa cổ Truyền tống trận @c0363"]},{"id":"cach-am-trao","name":"Cách âm trạo","loai":"bi-thuat","loaiLabel":"Tiểu pháp thuật","phamCap":"Pháp thuật thường dùng","hePhai":"","soHuu":["Hàn Lập","Đại ca Mông Sơn ngũ hữu"],"blurb":"Pháp thuật cách âm thường dùng để chống nghe lén khi nói chuyện riêng.","detail":"Hàn Lập thuận tay học được và bố trí Cách âm trạo để nói chuyện riêng với thanh niên trận pháp sư. Sau khi thành công Trúc Cơ, những pháp thuật trước đây không dùng được nay vừa học đã biết dùng ngay.","nguon":["@c0226","@c0284"]},{"id":"van-tieu-tam-thuat","name":"Vân Tiêu Tâm Thuật","cn":"","aliases":["Vân Tiêu Tâm Đắc"],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Thần Binh Môn","soHuu":["Tề Vân Tiêu","Hàn Lập"],"blurb":"Quyển thư tịch ghi chép hiểu biết luyện khí của Tề Vân Tiêu tích lũy hơn hai mươi năm, chứa nhiều phương pháp luyện khí bí mật của Thần Binh Môn.","detail":"Quyển ghi chép toàn bộ hiểu biết về luyện khí thuật mà Tề Vân Tiêu tích lũy suốt hai mươi mấy năm, bên trong chứa nhiều phương pháp luyện khí bí mật của Thần Binh Môn vốn không được lưu truyền ra ngoài. Do vướng tổ huấn, Tề Vân Tiêu chỉ có thể giao lại quyển sách chứ không đích thân truyền thụ. Hàn Lập nhận quyển này trong giao dịch rồi dùng phong ấn thuật khóa lại, hẹn năm năm không mở, biến sách hóa thành bạc cứng.","nguon":["@c0227"]},{"id":"phong-an-thuat","name":"Phong ấn thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thuật Hàn Lập dùng để khóa quyển Vân Tiêu Tâm Thuật, phát ra chuỗi phù văn màu bạc xuyên nhập vào sách.","detail":"Khi thi triển, thuật phát ra một chuỗi phù văn màu bạc xuyên nhập vào quyển sách, khiến sách hóa thành bạc cứng, không thể lật mở được. Hàn Lập dùng thuật này khóa quyển Vân Tiêu Tâm Đắc, hẹn năm năm không động tới để giữ chữ tín với Tề Vân Tiêu.","nguon":["@c0227"]},{"id":"luyen-khi-thuat","name":"Luyện khí thuật","cn":"","aliases":[],"loai":"khac","loaiLabel":"Kỹ thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Tề Vân Tiêu"],"blurb":"Kỹ thuật chế luyện pháp khí; ở tu tiên giới nhiều tu sĩ biết, nhưng luyện khí thuật của Thần Binh Môn thuộc hàng nổi tiếng.","detail":"Kỹ thuật chế luyện pháp khí phổ biến ở tu tiên giới với nhiều tu sĩ nắm giữ, nhưng luyện khí thuật của Thần Binh Môn thuộc hàng nổi tiếng bậc nhất trong các quốc gia lân cận. Gia tổ Tề Vân Tiêu từng là Luyện khí trưởng lão Thần Binh Môn, luyện khí đạt cực đỉnh và tự tay truyền dạy cho hắn.","nguon":["@c0227"]},{"id":"phap-quyet-dieu-khien-than-phong-chau","name":"Pháp quyết điều khiển Thần Phong Châu","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Đạo pháp quyết màu xanh của Hàn Lập chạm vào Thần Phong Châu khiến thuyền nhỏ biến lớn thành thuyền độc mộc như thật, chở người bay lên không.","detail":"Hàn Lập niệm một đạo pháp quyết màu xanh chạm vào thuyền trắng nhỏ, khiến nó biến lớn thành thuyền độc mộc chở được mấy người, đưa hắn lên không trung mười mấy trượng để điều khiển bay đi.","nguon":["@c0228"]},{"id":"ho-trao-hop-luc","name":"Hộ trạo hợp lực","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Pháp thuật phòng ngự chung do nhóm Trúc Cơ Hậu Kỳ tu sĩ dựng lên, hai người áp tay bổ sung pháp lực để chống quang trụ, quang tiễn và đao thương khôi lỗi.","detail":"Lồng bảo vệ hợp lực (hộ trạo) do bốn năm Trúc Cơ Hậu Kỳ tu sĩ chung dựng, với hai người liên tục áp tay bổ sung pháp lực nhằm duy trì che chắn trước quang trụ nhiều màu, quang tiễn và binh khí của gần trăm khôi lỗi.","nguon":["@c0228"]},{"id":"dai-dien-quyet","name":"Đại Diễn Quyết","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Trọng yếu","hePhai":"Thiên Trúc Giáo","soHuu":["Lâm sư huynh","Hoàng Long","Hàn Lập"],"blurb":"Công pháp trọng yếu của Thiên Trúc Giáo, nửa phần sau bị đồn giấu trong khôi lỗi thú (thực ra là bẫy). Người luyện tới tầng cao có thể điều khiển đồng thời hàng trăm khôi lỗi.","detail":"Đại Diễn Quyết là công pháp trọng yếu liên quan tới Thiên Trúc Giáo. Nửa phần sau bị đồn giấu trong khôi lỗi thú, nhưng thực chất chỉ là bẫy do Kim Giáo Chủ giăng ra để dụ Lâm sư huynh xuất hiện. Lâm sư huynh từng lén truyền khẩu quyết tầng thứ nhất cho Hoàng Long, còn bản thân đã luyện tới tầng thứ ba — cấp độ cho phép điều khiển nhiều khôi lỗi cùng lúc, nên có thể triệu ra và chỉ huy hơn hai trăm khôi lỗi sĩ binh trong trận đại chiến.","nguon":["@c0230","@c0236","@c0271","@c0308"],"cn":"大衍诀"},{"id":"doat-xa","name":"Đoạt xá","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Lâm sư huynh"],"blurb":"Thuật thần hồn chiếm đoạt xác thân người khác. Thần hồn Lâm sư huynh hóa đoàn sáng màu lục lao vào mặt Hàn Lập định chiếm thân xác hắn.","detail":"Hành động thần hồn rời khỏi xác cũ, hóa thành đoàn sáng lao vào đối phương để chiếm lấy thân thể. Ở chương này thần hồn Lâm sư huynh từ trong áo xác bay ra như ma quỷ, đánh thẳng vào mặt Hàn Lập nhưng bị tay phải hắn lóe bạch quang chộp giữ khiến rên rỉ, đành cầu xin tha mạng.","nguon":["@c0231"]},{"id":"trao-bach-quang","name":"Trảo bạch quang","cn":"","loai":"than-thong","loaiLabel":"Thủ pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thủ pháp tay phải Hàn Lập lóe bạch quang, một trảo chộp giữ đoàn sáng thần hồn đang lao tới.","detail":"Khi thần hồn Lâm sư huynh lao vào mặt định đoạt xá, tay phải Hàn Lập bỗng lóe bạch quang, một trảo nắm chặt đoàn sáng khiến nó rên rỉ không thoát được, ghìm được màn đoạt xá.","nguon":["@c0231"]},{"id":"dai-dien-quyet-ban-don-gian-hoa-tang-thu-nhat","name":"Đại Diễn quyết bản đơn giản hóa tầng thứ nhất","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Thiên Trúc giáo","soHuu":[],"blurb":"Bản Đại Diễn quyết giản lược mà giáo đồ thường của Thiên Trúc giáo tu luyện.","detail":"Là bản giản hóa của tầng thứ nhất Đại Diễn quyết, dễ luyện nhưng uy lực không bằng bản chính thống. Chỉ cao tầng trong Thiên Trúc giáo mới có tư cách tu, còn giáo đồ thường tu bản đơn giản hóa này để thao túng khôi lỗi ở mức cơ bản.","nguon":["@c0232"]},{"id":"phan-than-thuat","name":"Phân Thần thuật","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Thiên Trúc giáo","soHuu":[],"blurb":"Bí pháp gắn liền trong Đại Diễn quyết, giúp gắn thần thức lên khôi lỗi để thao túng.","detail":"Bí pháp tu luyện song song trong Đại Diễn quyết của Thiên Trúc giáo. Nhờ Phân Thần thuật, người tu có thể gắn thần thức của mình lên các khôi lỗi cơ quan để thao túng chúng tự do; số lượng khôi lỗi khống chế được tùy theo tầng thứ Đại Diễn quyết đã tu.","nguon":["@c0232"]},{"id":"nguyen-than-xuat-the","name":"Nguyên thần xuất thể","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chiêu bảo mệnh","hePhai":"","soHuu":["Lâm sư huynh","Dư Tử Đồng"],"blurb":"Chiêu bảo mệnh cho nguyên thần thoát khỏi thân xác. Cần thời gian thi pháp và không được loạn động nên gần như vô dụng khi chém giết.","detail":"Chiêu bảo mệnh giúp nguyên thần tu sĩ thoát ly khỏi thân xác. Vì cần thời gian thi pháp và tu sĩ không được loạn động, bình thường gần như vô dụng trong tình huống chém giết; chỉ tu sĩ từ Nguyên Anh kỳ trở lên mới mượn sức Nguyên Anh để nguyên thần lập tức ly thể. Lâm sư huynh dùng khi độc phát cùng đường, định đoạt xá Hàn Lập nhưng bị bắt chế trụ mà tan.","nguon":["@c0233"]},{"id":"cong-phap-di-linh-can-loi-thuoc-tinh","name":"Công pháp dị linh căn Lôi thuộc tính","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Dị linh căn","hePhai":"Hoàng Phong cốc","soHuu":["Lôi Vạn Hạc"],"blurb":"Công pháp dị linh căn Lôi thuộc tính của Lôi Vạn Hạc, biểu hiện qua ngân quang dài mười trượng cùng sấm chớp.","detail":"Công pháp tu luyện theo dị linh căn Lôi thuộc tính, khiến Hàn Lập kinh ngạc. Khi thi triển hóa thành đạo ngân quang dài hơn mười trượng bay như sấm chớp, có thể tách thành sáu bảy đạo ngân quang nhỏ để truy sát nhiều mục tiêu cùng lúc, uy lực đủ biến cả nhóm tu sĩ thành tro bụi trong chớp mắt.","nguon":["@c0233"]},{"id":"co-doc-co-doc-tong","name":"Cổ độc Cổ Độc tông","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Cổ Độc tông","soHuu":["Cổ Độc tông"],"blurb":"Cổ độc gieo bởi Cổ Độc tông ở nơi cực tây, khiến người trúng bộc phát mà chết.","detail":"Loại cổ độc của Cổ Độc tông ở nơi cực tây. Lâm sư huynh trúng phải cổ độc này, độc bộc phát mà chết dù đã được thu vào Hoàng Phong cốc. Lôi Vạn Hạc chỉ cần nhấc thi thể kiểm tra là xác nhận được nguồn gốc cổ độc.","nguon":["@c0233"]},{"id":"cam-doan-than-thuc-dien-dao-ngu-hanh","name":"Cấm đoạn thần thức (biến hóa Điên Đảo Ngũ Hành trận)","loai":"bi-thuat","loaiLabel":"Cấm chế / Biến hóa trận","phamCap":"Không rõ","hePhai":"Điên Đảo Ngũ Hành trận","soHuu":["Hàn Lập"],"blurb":"Biến hóa cấm chế phụ trợ của Điên Đảo Ngũ Hành trận, hạn chế thần thức đối phương.","detail":"Phương pháp cấm đoạn thần thức cực đơn giản dễ dàng bố trí; nếu luyện chế thành pháp khí thì uy lực giống hoàn toàn chính bản, không yếu đi điểm nào — công hiệu duy nhất có thể sánh với chính bản. Khi phát động, thần thức Hàn Lập chỉ còn chuyển động cận vài thước trong phạm vi phụ; thần thức tu sĩ Kết Đan kỳ như Lôi Vạn Hạc cũng không khuếch tán quá mười trượng trong đại sảnh.","nguon":["@c0234"]},{"id":"khoi-loi-chan-giai","name":"Khôi lỗi chân giải","loai":"khac","loaiLabel":"Kinh văn chế tác khôi lỗi","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bộ kinh văn ẩn phía sau Đại Diễn quyết trong ngọc giản, dạy pháp môn luyện chế các loại khôi lỗi thú và khôi lỗi nhân.","detail":"Xuất hiện ngay sau bốn tầng khẩu quyết Đại Diễn quyết trong ngọc giản Lâm sư huynh trao cho Hàn Lập. Là bộ khôi lỗi chế tác đại toàn cực kỳ tường tận, giảng giải pháp môn luyện chế khôi lỗi thú và khôi lỗi nhân. Hàn Lập nhận ra nó phối hợp hoàn mỹ với Đại Diễn quyết: tu tới một tầng nhất định có thể dùng nhiều khôi lỗi áp chế tu sĩ Trúc Cơ đồng cấp như Hoàng Long từng làm. Hắn tạm cất ngọc giản chờ xử lý sau.","nguon":["@c0237"]},{"id":"bang-tam-quyet","name":"Băng Tâm quyết","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Công pháp tu luyện của phu nhân Lý Hóa Nguyên","soHuu":["Sư nương (thê tử Lý Hóa Nguyên)"],"blurb":"Công pháp tu luyện của phu nhân Lý Hóa Nguyên. Đòi hỏi tâm cảnh an ổn; nếu tâm trạng bất ổn (chưa báo được ân) sẽ không luyện thành cảnh giới đại viên mãn, cản trở tiến vào Kết Đan kỳ.","detail":"Phu nhân Lý Hóa Nguyên tu luyện Băng Tâm quyết. Nàng tiết lộ nếu không báo được ân cứu mạng cho Hàn Lập thì tâm trạng sẽ bất ổn, khiến không thể luyện tới cảnh giới đại viên mãn để tiến vào Kết Đan kỳ và sống bên chồng lâu dài. Đây là động cơ thật khiến nàng thúc chồng bồi thường Hàn Lập.","nguon":["@c0238"]},{"id":"ngu-hanh-phap-thuat-thuc-chien","name":"Ngũ Hành pháp thuật thực chiến","loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"Không rõ","hePhai":"Sở trường của Tống Mông","soHuu":["Tống Mông"],"blurb":"Pháp thuật thực chiến hệ Ngũ Hành, sở trường của Tống Mông, được nói là đứng đầu trong môn hạ Lý Hóa Nguyên.","detail":"Tống Mông (Tứ sư huynh) là hán tử cuồng chiến đấu, giỏi vận dụng Ngũ Hành pháp thuật trong thực chiến, đứng đầu về khả năng chiến đấu trong đám môn hạ Lý Hóa Nguyên.","nguon":["@c0238"]},{"id":"chan-duong-quyet","name":"Chân Dương quyết","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Đỉnh cấp","hePhai":"Hoàng Phong cốc","soHuu":["Lý Hóa Nguyên"],"blurb":"Công pháp đỉnh cấp (loại thứ ba) mà Lý Hóa Nguyên tu luyện, hợp với người tam dương chi thể gần Thiên Linh căn.","detail":"Công pháp thuộc loại thứ ba (đỉnh cấp) mà Lý Hóa Nguyên tu luyện. Vì bản thân lão là tam dương chi thể gần với Thiên Linh căn nên tu như cá gặp nước, giúp lão kết thành kim đan. Thuộc dòng công pháp cực hiếm gộp điểm mạnh của cả hai loại thông thường.","nguon":["@c0239"]},{"id":"cong-phap-loai-mot","name":"Công pháp loại một","loai":"khac","loaiLabel":"Phân loại công pháp","phamCap":"Thông thường","hePhai":"","soHuu":[],"blurb":"Loại công pháp pháp lực tinh tiến bình thường nhưng có thần thông thủ đoạn khắc địch chế thắng, thực chiến vượt cấp.","detail":"Một trong ba loại công pháp theo cách phân của Lý Hóa Nguyên. Pháp lực tinh tiến bình thường hoặc hơi thấp nhưng có thần thông và thủ đoạn khắc địch chế thắng, uy lực mạnh, thực chiến vượt cấp. Tu sĩ tự biết đời này vô vọng kết đan thường chọn loại này.","nguon":["@c0239"]},{"id":"cong-phap-loai-hai","name":"Công pháp loại hai","loai":"khac","loaiLabel":"Phân loại công pháp","phamCap":"Thông thường","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Loại công pháp hiệu quả tinh tiến pháp lực cực nhanh, dễ tu luyện nhưng thiếu thủ đoạn tự bảo vệ; là loại Hàn Lập chọn.","detail":"Một trong ba loại công pháp theo cách phân của Lý Hóa Nguyên. Hiệu quả tinh tiến pháp lực cực nhanh, dễ tu luyện, ít gặp bình cảnh, nhưng thiếu thủ đoạn tự bảo vệ và thần thông, dễ trở thành kẻ yếu cùng cấp. Người muốn tiến gần Kết Đan kỳ hay chọn. Đây là loại Hàn Lập kiên định lựa chọn.","nguon":["@c0239"]},{"id":"cong-phap-loai-ba-dinh-cap","name":"Công pháp loại ba (đỉnh cấp)","loai":"khac","loaiLabel":"Phân loại công pháp","phamCap":"Đỉnh cấp","hePhai":"","soHuu":[],"blurb":"Loại công pháp cực hiếm gộp điểm mạnh hai loại kia nhưng cực nguy hiểm, sơ sẩy vạn kiếp bất phục.","detail":"Loại công pháp thứ ba theo cách phân của Lý Hóa Nguyên, cực hiếm, là pháp môn đỉnh cấp mà đông đảo tu sĩ truy đuổi. Gộp điểm mạnh hai loại kia (uy lực mạnh cộng pháp lực tinh tiến kinh người) nhưng nhiều điều kiện hạn chế, cực kỳ nguy hiểm, sơ sẩy là vạn kiếp bất phục. Sư nương của Hàn Lập tu loại này và từng suýt mất mạng.","nguon":["@c0239"]},{"id":"cam-che-tang-thu-that","name":"Cấm chế Tàng thư thất","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Hoàng Phong cốc","soHuu":["Lý Hóa Nguyên"],"blurb":"Cấm chế đặt lên mỗi món trong Tàng thư thất, kích động trận pháp vây khốn kẻ lấy trái phép.","detail":"Mỗi món ngọc giản, sách, hộp trong Tàng thư thất của Lý Hóa Nguyên đều bị hạ cấm chế. Nếu không phải Lý Hóa Nguyên hoặc phu nhân đi lấy thì sẽ kích động trận pháp vây khốn kẻ lấy.","nguon":["@c0239"]},{"id":"quy-nguyen-cong","name":"Quy Nguyên công","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Thông thường","hePhai":"","soHuu":[],"blurb":"Công pháp có tốc độ tăng tiến pháp lực không chậm, kèm tiểu thần thông Quy Nguyên linh giáp.","detail":"Một trong các công pháp Hàn Lập xem xét trong Tàng thư thất. Tốc độ tăng tiến pháp lực không chậm, đi kèm tiểu thần thông phòng ngự Quy Nguyên linh giáp.","nguon":["@c0240"]},{"id":"quy-nguyen-linh-giap","name":"Quy Nguyên linh giáp","loai":"than-thong","loaiLabel":"Tiểu thần thông","phamCap":"","hePhai":"","soHuu":[],"blurb":"Tiểu thần thông phụ trợ của Quy Nguyên công, dùng pháp lực ngưng tụ xuất linh giáp bảo vệ tính mạng.","detail":"Tiểu thần thông đi kèm Quy Nguyên công, thêm một tầng phòng ngự pháp thuật bằng cách dùng pháp lực ngưng tụ xuất ra linh giáp bảo vệ tính mạng. Lực phòng ngự tăng theo sự tinh tiến của Quy Nguyên công.","nguon":["@c0240"]},{"id":"huyen-linh-quyet","name":"Huyễn Linh quyết","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Thông thường","hePhai":"","soHuu":[],"blurb":"Công pháp Hàn Lập xem xét trong Tàng thư thất, kèm thần thông Ảo ảnh.","detail":"Một trong các công pháp Hàn Lập xem qua trong Tàng thư thất, đi kèm thần thông Ảo ảnh huyễn hóa phân thân.","nguon":["@c0240"]},{"id":"ao-anh","name":"Ảo ảnh","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":[],"blurb":"Thần thông huyễn hóa ra phân thân giống đúc như mình để mê hoặc địch nhân.","detail":"Thần thông đi kèm Huyễn Linh quyết, huyễn hóa ra phân thân giống đúc như mình làm mê hoặc địch nhân. Tầng thứ càng cao thì số phân thân càng nhiều.","nguon":["@c0240"]},{"id":"ngung-nguyen-cong","name":"Ngưng Nguyên công","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Thông thường","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Pháp quyết bình thường ghi trong quyển sách màu vàng Hàn Lập chọn, kèm thần thông phụ trợ Tụ Linh thuật.","detail":"Pháp quyết bình thường được ghi trong quyển sách màu vàng mà Hàn Lập chọn làm chủ công pháp, kèm thần thông phụ trợ Tụ Linh thuật nhưng không có đại thần thông. Hàn Lập chọn nó chủ yếu vì nghi ngờ mối liên hệ với quyển sách màu bạc trong tay hắn.","nguon":["@c0240"]},{"id":"tu-linh-thuat","name":"Tụ Linh thuật","loai":"than-thong","loaiLabel":"Thần thông phụ trợ","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông phụ trợ đi kèm Ngưng Nguyên công, đẩy nhanh tốc độ tu luyện bằng cách tụ tập linh khí.","detail":"Thần thông phụ trợ ghi cùng Ngưng Nguyên công trong quyển sách màu vàng, có tác dụng đẩy nhanh tốc độ tu luyện bằng cách tụ tập linh khí.","nguon":["@c0240"]},{"id":"thanh-nguyen-kiem-quang","name":"Thanh Nguyên kiếm quang","loai":"kiem-quyet","loaiLabel":"Kiếm quang","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Công pháp kiếm quang Hàn Lập đang tu luyện, phóng ra đạo kiếm quang màu xanh to như cái bát.","detail":"Công pháp kiếm quang mà Hàn Lập đang tu luyện. Khi thi triển phóng ra một đạo kiếm quang màu xanh to như cái bát; chính đạo kiếm quang này bị quyển sách vàng ẩn nuốt trọn không tăm tích.","nguon":["@c0240","@c0270"]},{"id":"kiem-tu-chi-thuat","name":"Kiếm tu chi thuật","loai":"kiem-quyet","loaiLabel":"Kiếm thuật","phamCap":"","hePhai":"Cự Kiếm môn","soHuu":[],"blurb":"Thuật điều khiển phi kiếm và tu luyện kiếm quang ghi trong quyển sách màu vàng ẩn bên trong sách bạc.","detail":"Nội dung dạy điều khiển phi kiếm cùng thuật tu luyện kiếm quang, ghi trong quyển sách màu vàng ẩn bên trong sách bạc. Thần diệu với tu sĩ Luyện Khí kỳ nhưng Hàn Lập cho là bình thường vì đã Trúc Cơ và đang tu Thanh Nguyên kiếm quang; hắn suy đoán hán tử chân trần Cự Kiếm môn ngày đó từng tu quyển này.","nguon":["@c0240"]},{"id":"tam-chuyen-trong-nguyen-cong","name":"Tam chuyển trọng nguyên công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp phụ trợ","phamCap":"Không rõ","hePhai":"Thanh nguyên kiếm quyết","soHuu":["Hàn Lập"],"blurb":"Công pháp phụ trợ đi kèm Thanh nguyên kiếm quyết, nhắm tới việc tăng cơ hội Kết đan bằng cách nén chân nguyên qua nhiều lần trùng tu.","detail":"Tam chuyển trọng nguyên công do cao nhân sáng tạo Thanh nguyên kiếm quyết đặt ra như một phương án phòng ngừa trở ngại khi Kết đan. Người tu ở tầng thứ sáu kiếm quyết phải tán công rồi tu luyện lại, lặp ba lần để khiến chân nguyên tinh thuần hơn nhiều lần; theo lời người sáng lập, dù làm đúng thì khả năng Kết đan tức thì cũng chỉ khoảng một nửa.","nguon":["@c0241","@c0361"],"tabs":{"tienTrinh":[{"chuong":"@c0361","loai":"nhắc tới","importance":"normal","giaiDoan":"Trấn định khi mất pháp lực","text":"Hàn Lập nghĩ tới Tam Chuyển Trọng Nguyên Công trong lúc tu vi rơi mạnh nên tạm ổn định tinh thần.","anchor":"trong lòng cũng đã nghĩ đến phương pháp tu luyện “Tam Chuyển Trọng Nguyên Công” không khỏi trấn định lại"}]},"congNang":["Có liên quan khả năng tu luyện lại sau khi mất pháp lực @c0361"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0361","tangDatToi":"","trangThai":"đang biết"}]},{"id":"huyen-phu-thuat","name":"Huyền phù thuật","cn":"","loai":"khac","loaiLabel":"Pháp thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Pháp thuật dùng để giữ vật thể lơ lửng trên không.","detail":"Hàn Lập dùng Huyền phù thuật để treo tờ giấy vàng lơ lửng trong lúc truyền Thanh nguyên kiếm quang vào. Khi thuật mất hiệu lực, tờ giấy rơi xuống và Hàn Lập chộp lấy, dẫn tới việc chữ sáng tràn vào thân thể hắn.","nguon":["@c0241"]},{"id":"ho-phu-dai-tran","name":"Hộ phủ đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Có thể khiến tu sĩ Kết Đan kỳ khó lẻn vào","hePhai":"Hoàng Phong cốc","soHuu":["Hàn Lập"],"blurb":"Đại trận và cấm chế bảo vệ động phủ của Hàn Lập. Nho sinh nghe Lôi sư bá nói ngay cả tu sĩ Kết Đan kỳ cũng chưa chắc lẻn vào được.","detail":"Hộ phủ đại trận che giấu và bảo vệ động phủ Hàn Lập trong thời gian hắn bế quan. Khi nho sinh tới truyền tin, y rất muốn thử uy lực trận pháp nhưng phải bỏ ý định vì còn việc của sư phụ.","nguon":["@c0242"]},{"id":"tien-thien-chan-hoa","name":"Tiên thiên chân hỏa","cn":"","loai":"than-thong","loaiLabel":"Thần thông luyện đan","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Ngọn chân hỏa Hàn Lập dùng để luyện chế đan dược trong động phủ.","detail":"Trong thời gian bế quan, Hàn Lập dùng Tiên thiên chân hỏa để luyện Luyện khí tán và các đan dược khác. Cách này kém địa hỏa nhưng an toàn, kín đáo và không chịu áp lực thời hạn thuê phòng luyện đan.","nguon":["@c0243"]},{"id":"dai-tran-che-phu-dong-phu","name":"Đại trận che phủ động phủ","cn":"","loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Trận pháp che phủ động phủ của Hàn Lập, giúp bảo vệ cả khu vườn thuốc bí mật.","detail":"Đại trận bao phủ cả vị trí các lỗ nhỏ trên đỉnh dược viên bí mật, nhờ đó Hàn Lập không lo người ngoài phát hiện việc dẫn ánh sáng vào nơi đặt bình nhỏ và thúc sinh linh dược.","nguon":["@c0243"]},{"id":"cam-che-luc-ba-dong","name":"Cấm chế Lục Ba động","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Hoàng Phong cốc","soHuu":["Lý Hóa Nguyên"],"blurb":"Cấm chế bảo vệ Lục Ba động của Lý Hóa Nguyên.","detail":"Khi Hàn Lập đến Lục Ba động theo truyền âm phù, cấm chế được mở cho hắn vào. Người mở lần này là Vũ Huyễn, lục đệ tử của Lý Hóa Nguyên.","nguon":["@c0243"]},{"id":"phap-thuat-cap-thap","name":"Pháp thuật cấp thấp","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"cấp thấp","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Nhóm pháp thuật Hàn Lập luyện hằng ngày để phục vụ việc chế phù.","detail":"Trong bốn năm bế quan, Hàn Lập dành gần nửa ngày mỗi ngày luyện các pháp thuật cấp thấp có thể phát ra nhanh, nhờ đó nâng cao năng lực chế phù và dần chế được phù lục bậc cao sơ cấp.","nguon":["@c0243"]},{"id":"phap-thuat-trung-cap","name":"Pháp thuật trung cấp","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"trung cấp","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Nhóm pháp thuật Hàn Lập dự định học trong lần bế quan kế tiếp.","detail":"Sau khi trình độ chế phù tăng lên, Hàn Lập dự định bắt đầu học tập và tu luyện pháp thuật trung cấp để thử luyện chế phù lục trung cấp.","nguon":["@c0243"]},{"id":"song-tu","name":"Song tu","cn":"","loai":"cong-phap","loaiLabel":"Phương pháp tu luyện","phamCap":"Không rõ","hePhai":"Tu tiên giới","soHuu":[],"blurb":"Song tu là phương pháp tu luyện nam nữ cùng phối hợp để thúc đẩy tốc độ tu luyện của hai bên.","detail":"Trong lời Lý Hóa Nguyên, song tu được xem là phương pháp tuyệt diệu giúp nam nữ hai bên tu luyện nhanh hơn. Đây là lý do chính ông và Hồng Phất muốn sắp đặt Hàn Lập kết thành bạn song tu với Đổng Huyên Nhi.","nguon":["@c0244"]},{"id":"hoa-xuan-quyet","name":"Hóa xuân quyết","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Đỉnh cấp","hePhai":"Hoàng Phong cốc","soHuu":["Hồng Phất","Đổng Huyên Nhi"],"blurb":"Công pháp đỉnh cấp do Hồng Phất nắm giữ, được Đổng Huyên Nhi chọn vì hiệu quả trú nhan.","detail":"Hóa xuân quyết khiến dung mạo Đổng Huyên Nhi có vẻ gợi tình, làm một số tu sĩ hiểu lầm nàng đã mất nguyên âm. Công pháp này đã tới giai đoạn cần song tu, nếu không pháp lực có thể đình trệ hoặc thụt lùi.","nguon":["@c0246"]},{"id":"cam-che-ngu-sac-che-giau-yen-linh-bao","name":"Cấm chế ngũ sắc che giấu Yến Linh bảo","cn":"","loai":"than-thong","loaiLabel":"Trận pháp/cấm chế","phamCap":"không rõ","hePhai":"Yến gia","soHuu":["Yến gia"],"blurb":"Cấm chế ngũ sắc che giấu Yến Linh bảo, khiến khoảng không giữa hai ngọn núi trông như trống rỗng. Khi Yến Vũ dùng lệnh bài phóng ánh sáng vàng, hào quang ngũ sắc hiện ra rồi tan đi để lộ cổ bảo.","detail":"Cấm chế này bao phủ vị trí Yến Linh bảo giữa hai ngọn núi nhỏ. Người ngoài chỉ thấy khoảng không trống rỗng; sau khi lệnh bài mở bảo được kích phát, hào quang ngũ sắc xuất hiện và tòa cổ bảo hùng vĩ mới hiện hình giữa lưng chừng núi.","nguon":["@c0247"]},{"id":"phap-thuat-va-doc-thuat-am-hiem-cua-ma-dao","name":"Pháp thuật và độc thuật âm hiểm của ma đạo","cn":"","loai":"khac","loaiLabel":"Pháp thuật và độc thuật","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Nhóm người khiêu chiến Yến gia"],"blurb":"Thủ đoạn ma đạo được nhóm người khiêu chiến Yến gia sử dụng trong tỷ thí. Người thua trận đều hôn mê, trúng độc mơ hồ và thương thế khó chữa.","detail":"Yến Vũ cho biết nhóm khiêu chiến tinh thông một số pháp thuật và độc thuật âm hiểm của ma đạo, khiến đệ tử Yến gia giao thủ thất bại bị hôn mê và trúng độc khó cứu. Vì còn ở trong Yến Linh bảo, đối phương chưa dám gây chết người.","nguon":["@c0248"]},{"id":"bi-phap-cua-yen-gia","name":"Bí pháp của Yến gia","cn":"","loai":"cong-phap","loaiLabel":"Bí pháp","phamCap":"không rõ","hePhai":"Yến gia","soHuu":["Diễn Vũ đường"],"blurb":"Pháp môn do đệ tử tinh nhuệ Diễn Vũ đường tu luyện. Yến Linh tin nhóm này có thể giáo huấn những người đang khiêu chiến Yến gia.","detail":"Bí pháp này được nhắc qua lời Yến Linh khi nói các trưởng lão đã gọi người đứng đầu đệ tử Diễn Vũ đường tới. Đây là nền tảng khiến đệ tử tinh nhuệ Yến gia được kỳ vọng có thể đối phó nhóm khách dùng thủ đoạn ma đạo.","nguon":["@c0248"]},{"id":"cam-che-ho-bao","name":"Cấm chế hộ bảo","cn":"","loai":"khac","loaiLabel":"Cấm chế trận pháp","phamCap":"không rõ","hePhai":"Yến gia","soHuu":["Yến gia"],"blurb":"Cấm chế bảo vệ Yến Linh bảo được mở một phần khi khách đến quá đông. Nó khiến vài khu vực đặc biệt không thể dùng truyền âm phù pháp thuật khoảng cách xa.","detail":"Yến Vũ giải thích Yến gia mở một phần cấm chế hộ bảo vì trong bảo gần đây có quá nhiều khách và rồng rắn lẫn lộn. Tác dụng phụ được nêu là ở vài nơi đặc biệt, truyền âm phù pháp thuật khoảng cách xa không thể phóng thích, nên Yến Linh phải trực tiếp đi báo tin.","nguon":["@c0248"]},{"id":"dao-thuat-tho-thuoc-tinh","name":"Đạo thuật thổ thuộc tính","cn":"","loai":"than-thong","loaiLabel":"Đạo thuật","phamCap":"không rõ","hePhai":"Yến gia","soHuu":["Đường huynh của Yến Vũ"],"blurb":"Đạo thuật được đường huynh của Yến Vũ thi triển thuần thục trong trận tỷ thí. Nó giúp hắn tạo đá lớn liên tục tấn công người áo lục.","detail":"Trong trận đấu, đường huynh của Yến Vũ được nhận xét là thi triển đạo thuật thổ thuộc tính đến mức xuất thần nhập hóa. Hắn dùng thủ đoạn này phối hợp với phướn vàng hộ thân để duy trì thế công trước người áo lục.","nguon":["@c0248"]},{"id":"cu-thach-thuat","name":"Cự thạch thuật","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật thổ hệ","phamCap":"không rõ","hePhai":"Yến gia","soHuu":["Đường huynh của Yến Vũ"],"blurb":"Pháp thuật thổ hệ tạo cự thạch tấn công trong trận đấu ở Yến Linh bảo. Đường huynh của Yến Vũ ngừng dùng thuật này khi chuyển sang quạt giấy màu vàng.","detail":"Cự thạch thuật là thủ đoạn tấn công giai đoạn đầu của tinh anh Yến gia, tạo ra các tảng đá lớn ném về phía người áo lục. Khi cục diện thay đổi, hắn dừng thuật này và đổi sang dùng pháp khí quạt giấy màu vàng.","nguon":["@c0248"]},{"id":"hac-khi-luoi-den","name":"Hắc khí lưới đen","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật nghi ma đạo","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Người áo bào màu lục"],"blurb":"Hắc khí đen như mực do người áo lục phóng ra trong trận đấu. Nó bay múa như độc xà, kết thành lưới đen và bắn ngược cự thạch của đối thủ.","detail":"Người áo lục dùng nhiều luồng hắc khí kết thành tấm lưới đen trước thân, phòng ngự trước đạo thuật thổ thuộc tính của đường huynh Yến Vũ. Khi cự thạch lao tới, lưới đen có thể phản kích khiến thế trận tạm giằng co.","nguon":["@c0248"]},{"id":"ho-mi-cong","name":"Hồ mị công","cn":"","loai":"cong-phap","loaiLabel":"công pháp mị thuật","phamCap":"không rõ","hePhai":"Đổng Huyên Nhi","soHuu":["Đổng Huyên Nhi"],"blurb":"Công pháp mị thuật của Đổng Huyên Nhi, có khả năng khiến người khác bất giác dao động trước nàng. Trong chương này, Hàn Lập nghi nó tác động tới cả tu sĩ Trúc Cơ nhưng lại không có hiệu quả với hắn.","detail":"Hồ mị công được Hàn Lập liên hệ với việc Yến Vũ và Phong sư huynh vốn không phải người ngu nhưng vẫn bị Đổng Huyên Nhi khiến cho tranh phong mất tỉnh táo. Điểm bất thường là công pháp này không gây tác dụng với Hàn Lập, khiến cả hắn và Đổng Huyên Nhi đều nhận ra sự khác biệt.","nguon":["@c0249"]},{"id":"huyen-phap-quy-linh-mon","name":"Huyền pháp Quỷ linh môn","cn":"","loai":"than-thong","loaiLabel":"huyền pháp","phamCap":"không rõ","hePhai":"Quỷ linh môn","soHuu":["Lục bào quái nhân"],"blurb":"Huyền pháp của Quỷ linh môn được trưởng lão Yến gia thừa nhận là tinh diệu sau trận bại của Đường huynh. Lục bào quái nhân dùng các khô lâu phá độc vụ của Hóa cốt phiến rồi hạ đối thủ.","detail":"Trong cuộc tỷ thí tại Yến gia, lục bào quái nhân vận dụng thủ đoạn khô lâu hút hắc khí, nuốt lục vụ của Hóa cốt phiến và phun luồng sáng đen hợp thành cột sáng đánh bại Đường huynh. Sau trận này, trưởng lão Yến gia công khai nói Huyền pháp Quỷ linh môn quả nhiên tinh diệu tuyệt luân.","nguon":["@c0249"]},{"id":"khu-quy-dich-yeu-thuat","name":"Khu quỷ dịch yêu thuật","cn":"","loai":"than-thong","loaiLabel":"Thuật pháp","phamCap":"Sở trường ma đạo của Quỷ Linh Môn","hePhai":"Quỷ Linh Môn","soHuu":["Quỷ Linh Môn"],"blurb":"Thuật pháp sở trường của Quỷ Linh Môn, được Vô Du Tử nêu khi giới thiệu lai lịch môn phái này.","detail":"Khu quỷ dịch yêu thuật là một trong những năng lực tiêu biểu của Quỷ Linh Môn, đi cùng độc thuật và ám thuật trong lời giải thích về thực lực ma phái Thiên La quốc này.","nguon":["@c0253"]},{"id":"doc-thuat","name":"Độc thuật","cn":"","loai":"than-thong","loaiLabel":"Thuật pháp","phamCap":"Sở trường ma đạo của Quỷ Linh Môn","hePhai":"Quỷ Linh Môn","soHuu":["Quỷ Linh Môn"],"blurb":"Một trong các sở trường của Quỷ Linh Môn theo lời Vô Du Tử.","detail":"Độc thuật được nêu cùng khu quỷ dịch yêu thuật và ám thuật khi Vô Du Tử giải thích vì sao Quỷ Linh Môn là ma phái đáng gờm trong sáu tông phái ma đạo Thiên La quốc.","nguon":["@c0253"]},{"id":"am-thuat","name":"Ám thuật","cn":"","loai":"than-thong","loaiLabel":"Thuật pháp","phamCap":"Sở trường ma đạo của Quỷ Linh Môn","hePhai":"Quỷ Linh Môn","soHuu":["Quỷ Linh Môn"],"blurb":"Nhóm thuật pháp Quỷ Linh Môn tinh thông, được nhắc cùng độc thuật khi giải thích thực lực ma phái này.","detail":"Ám thuật là một trong các sở trường của Quỷ Linh Môn, góp phần tạo nên danh tiếng nguy hiểm của môn phái này trong sáu ma tông Thiên La quốc.","nguon":["@c0253"]},{"id":"van-linh-thuc-kinh","name":"Vạn linh thực kinh","cn":"","loai":"cong-phap","loaiLabel":"Công pháp/kinh điển","phamCap":"không rõ","hePhai":"Quỷ linh môn","soHuu":["Quỷ linh môn"],"blurb":"Kinh điển Quỷ linh môn đề nghị chia sẻ cho Yến gia trong điều kiện hợp tác. Nó là một trong các lợi ích lớn được dùng để thuyết phục Yến gia ngả theo Quỷ linh môn.","detail":"Trong mật hội Phi vân các, Yến gia lão tổ nói Quỷ linh môn đưa ra điều kiện rất hậu hĩnh, trong đó có việc để Yến gia cùng xem Vạn linh thực kinh. Tên kinh này gắn với đề nghị hợp tác trọng đại giữa Quỷ linh môn và Yến gia trước khi ma đạo lục tông xâm lấn Việt quốc.","nguon":["@c0255"]},{"id":"sinh-tu-chu","name":"Sinh tử chú","cn":"","loai":"bi-thuat","loaiLabel":"Chú pháp ràng buộc","phamCap":"không rõ","hePhai":"Yến gia dùng để chế ước Quỷ linh môn","soHuu":["Yến Như Yên","Yến Văn","Yến Kì","Thiếu chủ Quỷ linh môn","Hai vị tu sĩ Kết Đan Quỷ linh môn"],"blurb":"Sinh tử chú là chú pháp ràng buộc được Huyền Dạ đề xuất dùng trong đàm phán giữa Yến gia và Quỷ linh môn. Nó nhằm buộc đối phương không thể bất lợi cho Yến gia trong hai ba trăm năm.","detail":"Huyền Dạ yêu cầu Thiếu chủ Quỷ linh môn và hai tu sĩ Kết Đan trao đổi Sinh tử chú với Yến Như Yên cùng hai bá phụ Yến gia. Yến gia lão tổ chấp thuận kế hoạch, phái ba người đến phòng khách hạ chú, đồng thời chuẩn bị đại trận nếu người Quỷ linh môn không đồng ý; sau đó Yến Như Yên truyền tin báo việc thành công.","nguon":["@c0256"]},{"id":"dai-tran-trong-phong-khach","name":"Đại trận trong phòng khách","cn":"","loai":"khac","loaiLabel":"Trận pháp mai phục","phamCap":"không rõ","hePhai":"Yến gia","soHuu":["Yến gia lão tổ"],"blurb":"Đại trận trong phòng khách là bố trí mai phục của Yến gia khi đàm phán Sinh tử chú với người Quỷ linh môn. Nếu đối phương không đồng ý, Yến gia sẽ phát động trận pháp để vây khốn họ.","detail":"Yến gia lão tổ ra lệnh cho Yến Như Yên, Yến Văn và Yến Kì đến phòng khách hạ Sinh tử chú với người Quỷ linh môn. Lão dặn rõ nếu người Quỷ linh môn không đồng ý thì lập tức phát động đại trận trong phòng để đối phó.","nguon":["@c0256"]},{"id":"am-hoa-dai-tran","name":"Âm Hỏa đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Quỷ Linh môn","soHuu":["Vương Thiền","Quỷ Linh môn"],"blurb":"Trận pháp của Quỷ Linh môn được Vương Thiền đề xuất dùng trong kế hoạch huyết tế tại Yến gia bảo.","detail":"Vương Thiền muốn dùng Âm Hỏa đại trận của Quỷ Linh môn để luyện hóa thân thể hơn hai trăm tu sĩ Trúc Cơ trong bảo, chỉ giữ lại hồn phách làm vật huyết tế cho Yến Như Yên Trúc Cơ và tu luyện Huyết Linh đại pháp.","nguon":["@c0257"]},{"id":"phuong-phap-me-hon","name":"Phương pháp mê hồn","cn":"","loai":"than-thong","loaiLabel":"Mê thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Nam tử diễm lệ"],"blurb":"Thủ đoạn mê hoặc bị Hàn Lập chỉ thẳng khi thấy Đổng Huyên Nhi bị khống chế bất thường. Nó khiến Yến Vũ và Phong sư huynh nhận ra nàng không tự nguyện đi theo nam tử diễm lệ.","detail":"Hàn Lập dùng cách gọi phương pháp mê hồn để chất vấn nam tử diễm lệ vì sao hạ thủ với người của bảy đại phái. Tác dụng cụ thể được thể hiện qua trạng thái Đổng Huyên Nhi mê luyến đối phương và xem Hàn Lập như người xa lạ.","nguon":["@c0258"]},{"id":"me-tam-thuat","name":"Mê Tâm thuật","cn":"","loai":"than-thong","loaiLabel":"Mê thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Nam tử diễm lệ"],"blurb":"Mê thuật của nam tử diễm lệ khiến Đổng Huyên Nhi chỉ sau một lần nhìn nhau đã mất ý chí phản kháng. Hàn Lập suy luận thuật này rất lợi hại nhưng có thể bị giới hạn với nữ tử.","detail":"Đổng Huyên Nhi kể rằng sau khi nhìn nam tử diễm lệ thì đầu óc ong lên, toàn tâm muốn lấy lòng hắn và không còn ý phản kháng. Hàn Lập cho rằng nếu thuật này hữu hiệu với nam tử thì đối phương đã không dễ dàng buông tha ba người, nên khả năng lớn là nó không tác dụng với họ.","nguon":["@c0258"]},{"id":"me-hon-thuat","name":"Mê hồn thuật","cn":"","loai":"phap-thuat","loaiLabel":"Pháp thuật","phamCap":"không rõ","hePhai":"Mê hồn pháp thuật","soHuu":["Hàn Lập","Nam tử diễm lệ"],"blurb":"Loại pháp thuật ảnh hưởng tâm thần được Hàn Lập dùng làm cơ sở phân tích việc Đổng Huyên Nhi bị khống chế. Theo suy luận của hắn, hiệu quả tức thời như vậy không hợp lý nếu chỉ do chênh lệch Trúc Cơ sơ kỳ và trung kỳ.","detail":"Hàn Lập chỉ biết sơ qua về Mê hồn thuật nhưng vẫn nhận ra điểm bất thường trong việc Đổng Huyên Nhi bị nam tử diễm lệ chế trụ sau khi đối mắt. Hắn cho rằng muốn đạt hiệu quả như thế thường phải có chênh lệch pháp lực rất lớn hoặc là tu sĩ chuyên tu loại pháp thuật này.","nguon":["@c0259"]},{"id":"hai-tang-vong-phong-ngu-do-va-xanh-co-mui-nhon","name":"Hai tầng vòng phòng ngự đỏ và xanh có mũi nhọn","cn":"","loai":"than-thong","loaiLabel":"Phòng ngự pháp thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Phòng ngự pháp thuật Hàn Lập kích hoạt khi bị Vương Thiền bất ngờ chặn lại. Hai tầng bảo hộ gồm một tầng đỏ và một tầng xanh có mũi nhọn, dùng để ứng biến trước nguy cơ bị công kích.","detail":"Khi nghe tiếng Vương Thiền và lập tức lùi hơn mười trượng, Hàn Lập mở ra hai tầng phòng hộ quanh thân. Research ghi rõ đây là một tầng bảo hộ đỏ và một tầng bảo hộ xanh có mũi nhọn, xuất hiện trước khi hắn phóng khiên vảy cá trắng và lên Thần Phong Chu bỏ chạy.","nguon":["@c0260"]},{"id":"huyet-don-thuat","name":"Huyết Độn Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Thuộc Huyết Linh Đại Pháp","hePhai":"Quỷ Linh Môn","soHuu":["Vương Thiền"],"blurb":"Bí pháp độn hành trong Huyết Linh Đại Pháp, giúp Vương Thiền điều khiển Huyết Vân truy đuổi Hàn Lập với tốc độ rất cao.","detail":"Huyết Độn Thuật khiến Huyết Vân bám sát Thần Phong Châu, được mô tả nhanh hơn nhiều pháp khí phi hành đỉnh cấp thông thường. Trong lần truy sát này, nó vẫn nhất thời chưa bắt kịp Hàn Lập đang dùng tiểu châu bỏ chạy.","nguon":["@c0261"]},{"id":"huyet-quy","name":"Huyết Quỷ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thuộc Huyết Linh Đại Pháp","hePhai":"Quỷ Linh Môn","soHuu":["Vương Thiền"],"blurb":"Quỷ vật màu đỏ như máu do Huyết Vân sinh ra, dùng để vây công và tiêu hao đối thủ.","detail":"Huyết Quỷ bị Ô Long Đoạt bóp nát sẽ hóa trở lại Huyết Vân rồi tiếp tục được sinh ra, khiến số lượng vây công Hàn Lập luôn duy trì quanh mức ba mươi mấy con. Cơ chế tái sinh này buộc Hàn Lập phải tiêu hao pháp lực liên tục mà không thể dứt điểm nhanh.","nguon":["@c0261"]},{"id":"am-ma-ti","name":"Âm Ma Ti","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Phụ thuộc Bích Âm Thoa","hePhai":"Quỷ Linh Môn","soHuu":["Vương Thiền"],"blurb":"Hắc khí dạng tơ do Bích Âm Thoa phóng ra để quấn trói pháp khí đối phương.","detail":"Âm Ma Ti được Bích Âm Thoa phóng ra nhằm khóa Ô Long Đoạt của Hàn Lập. Tuy nhiên, hắc mang từ Ô Long Đoạt xé nát lớp hắc khí này, khiến Vương Thiền nhận ra pháp khí của Hàn Lập không phải loại đỉnh cấp thông thường.","nguon":["@c0261"]},{"id":"huyet-linh-dai-phap","name":"Huyết Linh Đại Pháp","cn":"","aliases":["Huyết linh đại pháp","Huyết Linh đại pháp"],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Quỷ Linh Môn","soHuu":["Vương Thiền"],"blurb":"Huyết Linh Đại Pháp là công pháp Vương Thiền dùng để khống chế Huyết Vân. Trong chương này, hắn hao tinh huyết thúc pháp khiến Huyết Vân xoay xiết và hấp thu mê vụ để ép Hàn Lập lộ thân.","detail":"Vương Thiền nhận định pháp khí thông thường khó phá được Huyết Linh Đại Pháp, nhưng Hàn Lập đã dùng tiểu đao Phù Bảo phối hợp phù lục hỏa long đánh tan Huyết Vân để thoát thân. Công pháp này cũng khiến Vương Thiền vô tình hút Mạc Giao chi Độc theo Huyết Vân vào người.","nguon":["@c0262"]},{"id":"tu-sat-tran","name":"Tứ Sát Trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Yểm Nguyệt Tông","soHuu":["Tuyên Nhạc"],"blurb":"Trận pháp công thủ được Tuyên Nhạc bố trí tại linh khoáng.","detail":"Tuyên Nhạc lấy hơn mười trận kỳ và trận bàn, bố trí thêm Tứ Sát Trận dưới lớp ảo trận che phủ hiệp cốc để tăng khả năng công kích và phòng thủ cho linh thạch khoáng.","nguon":["@c0263"]},{"id":"khoi-loi-chan-kinh","name":"Khôi Lỗi Chân Kinh","cn":"","loai":"cong-phap","loaiLabel":"Điển tịch khôi lỗi thuật","phamCap":"không rõ","hePhai":"Khôi lỗi thuật","soHuu":["Hàn Lập"],"blurb":"Điển tịch khôi lỗi thuật Hàn Lập nghiên cứu khi luyện cơ quan khôi lỗi. Nội dung chỉ ra khôi lỗi muốn có linh tính cần dung luyện hồn phách sinh linh cùng tài liệu luyện khí.","detail":"Khôi Lỗi Chân Kinh giải thích rằng luyện khôi lỗi không chỉ cần tài liệu như luyện khí, mà còn cần hồn phách sinh linh dung hợp mới có thể khiến khôi lỗi thành phẩm có linh tính. Cuối kinh còn kèm ba pháp thuật thường được Ma Đạo dùng là Khiên Hồn Thuật, Ngưng Hồn Thuật và Luyện Hồn Thuật, phục vụ việc dẫn hồn, ngưng tụ và cải tạo hồn phách trước khi dung luyện vào khôi lỗi.","nguon":["@c0264"]},{"id":"khien-hon-thuat","name":"Khiên Hồn Thuật","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật dẫn hồn","phamCap":"không rõ","hePhai":"Ma Đạo","soHuu":["Hàn Lập"],"blurb":"Pháp thuật kéo hồn phách ra khỏi thi thể mới chết. Hàn Lập dùng thuật này để thu hồn phách thằn lằn phục vụ luyện khôi lỗi.","detail":"Khiên Hồn Thuật có uy lực nhỏ và tỷ lệ thành công không cao, với tu sĩ Trúc Cơ trung kỳ thì vận dụng bình thường hơn, còn Hàn Lập ở Trúc Cơ sơ kỳ chỉ miễn cưỡng dùng được. Trong lần thử trên hoang nguyên, hắn thi triển thuật này để hút quang cầu hồn phách màu xanh lục từ xác thằn lằn rồi thu vào bình ngọc nhỏ.","nguon":["@c0264"]},{"id":"ngung-hon-thuat","name":"Ngưng Hồn Thuật","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật ngưng hồn","phamCap":"không rõ","hePhai":"Ma Đạo","soHuu":["Hàn Lập"],"blurb":"Pháp thuật ngưng tụ nhiều hồn phách cấp thấp thành hồn phách nhân tạo mạnh hơn. Thuật này dùng khi cần hồn phách phù hợp cho khôi lỗi cao cấp.","detail":"Ngưng Hồn Thuật được Khôi Lỗi Chân Kinh nhắc kèm Khiên Hồn Thuật và Luyện Hồn Thuật. Nó phục vụ việc gom nhiều hồn phách yếu lại thành hồn phách nhân tạo có sức mạnh cao hơn, nhất là khi luyện khôi lỗi mà không sẵn hồn phách mạnh bẩm sinh.","nguon":["@c0264"]},{"id":"luyen-hon-thuat","name":"Luyện Hồn Thuật","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật luyện hồn","phamCap":"không rõ","hePhai":"Ma Đạo","soHuu":["Hàn Lập"],"blurb":"Pháp thuật cải tạo hồn phách trước khi dung luyện vào khôi lỗi. Đây là một trong ba thuật kèm theo Khôi Lỗi Chân Kinh.","detail":"Luyện Hồn Thuật được dùng vì linh hồn sống thông thường không thể trực tiếp đưa vào khôi lỗi. Hồn phách sau khi được dẫn ra và ngưng tụ cần trải qua luyện chế, cải tạo mới thích hợp để dung hợp với thân khôi lỗi.","nguon":["@c0264","@c0338"],"tabs":{"tienTrinh":[{"chuong":"@c0338","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Khúc Hồn nhận lầm là thủ đoạn Hàn Lập sắp dùng","text":"Khúc Hồn thấy Tụ Hồn Bát âm trầm liền liên tưởng đến Luyện Hồn thuật và kinh sợ.","anchor":"có thể đem hồn phách của người ta rút ra, dùng pháp thuật chuyên môn để tra tấn"}]},"congNang":["Rút hồn phách ra để tra tấn trực tiếp linh hồn @c0338"]},{"id":"khoi-loi-luyen-che-thuat","name":"Khôi Lỗi Luyện Chế Thuật","cn":"","loai":"khac","loaiLabel":"Kỹ nghệ luyện chế","phamCap":"không rõ","hePhai":"Khôi lỗi thuật","soHuu":["Hàn Lập","Thiên Trúc Giáo"],"blurb":"Hệ thống luyện chế cơ quan khôi lỗi mà Hàn Lập bắt đầu nghiên cứu sâu sau khi có Đại Diễn Quyết. Thuật này kết hợp tài liệu luyện khí với hồn phách đã xử lý để tạo linh tính cho khôi lỗi.","detail":"Khôi Lỗi Luyện Chế Thuật yêu cầu chế tạo thân khôi lỗi từ tài liệu phù hợp, đồng thời dung luyện hồn phách sinh linh đã được dẫn, ngưng và luyện. Hàn Lập đã thử nghiệm nhiều lần, luyện được cơ quan thú hình thằn lằn, rút ra hạn chế về phạm vi và độ trễ điều khiển, rồi chuẩn bị tiến tới khôi lỗi cấp hai.","nguon":["@c0264"]},{"id":"khoi-loi-thuat","name":"Khôi Lỗi Thuật","cn":"","loai":"khac","loaiLabel":"Thuật khôi lỗi","phamCap":"không rõ","hePhai":"Thiên Trúc Giáo","soHuu":["Hàn Lập","Thiên Trúc Giáo"],"blurb":"Khôi Lỗi Thuật là thuật luyện chế và điều khiển khôi lỗi, được Hàn Lập đánh giá có thể tăng mạnh chiến lực Trúc Cơ kỳ. Khi đối diện Kết Đan kỳ, thuật này cần khôi lỗi cấp cao cùng lượng tài liệu và hồn phách cực lớn nên khó phổ biến.","detail":"Ở chương này, Hàn Lập phân tích Khôi Lỗi Thuật dựa trên khả năng phân thần của Đại Diễn Quyết. Hắn cho rằng khôi lỗi cấp thấp có thể hữu dụng ở Trúc Cơ kỳ, nhưng muốn uy hiếp Kết Đan kỳ thì phải có hàng trăm khôi lỗi cấp ba trở lên, kéo theo chi phí tài liệu, hồn phách và luyện chế rất lớn.","nguon":["@c0265","@c0312"]},{"id":"ngu-hanh-dao-phap","name":"Ngũ Hành Đạo Pháp","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Ngũ Hành Đạo Pháp là pháp môn Hàn Lập tu tập, được nhắc khi so sánh với tiến độ luyện Đại Diễn Quyết. Tư chất của Hàn Lập với pháp môn này kém hơn rõ rệt so với khi tu luyện Đại Diễn Quyết.","detail":"Trong lúc nhận xét tiến triển của Đại Diễn Quyết, Hàn Lập tự thấy việc tu luyện công pháp nguyên thần thuận lợi hơn các pháp môn khác như Ngũ Hành Đạo Pháp và Thanh Nguyên Kiếm Quyết.","nguon":["@c0265"]},{"id":"cam-che-dai-tran-cua-that-phai","name":"Cấm chế đại trận của thất phái","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Việt Quốc thất phái","soHuu":["Việt Quốc thất phái"],"blurb":"Cấm chế đại trận của thất phái là hệ thống trận pháp chiến trường giúp Việt Quốc thất phái dựa hiểm chống Ma Đạo. Các đại trận này góp phần kéo thế công Ma Đạo vào cục diện tiêu hao.","detail":"Khi chiến tranh leo thang, Việt Quốc thất phái dựa vào các đại trận đã bố trí trong địa phận Việt Quốc để phòng thủ trước thế công quy mô lớn của Ma Đạo lục tông, chờ viện quân các nước lân cận đến hỗ trợ.","nguon":["@c0265"]},{"id":"thanh-duong-ma-hoa","name":"Thanh dương ma hỏa","cn":"","loai":"than-thong","loaiLabel":"Ma hỏa/thần thông","phamCap":"không rõ","hePhai":"Ma Diễm môn","soHuu":["Hồng y nhân Ma Diễm môn / Cuồng diễm tu sĩ"],"blurb":"Thanh dương ma hỏa là pháp thuật ma hỏa do Cuồng diễm tu sĩ Ma Diễm môn thi triển bằng đại kỳ đỏ rực. Lữ Thiên Mông vừa nhận ra đã kinh hãi hô mọi người ngăn cản.","detail":"Trong trận công kích linh quáng, nhóm hồng y nhân Ma Diễm môn bày trận hình kỳ quái, lấy đại kỳ đỏ rực có Kim ô liệt dương rồi niệm chú để phóng Thanh dương ma hỏa. Khi pháp thuật thành công, ngọn lửa màu xanh trong đại kỳ hướng về Lữ Thiên Mông, khiến thế phòng thủ của thất phái trở nên bất lợi.","nguon":["@c0266"]},{"id":"linh-quang-thuat","name":"Linh quang thuật","cn":"","loai":"than-thong","loaiLabel":"Thuật pháp quan sát","phamCap":"chỉ tu sĩ Trúc Cơ kỳ sử dụng được","hePhai":"không rõ","soHuu":["Hàn Lập","Tu sĩ Trúc Cơ kỳ thất phái dùng Linh quang thuật"],"blurb":"Linh quang thuật là thuật quan sát được tu sĩ Trúc Cơ kỳ dùng để nhìn ra lớp ẩn thân trước đội Ma Diễm môn. Nhờ thuật này, Hàn Lập phát hiện các bóng trắng và ngân ti đang khống chế pháp khí.","detail":"Sau khi phi thiên ngô công và pháp khí của thất phái bị thủ đoạn vô hình xử lý, một tu sĩ Trúc Cơ nhắc mọi người dùng Linh quang thuật. Hàn Lập thi triển theo và thấy trước hồng y nhân Ma Diễm môn có các bóng trắng yếu nhược đang thả ngân ti trói pháp khí.","nguon":["@c0266"]},{"id":"bi-phap-an-than-cua-bong-trang","name":"Bí pháp ẩn thân của bóng trắng","cn":"","loai":"bi-thuat","loaiLabel":"Bí pháp","phamCap":"không rõ","hePhai":"Ma Diễm môn","soHuu":["Bóng trắng ẩn thân trước Ma Diễm môn"],"blurb":"Bí pháp ẩn thân của bóng trắng che giấu lớp bảo vệ đứng trước đội hồng y nhân Ma Diễm môn. Thủ đoạn này chỉ bị nhìn ra khi tu sĩ Trúc Cơ dùng Linh quang thuật.","detail":"Các bóng trắng ẩn trước đội hình hồng y nhân khiến thất phái ban đầu không nhận ra nguồn chém nát phi thiên ngô công và khống chế pháp khí. Khi Linh quang thuật được thi triển, thân hình yếu nhược của chúng mới lộ ra trước mắt Hàn Lập.","nguon":["@c0266"]},{"id":"ngan-ti","name":"Ngân ti","cn":"","loai":"than-thong","loaiLabel":"Thủ đoạn pháp thuật","phamCap":"không rõ","hePhai":"Ma Diễm môn","soHuu":["Bóng trắng ẩn thân trước Ma Diễm môn"],"blurb":"Ngân ti là các sợi bạc do bóng trắng ẩn thân thả ra để khống chế pháp khí. Những sợi này bó chặt pháp khí công kích, khiến chúng không thể nhúc nhích.","detail":"Khi bị Linh quang thuật nhìn ra, các bóng trắng trước đội Ma Diễm môn đang thả ngân ti để trói chặt pháp khí của thất phái. Thủ đoạn này khiến công kích bằng pháp khí thông thường khó phá được lớp bảo vệ cho đội Cuồng diễm tu sĩ.","nguon":["@c0266"]},{"id":"thanh-duong-ma-hoa-quyet","name":"Thanh dương ma hỏa quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Thiên Sát tông / ma đạo","soHuu":["Các Hồng y nhân"],"blurb":"Công pháp mà cuồng diễm tu sĩ phải tu luyện để thi triển Thanh dương ma hỏa. Lữ Thiên Mông nói mỗi lần phóng loại ma hỏa này sẽ khiến người dùng hao tổn tu vi rất nhiều.","detail":"Trong trận linh quáng, Lữ Thiên Mông giải thích Thanh dương ma hỏa không thể tùy tiện phóng ra mà đòi hỏi các cuồng diễm tu sĩ tu luyện Thanh dương ma hỏa quyết. Công pháp này đổi lấy uy lực cực mạnh của ma hỏa bằng cái giá hao tổn tu vi mỗi lần thi triển.","nguon":["@c0267"]},{"id":"tho-don-thuat","name":"Thổ độn thuật","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật độn thổ","phamCap":"không rõ","hePhai":"","soHuu":[],"blurb":"Pháp thuật giúp tu sĩ độn hành trong đất. Hàn Lập hối hận vì chưa học thuật này khi bị chôn dưới lòng đất sau vụ sập đường hầm.","detail":"Trong hoàn cảnh bị đất đá vùi lấp và không xác định được phương hướng, Hàn Lập nghĩ nếu biết Thổ độn thuật thì có thể thi pháp đi trong đất, thay vì phải dựa vào khôi lỗi thú mở đường.","nguon":["@c0268"]},{"id":"luc-giac-truyen-tong-tran-co","name":"Lục giác truyền tống trận cổ","cn":"","aliases":["Truyền tống trận"],"loai":"khac","loaiLabel":"Trận pháp truyền tống","phamCap":"cổ trận","hePhai":"","soHuu":[],"blurb":"Truyền tống trận sáu góc cực cổ nằm trong nhũ động phía sau Bạch tri thù. Trận pháp được quặng linh thạch bao quanh và nằm cạnh năm hài cốt cùng lệnh bài màu lam.","detail":"Nhóm Hàn Lập phát hiện trận pháp này trong nhũ động lớn dưới lòng đất. Nó nằm sau lưng Bạch tri thù, được một đống quặng linh thạch bao lấy, bên cạnh có năm hài cốt ngồi tỏa ngũ sắc quang hoa và các lệnh bài màu lam, cho thấy đây là một bí mật quan trọng của khu vực.","nguon":["@c0268"]},{"id":"phu-luc-dieu-khien-da","name":"Phù lục điều khiển đá","cn":"","loai":"khac","loaiLabel":"Phù lục / thuật pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Tuyên Nhạc"],"blurb":"Phù lục màu vàng được Tuyên Nhạc dùng để điều động đá lớn trong sơn động. Nó tạm thời ép Bạch tri thù vào đỉnh động, tạo cơ hội cho Lữ Thiên Mông dùng Túi nhật nguyệt thu yêu thú.","detail":"Khi Bạch tri thù lao tới, Tuyên Nhạc ấn phù lục màu vàng xuống đất, khiến nhiều tảng đá lớn bay chuẩn xác về phía bụng yêu thú. Đòn này khóa chuyển động của Bạch tri thù trong thời gian ngắn nhưng không đủ giải quyết triệt để nguy cơ.","nguon":["@c0269"]},{"id":"bang-vu-thuat","name":"Băng vũ thuật","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật băng hệ","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Tuyên Nhạc"],"blurb":"Băng vũ thuật là pháp thuật băng hệ do Tuyên Nhạc thi triển khi giao chiến với Hàn Lập trong nhũ động.","detail":"Tuyên Nhạc dùng Băng vũ thuật tạo băng trùy lớn bắn về phía Hàn Lập, nhằm làm chậm bước áp sát của đối phương trong địa hình chật hẹp.","nguon":["@c0270"]},{"id":"co-truyen-tong-tran","name":"Cổ Truyền tống trận","cn":"","aliases":["Truyền tống trận cổ xưa","Truyền tống trận pháp thượng cổ","Cổ trận truyền tống nghi hư hỏng","Truyền tống trận"],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"thượng cổ","hePhai":"không rõ","soHuu":[],"blurb":"Trận truyền tống trong huyệt động bị hư một góc, chưa thể sử dụng bình thường. Hàn Lập sao chép dạng thức và hoa văn để tìm cách sửa, sau đó suy đoán đây có thể là cổ trận truyền tống siêu xa.","detail":"Cổ Truyền tống trận nằm trong huyệt động nơi Hàn Lập thu Đại na di lệnh. Vì một góc trận đã hư hại, Hàn Lập không thể dùng ngay mà sao chép hoa văn vào ngọc giản; sau khi tra cứu công dụng Đại na di lệnh, hắn nảy ý sửa trận để rời xa chiến cuộc giữa bảy phái Việt quốc và sáu tông ma đạo.","nguon":["@c0271"]},{"id":"tieu-truyen-tong-tran-trong-va-ngoai-nhac-loc-dien","name":"Tiểu Truyền tống trận trong và ngoài Nhạc Lộc điện","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Trận truyền tống đoạn ngắn được nêu làm đối chiếu với cổ trận truyền tống siêu xa. Loại truyền tống này không gây áp lực không gian đáng kể như truyền tống khoảng cách cực xa.","detail":"Khi Hàn Lập tra cứu về Đại na di lệnh và cổ Truyền tống trận, tiểu Truyền tống trận trong và ngoài Nhạc Lộc điện được nhắc như ví dụ về truyền tống đoạn ngắn. Sự đối chiếu này giúp làm rõ vì sao truyền tống siêu xa cần pháp khí bảo hộ như Đại na di lệnh.","nguon":["@c0271"]},{"id":"phap-tran-khong-than","name":"Pháp trận khống thần","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"cơ bản","hePhai":"tu sĩ phổ thông","soHuu":["Hàn Lập"],"blurb":"Pháp trận dùng để khống chế trứng yêu thú. Hàn Lập vẽ trận này, nhỏ tinh huyết và cho hai trứng nhện hấp thu.","detail":"Sau khi thấy hai trứng nhện lớn lên nhờ Linh nhãn chi tuyền, Hàn Lập vẽ một pháp trận khống thần đơn giản, dùng tinh huyết để tạo liên hệ khống chế với yêu thú non trong tương lai.","nguon":["@c0272"]},{"id":"tran-ky-tieu-cam","name":"Trận kỳ tiểu cấm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp/cấm chế","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Bộ trận kỳ dùng để phong bế nơi ở tạm. Hàn Lập dùng nó khóa thạch ốc trước khi kiểm kê chiến lợi phẩm.","detail":"Khi trở lại thạch ốc trong doanh trại Kim Cổ nguyên, Hàn Lập bố trí trận kỳ tiểu cấm để phong bế chỗ ở, rồi mới phân loại vật phẩm thu được từ túi trữ vật của đối thủ.","nguon":["@c0272"]},{"id":"nhan-mi-cong","name":"Nhân Mị công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Yểm Nguyệt tông","soHuu":["Nam Cung Uyển"],"blurb":"Công pháp của Yểm Nguyệt tông được Lý Hóa Nguyên nhắc tới khi cảnh báo Hàn Lập. Ông lo Hàn Lập tiếp xúc nhiều với Nam Cung Uyển sẽ bị ảnh hưởng thần trí mà không tự biết.","detail":"Lý Hóa Nguyên dùng Nhân Mị công làm lý do khuyên Hàn Lập ít qua lại với Nam Cung Uyển. Trong lời cảnh báo, công pháp này gắn với khả năng khiến người khác bất tri bất giác nghe lời tu sĩ Yểm Nguyệt tông.","nguon":["@c0274"]},{"id":"tran-phap-ngoai-thung-lung-cua-te-van-tieu","name":"Trận pháp ngoài thung lũng của Tề Vân Tiêu","cn":"","loai":"than-thong","loaiLabel":"Trận pháp / cấm chế","phamCap":"không rõ","hePhai":"trận pháp","soHuu":["Tề Vân Tiêu"],"blurb":"Trận pháp hoặc cấm chế bảo vệ quanh thung lũng nơi Tề Vân Tiêu cư trú. Người ngoài phải đi theo đúng lộ tuyến do người quen dẫn đường để tránh chạm cấm chế.","detail":"Chưởng quầy trà quán dẫn Hàn Lập qua vùng đồi núi phía tây Kim Mã thành tới thung lũng của Tề Vân Tiêu và nhắc phải theo sát, nếu đi sai đường sẽ đụng cấm chế rất phiền toái. Điều này cho thấy nơi ở của Tề Vân Tiêu được bố trí trận pháp phòng hộ riêng.","nguon":["@c0275"]},{"id":"tran-phap-don-gian-trong-rung-cay","name":"Trận pháp đơn giản trong rừng cây","cn":"","loai":"than-thong","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Tân Như Âm"],"blurb":"Trận pháp phòng hộ do Tân Như Âm vội vàng bố trí trong rừng gần Bích Vân sơn bằng trận kỳ tùy thân.","detail":"Khi bị nhóm tu sĩ Luyện Khí kỳ truy đuổi, Tân Như Âm dùng một bộ trận kỳ mang theo để lập trận đơn giản trong rừng, tạm thời tạo màn thanh quang che chở. Lúc Hàn Lập tới nơi, màn phòng hộ này đã bị nhóm truy đuổi công kích đến suy yếu.","nguon":["@c0276"]},{"id":"tran-phap-phong-bi-quanh-cho-o-tan-nhu-am","name":"Trận pháp phòng bị quanh chỗ ở Tân Như Âm","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Tân Như Âm"],"blurb":"Trận pháp phòng bị được Hàn Lập suy đoán tồn tại quanh nơi ở của Tân Như Âm. Bề ngoài khu vực chỉ có sương mù nhàn nhạt, nhưng vì chủ nhân là trận pháp sư nên hắn không dám xem thường.","detail":"Khi đến chỗ ở của Tân Như Âm, Hàn Lập không nhìn ra dị thường rõ ràng ngoài lớp sương mù nhàn nhạt. Tuy vậy, hắn phán đoán nơi cư trú của người tinh thông trận pháp chắc chắn có biện pháp phòng bị, thể hiện sự thận trọng trước khả năng nơi này được bố trí trận pháp không nhỏ.","nguon":["@c0277"]},{"id":"dan-khi-thuat","name":"Dẫn khí thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật thu liễm khí tức","phamCap":"Chỉ tu sĩ Trúc Cơ kỳ mới có thể học","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Dẫn khí thuật là thuật thu liễm linh khí mà Hàn Lập dùng trong tửu lâu. Sau khi thi triển, tu sĩ Luyện Khí kỳ nhìn hắn không khác gì phàm nhân.","detail":"Hàn Lập vận dụng Dẫn khí thuật để thu linh khí vào cơ thể khi phát hiện năm tu sĩ Luyện Khí kỳ trên lầu hai tửu lâu. Nhờ vậy, hắn che giấu thân phận Trúc Cơ kỳ và thuận lợi âm thầm quan sát nhóm Mông Sơn Ngũ Hữu.","nguon":["@c0284"]},{"id":"cam-che-co-quai","name":"Cấm chế cổ quái","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"","soHuu":["Kẻ bí ẩn khống chế Mông Sơn Ngũ Hữu"],"blurb":"Cấm chế cổ quái là thủ đoạn mà kẻ bí ẩn đặt lên người Mông Sơn Ngũ Hữu. Theo lão già mặt đen, nếu không được đối phương xử lý đúng cách, nhóm có thể bạo thể mà chết.","detail":"Cấm chế này khiến sinh tử của Mông Sơn Ngũ Hữu bị kẻ khác nắm giữ. Lão già mặt đen cho rằng Thất đại phái chưa chắc giải được, còn việc tùy tiện chống lại có thể dẫn đến hậu quả chết người.","nguon":["@c0284"]},{"id":"than-thuc","name":"Thần thức","cn":"","loai":"than-thong","loaiLabel":"Thần thông/cảm ứng","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Năng lực cảm ứng được Hàn Lập dùng để nghe chuyện nhóm tu sĩ và bao phủ Tần phủ khi tu luyện. Trong chương này, thần thức giúp hắn nắm được cả lời bàn ở quán lẫn những lời xấu sau lưng trong phủ.","detail":"Hàn Lập dùng thần thức nghe nhóm tu sĩ bàn về vụ mất tích, sau đó thu về khi quyết định không can dự. Về sau, khi tu luyện ban đêm trong Tần phủ, hắn để thần thức bao phủ chung quanh nên nghe rõ lời bất mãn và một số bí mật của người trong phủ.","nguon":["@c0285"]},{"id":"tien-thuat","name":"Tiên thuật","cn":"","loai":"khac","loaiLabel":"Phép tu tiên","phamCap":"Không rõ","hePhai":"Tu tiên","soHuu":["Ngô tiên sư"],"blurb":"Phép tu tiên được Hinh Vương nhắc tới khi kể con út có tiên căn. Đây là thứ người có tiên duyên có thể lĩnh ngộ khi theo Ngô tiên sư học đạo.","detail":"Trong yến hội Hinh Vương phủ, Hinh Vương nói con út của ông có tiên căn nên có thể lĩnh ngộ tiên thuật và sắp rời phủ tu tiên học đạo. Khái niệm này được dùng để thuyết phục khách khứa đưa con cháu tới cho Ngô tiên sư xem mặt.","nguon":["@c0287"]},{"id":"cong-phap-che-giau-linh-khi","name":"Công pháp che giấu linh khí","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Chưa rõ","hePhai":"Gia tộc của thanh bào lão giả","soHuu":["Thanh bào lão giả","Thiếu nữ nam trang"],"blurb":"Pháp môn giúp thanh bào lão giả và thiếu nữ nam trang che giấu linh khí trong đại sảnh Tần phủ. Hàn Lập nhận ra công pháp này có thể qua mắt tu sĩ cùng cấp nên sinh ý muốn tìm hiểu.","detail":"Công pháp này khiến linh khí của người tu luyện được che giấu, đến mức Ngô tiên sư khó phát giác hai tu sĩ già trẻ trong sảnh. Hàn Lập nhờ tu vi cao hơn nhiều mới nhận ra và đánh giá nếu học được, khi tranh đấu có thể chiếm tiên cơ.","nguon":["@c0288"]},{"id":"mong-yem-thuat","name":"Mộng yểm thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Pháp thuật mê hồn","phamCap":"Chưa rõ","hePhai":"Chưa rõ","soHuu":["Thanh bào lão giả"],"blurb":"Mộng yểm thuật là pháp thuật mê hồn thanh bào lão giả dùng qua ánh mắt tím để giáo huấn Hàn Lập. Do chênh lệch tu vi, lão bị Hàn Lập chế trụ ngược và suýt chịu phản phệ.","detail":"Thanh bào lão giả tưởng Hàn Lập là công tử phàm tục nên dùng Mộng yểm thuật. Trước tu vi Trúc Cơ trung kỳ của Hàn Lập, thuật này không áp chế được mục tiêu mà khiến người thi triển rơi vào thế nguy, chỉ thoát ra khi Hàn Lập hạ thủ lưu tình.","nguon":["@c0288"]},{"id":"hoa-dieu-thuat","name":"Hỏa điểu thuật","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"Trung cấp bậc thấp","hePhai":"Hỏa hệ","soHuu":[],"blurb":"Hỏa điểu thuật là pháp thuật hỏa hệ trung cấp bậc thấp có uy lực lớn. Hàn Lập thoáng tưởng Ngô tiên sư thi triển thuật này khi thấy quả cầu lửa hóa chim, nhưng sau đó nhận ra không phải chân thuật.","detail":"Trong màn biểu diễn ở Hinh vương phủ, hình thái chim lửa do Ngô tiên sư tạo ra khiến Hàn Lập liên tưởng đến Hỏa điểu thuật. Tuy nhiên dao động pháp lực không tăng và kích thước vẫn như Hỏa đạn thuật, nên Hàn Lập xác định đó chỉ là biến hình chứ không phải Hỏa điểu thuật thật sự.","nguon":["@c0289"]},{"id":"phap-thuat-dieu-khien-ngon-lua","name":"Pháp thuật điều khiển ngọn lửa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Ngô tiên sư"],"blurb":"Pháp thuật điều khiển lửa do Ngô tiên sư thi triển trước khách khứa trong Hinh Vương phủ. Màn biểu diễn khiến người thế tục kinh sợ và làm Hinh Vương nở mày nở mặt.","detail":"Trong buổi kiểm tra tiên duyên tại Hinh Vương phủ, Ngô tiên sư vừa thi triển màn điều khiển ngọn lửa khiến khách khứa phàm tục kinh hãi. Chương nhắc lại tác dụng biểu diễn của pháp thuật này như bằng chứng rõ rệt về thân phận tiên sư trước mắt người thế tục.","nguon":["@c0290"]},{"id":"thang-tien-dai-hoi","name":"Thăng Tiên đại hội","cn":"","loai":"khac","loaiLabel":"Cơ chế tu tiên giới","phamCap":"Không rõ","hePhai":"Tu tiên giới","soHuu":[],"blurb":"Cơ hội trong tu tiên giới khiến tu sĩ cấp thấp tranh đoạt hy vọng Trúc Cơ. Sự xuất hiện của nó làm người tu tiên ít lưu lại thế tục hơn trước.","detail":"Chương giải thích rằng sau khi Thăng Tiên đại hội xuất hiện, người tu tiên vì hy vọng Trúc Cơ mà đánh nhau sống chết, từ đó chuyên tâm ẩn cư khổ tu thay vì làm môn khách cho phàm nhân. Đây là nguyên nhân khiến người tu tiên ngày càng hiếm khi công khai xuất hiện trong thế tục giới.","nguon":["@c0290"]},{"id":"truc-co","name":"Trúc Cơ","cn":"","loai":"khac","loaiLabel":"Cảnh giới tu luyện","phamCap":"Cảnh giới","hePhai":"Tu tiên giới","soHuu":[],"blurb":"Mục tiêu tu luyện quan trọng đối với tán tiên và tu sĩ cấp thấp trong gia tộc tu tiên. Hy vọng Trúc Cơ khiến họ tranh đoạt cơ hội trong Thăng Tiên đại hội.","detail":"Trong lời giải thích của chương, Trúc Cơ là hy vọng khiến người tu tiên cấp thấp đánh nhau sống chết tại Thăng Tiên đại hội. Vì mục tiêu này, họ không còn dễ chán nản mà lưu luyến vinh hoa phú quý nơi thế tục.","nguon":["@c0290"]},{"id":"dau-hieu-truy-tung-cua-han-lap","name":"Dấu hiệu truy tung của Hàn Lập","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Thủ đoạn truy tung","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thủ đoạn Hàn Lập dùng để đánh dấu hai ông cháu họ Tiêu trước cuộc giao dịch cưỡng ép.","detail":"Hàn Lập bắn hai đạo lục quang nhỏ vào người Tiêu Chấn và thiếu nữ họ Tiêu, giải thích đó là dấu hiệu truy tung để tìm chính xác chỗ ở của họ. Hắn hứa sẽ xóa dấu hiệu sau khi giao dịch quyển sách vô danh hoàn tất.","nguon":["@c0292"]},{"id":"dan-khi-quyet","name":"Dẫn khí quyết","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Chỉ tu sĩ sau Trúc Cơ mới có thể thi triển","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Pháp môn che giấu khí tức được Hàn Lập dùng khi đột nhập vương phủ. Chương này nói rõ nó chỉ là thủ đoạn tu sĩ sau Trúc Cơ mới có thể thi triển.","detail":"Hàn Lập thi triển Dẫn khí quyết cùng Ẩn hình thuật để vô thanh vô tức tiến vào khu phía sau vương phủ, tránh bị người trong phủ phát hiện khí tức. Pháp môn này được mô tả là công pháp che giấu khí tức mà chỉ tu sĩ sau Trúc Cơ mới có thể thi triển.","nguon":["@c0293"]},{"id":"khong-than-thuat","name":"Khống thần thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Pháp thuật khống chế tâm thần","phamCap":"Trúc Cơ kỳ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Pháp thuật khống chế tâm thần tiêu hao tâm thần rất lớn, hữu hiệu với phàm nhân trong một thời gian. Hàn Lập dùng nó để thẩm vấn tiểu nha hoàn vương phủ.","detail":"Khống thần thuật có thể khiến phàm nhân trúng thuật nghe lệnh như nô lệ trong thời gian ngắn, nhưng tiêu hao tâm thần rất lớn. Pháp thuật này không có hiệu quả với tu sĩ có linh lực trong não, đồng thời đòi hỏi người thi triển ở Trúc Cơ kỳ có thần thức vượt xa người thường; Hàn Lập từng thấy khẩu quyết ở Thiên Tri các, ghi lại vì tò mò rồi luyện thành sau khi về động phủ.","nguon":["@c0293","@c0305"]},{"id":"khong-hoa-thuat","name":"Khống hỏa thuật","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"Không rõ","hePhai":"Tán tu","soHuu":["Lão đạo đầu bạc"],"blurb":"Thuật điều khiển lửa do lão đạo đầu bạc từng biểu diễn trong vương phủ. Chính biểu hiện này khiến Hàn Lập hỏi tới lai lịch công pháp của ông.","detail":"Khống hỏa thuật là cách gọi cho thủ đoạn điều khiển ngọn lửa của lão đạo đầu bạc. Hàn Lập đánh giá thuật này khá thú vị, từ đó dẫn đến việc lão đạo trình ra Lộng Diễm quyết do mình tự nghiên cứu.","nguon":["@c0294"]},{"id":"liet-duong-quyet","name":"Liệt Dương quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Lão đạo đầu bạc","Tu tiên giả sắp chết sở hữu Liệt Dương quyết"],"blurb":"Công pháp mà lão đạo đầu bạc tình cờ tìm được trên người một tu tiên giả sắp chết khi còn trẻ. Nhờ nó ông bước vào tu tiên giới nhưng chỉ luyện đến Luyện Khí tầng sáu.","detail":"Liệt Dương quyết là cơ duyên ban đầu của lão đạo đầu bạc. Do tư chất kém và thiếu người chỉ điểm, ông không tiến xa với công pháp này, nhưng nó trở thành nền tảng để ông tiếp xúc tu tiên và về sau tự mày mò thuật điều khiển lửa.","nguon":["@c0294"]},{"id":"long-diem-quyet","name":"Lộng Diễm quyết","cn":"","loai":"than-thong","loaiLabel":"Tâm pháp điều khiển lửa","phamCap":"Không rõ","hePhai":"Tán tu","soHuu":["Lão đạo đầu bạc","Hàn Lập"],"blurb":"Tâm pháp điều khiển lửa do lão đạo đầu bạc tự nghiên cứu hơn mười năm rồi viết thành sách. Hàn Lập nhận ra phần cuối sách có giá trị mở rộng hiểu biết về vận dụng pháp thuật.","detail":"Lộng Diễm quyết xuất phát từ các tiểu xảo điều khiển lửa do lão đạo đầu bạc tự cải biến và hoàn thiện. Ban đầu Hàn Lập chỉ xem là thủ pháp hoa mỹ, nhưng khi đọc sâu hơn, hắn thấy trong sách có các khái niệm linh hoạt và phương pháp tu luyện giúp ích cho cách sử dụng pháp thuật, nên dùng hai bình Hoàng Long Đan đổi lấy.","nguon":["@c0294"]},{"id":"tieu-ky-linh-luc","name":"Tiêu ký linh lực","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Thủ đoạn để lại linh lực trong người mục tiêu nhằm truy tung và khống chế tình hình khi có biến.","detail":"Hàn Lập đặt tiêu ký linh lực trong người lão đạo tóc bạc, nói rằng nhờ vậy nếu xảy ra chuyện hắn có thể lập tức tìm đến, đồng thời khiến lão đạo khó thoái thác hoặc lẩn tránh nhiệm vụ giám thị.","nguon":["@c0295"]},{"id":"linh-khi-cam-ung-truy-tim-nguoi","name":"Linh khí cảm ứng truy tìm người","cn":"","loai":"than-thong","loaiLabel":"Thủ đoạn truy tung","phamCap":"Trúc Cơ kỳ thường dùng","hePhai":"không rõ","soHuu":["Tu sĩ Trúc Cơ kỳ","Hàn Lập"],"blurb":"Thủ đoạn dùng linh khí cảm ứng để lần tìm người đã bị lưu lại dấu vết.","detail":"Chương nêu tu sĩ Trúc Cơ kỳ thông thường chỉ cảm ứng được tiêu ký trong phạm vi khoảng mười dặm, còn Hàn Lập nhờ Đại Diễn Quyết có thể mở rộng tới hơn trăm dặm.","nguon":["@c0295"]},{"id":"ngon-chu","name":"Ngôn chú","aliases":["Huyết chú","Huyết chú cấm chế"],"cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật cấm chế","phamCap":"không rõ","hePhai":"Bổn giáo của hai kẻ áo đỏ","soHuu":["Bổn giáo của hai kẻ áo đỏ"],"blurb":"Ngôn chú là cấm chế được hai kẻ áo đỏ nhắc đến khi bàn về Mông thị huynh đệ. Nó khiến người bị chế ước không dám hoặc không thể tiết lộ sự tình của bổn giáo.","detail":"Trong chương 298, hai kẻ áo đỏ cho rằng Mông thị huynh đệ dù bị bắt sống cũng khó tiết lộ bí mật vì đã có huyết chú cấm chế. Người trẻ tuổi áo đỏ còn nói hắn đã bí mật hạ thủ nhóm này, khiến thời gian sống của họ chỉ còn rất ngắn.","nguon":["@c0298"]},{"id":"ke-hoach-kim-thien-thoat-xac","name":"Kế hoạch kim thiền thoát xác","aliases":[],"cn":"","loai":"khac","loaiLabel":"Kế hoạch thế lực","phamCap":"không rõ","hePhai":"Bổn giáo của hai kẻ áo đỏ","soHuu":["Bổn giáo của hai kẻ áo đỏ"],"blurb":"Kế hoạch kim thiền thoát xác là bố trí của bổn giáo nhằm tạo thân phận bên ngoài Tu tiên giới cho đệ tử nòng cốt. Ngô lão đạo được dự định làm sư phụ bù nhìn cho người trẻ tuổi áo đỏ.","detail":"Lão giả áo đỏ cho biết bổn giáo muốn dùng Ngô lão đạo làm vỏ bọc, để người trẻ tuổi áo đỏ có thân phận hợp lý mà dần lộ diện trong Tu tiên giới. Bố trí này bị xáo trộn khi người trẻ tuổi vào phòng Ngô lão đạo và hút tinh huyết của lão.","nguon":["@c0298"]},{"id":"tu-la-cong","name":"Tu La công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Phe giáo chủ tại Việt Kinh","soHuu":["Tiểu vương gia Minh nhi"],"blurb":"Công pháp Tiểu vương gia đang tu luyện, liên quan trực tiếp tới tình trạng pháp lực phản phệ của hắn.","detail":"Vương tổng quản cho rằng Tiểu vương gia vì nóng vội muốn hoàn thành Tu La công nên pháp lực phản phệ phát tác sớm hơn, buộc hắn phải hút tinh huyết Ngô lão đạo để áp chế chân nguyên trong cơ thể.","nguon":["@c0299"]},{"id":"than-thuc-xam-nhap-than-thuc-hai","name":"Thần thức xâm nhập Thần thức hải","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Phương pháp cưỡng ép giải ngôn chú do Hàn Lập nêu ra, dùng thần thức xâm nhập Thần thức hải để xóa ấn ký cấm chế. Cách này đòi hỏi thần thức người giải mạnh hơn nhiều so với người hạ chú và nếu thất bại sẽ lập tức kích phát ngôn chú.","detail":"Trong lúc thẩm vấn nhóm bốn người bị bắt, Hàn Lập nói ngoài khẩu quyết giải chú còn có thể dùng thần thức tiến vào Thần thức hải của người bị chú để cưỡng ép xóa ấn ký. Đây là cách nguy hiểm, bởi nếu không thành công thì ngôn chú phát tác ngay, khiến những người bị chú vô cùng sợ hãi.","nguon":["@c0300"]},{"id":"huyet-chu","name":"Huyết chú","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế chú thuật","phamCap":"Không rõ","hePhai":"Thế lực dùng huyết chú khống chế Mông Sơn ngũ hữu","soHuu":["Thế lực dùng huyết chú khống chế Mông Sơn ngũ hữu"],"blurb":"Huyết chú là cấm chế đặt trên người Mông Sơn ngũ hữu, dùng để khống chế họ. Hàn Lập nghiên cứu chú này rồi biến việc giải trừ nó thành điều kiện buộc nhóm giao tin tức và tạm thời nghe lệnh.","detail":"Trong chương 301, Huyết chú là vấn đề sinh tử của Mông Sơn ngũ hữu. Hàn Lập nhấn mạnh mình chưa từng hứa giải chú miễn phí, sau đó yêu cầu nhóm nói hết tin tức và tuân theo phân phó của hắn trước khi chuẩn bị thử giải chú trên lão giả mặt đen.","nguon":["@c0301"]},{"id":"ta-cong-cua-hac-sat-giao","name":"Tà công của Hắc sát giáo","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp tà đạo","phamCap":"Không rõ","hePhai":"Hắc sát giáo","soHuu":["Hắc sát giáo"],"blurb":"Tà công mà Hắc sát giáo luyện bằng cách bắt tu tiên giả. Mông Sơn ngũ hữu chỉ biết đây là mục đích chính của việc đối phương bắt người.","detail":"Theo manh mối Mông Sơn ngũ hữu cung cấp, Hắc sát giáo bắt người chủ yếu để tu luyện tà công. Chi tiết công pháp chưa được lộ rõ trong chương này.","nguon":["@c0302"]},{"id":"an-than-phap-thuat","name":"Ẩn thân pháp thuật","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập","Mông Sơn tứ hữu"],"blurb":"Pháp thuật giúp Hàn Lập và Mông Sơn tứ hữu lặng lẽ tiềm nhập Hinh Vương phủ trong đêm.","detail":"Trong đêm hành động ở Hinh Vương phủ, Hàn Lập cùng bốn người còn lại của Mông Sơn ngũ hữu thi triển pháp thuật ẩn thân để tránh kinh động người trong phủ.","nguon":["@c0305"]},{"id":"cach-am-ket-gioi","name":"Cách âm kết giới","cn":"","loai":"khac","loaiLabel":"Kết giới","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kết giới do Hàn Lập dựng quanh tiểu lâu nhằm che giấu động tĩnh khi bắt Tiểu vương gia.","detail":"Trước khi lên tầng ba tiểu lâu của Tiểu vương gia, Hàn Lập không tiếc pháp lực bố trí một tầng cách âm kết giới lớn quanh nơi này để tránh kinh động Vương tổng quản và người trong phủ.","nguon":["@c0305"]},{"id":"phap-quyet-che-giau-khi-tuc-vo-danh","name":"Pháp quyết che giấu khí tức vô danh","cn":"","loai":"cong-phap","loaiLabel":"Pháp quyết","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Pháp quyết giúp Hàn Lập che giấu khí tức khi tiếp cận phòng Vương tổng quản.","detail":"Khi vận dụng, linh khí trên người Hàn Lập tiêu tán, khiến hắn trông như phàm nhân bình thường. Hắn dùng thủ đoạn này thay cho thần thức vì còn dè chừng sự quỷ dị của Vương tổng quản.","nguon":["@c0306"]},{"id":"lac-thach-tran","name":"Lạc Thạch trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"đơn giản","hePhai":"Thổ thuộc tính","soHuu":["Hắc Sát giáo"],"blurb":"Trận pháp Thổ thuộc tính bố trí quanh miếu hoang ngoài kinh thành.","detail":"Trận tạo màn hào quang vàng nhạt bảo vệ miếu hoang, ban đầu khiến Mông Sơn tứ hữu không dám xông vào. Hàn Lập dùng Thiên Nhãn thuật nhận ra đây chỉ là trận pháp đơn giản, rồi dùng bốn khôi lỗi và Ô long đoạt cường công phá hủy.","nguon":["@c0306"]},{"id":"hac-phong-tran","name":"Hắc Phong trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Hắc Sát giáo","soHuu":["Tiểu vương gia","Hắc y nhân Hắc Sát giáo"],"blurb":"Hắc Phong trận là trận pháp do Hắc y nhân Hắc Sát giáo dùng cờ đen triển khai để vây bắt Hàn Lập.","detail":"Huyết Thị nhận định muốn bắt Hàn Lập Trúc Cơ trung kỳ thì cần Hắc Phong trận hỗ trợ. Theo lệnh Tiểu vương gia, Hắc y nhân rút cờ đen bày trận; sau khi bị Hàn Lập phá rối, họ tiếp tục được tổ chức lại để múa cờ tạo mây mù đen và tiếng quỷ khóc.","nguon":["@c0307"]},{"id":"huyet-te-luyen-cong","name":"Huyết tế luyện công","cn":"","loai":"bi-thuat","loaiLabel":"Ma công/nghi thức tu luyện","phamCap":"Không rõ","hePhai":"Hắc Sát giáo","soHuu":["Giáo chủ Hắc Sát giáo"],"blurb":"Huyết tế luyện công là cách Giáo chủ Hắc Sát giáo sử dụng tu sĩ bị bắt làm tài nguyên tu luyện.","detail":"Tiểu vương gia và Huyết Thị cho rằng nếu hiến Hàn Lập cho Giáo chủ huyết tế luyện công thì hiệu quả sẽ tốt hơn các tu sĩ trước, vì Hàn Lập là tu sĩ Trúc Cơ trung kỳ có tinh huyết giá trị hơn.","nguon":["@c0307"]},{"id":"huyet-quang-ho-the-cua-huyet-thi","name":"Huyết quang hộ thể của Huyết Thị","cn":"","loai":"than-thong","loaiLabel":"Ma công","phamCap":"Không rõ","hePhai":"Hắc Sát giáo","soHuu":["Huyết Thị đại nhân"],"blurb":"Huyết quang hộ thể của Huyết Thị là ma công huyết sắc vừa phòng thủ vừa áp chế pháp khí.","detail":"Huyết quang trên người Huyết Thị giúp hắn truy kích Hàn Lập, cuốn giữ Tam Lăng thứ của Lão Nhị cao gầy, làm mất linh khí của pháp khí, tăng uy lực quyền kình và hóa thành khối huyết sắc cao lớn ngăn nhiều đỉnh cấp pháp khí của Hàn Lập.","nguon":["@c0307"]},{"id":"hac-quang-ho-than","name":"Hắc quang hộ thân","aliases":["Hộ thân sát khí"],"cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật phòng hộ","phamCap":"Chưa rõ","hePhai":"Phe tiểu vương gia","soHuu":["Tiểu vương gia","Vương tổng quản"],"blurb":"Bí pháp tạo hắc quang hoặc sát khí hộ thân cho tiểu vương gia và Vương tổng quản.","detail":"Tiểu vương gia và Vương tổng quản dùng hắc quang hộ thân khi bị Hàn Lập áp chế. Tiểu vương gia tin hộ thể sát khí này có thể ăn mòn pháp khí, nhưng Vương tổng quản vẫn bị Hàn Lập phá hộ thân và bắt sống.","nguon":["@c0308"]},{"id":"ma-cong-cua-dai-han-dau-bong-luong","name":"Ma công của đại hán đầu bóng lưỡng","cn":"","loai":"bi-thuat","loaiLabel":"Ma công","phamCap":"Chưa rõ","hePhai":"Phe Huyết Thị","soHuu":["Huyết Thị đại nhân"],"blurb":"Ma công từng thể hiện qua huyết quang của đại hán đầu bóng lưỡng.","detail":"Hàn Lập nhận ra công pháp hắc quang của tiểu vương gia và Vương tổng quản tương tự ma công của đại hán đầu bóng lưỡng, nhưng khác ở màu sắc biểu hiện: trước là huyết quang, nay là hắc quang.","nguon":["@c0308"]},{"id":"thanh-nguyen-kiem","name":"Thanh Nguyên kiếm","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết/pháp thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Kiếm xanh lớn do Hàn Lập sử dụng trong trận với Tiểu Vương gia.","detail":"Thanh Nguyên kiếm biến hóa linh hoạt, sượt qua chân Tiểu Vương gia, phá hắc khí hộ thân và chém đứt hai bắp chân đối phương.","nguon":["@c0309"]},{"id":"yeu-hoa","name":"Yêu hóa","cn":"","loai":"than-thong","loaiLabel":"Biến dị/thần thông chưa rõ","phamCap":"không rõ","hePhai":"Hắc Sát giáo","soHuu":["Huyết Thị đại nhân"],"blurb":"Trạng thái biến thân khiến đại hán đầu bóng lưỡng hóa thành quái vật hình người.","detail":"Sau khi phá Già Thiên chung, Huyết Thị đại nhân hiện hình cao hai trượng, có răng nanh, sừng cong, đuôi vảy, yêu văn đỏ và hung quang xanh ngọc. Thân thể yêu hóa có sức phòng ngự và công kích rất mạnh, chịu được cột sáng khôi lỗi và phá nát pháp khí của Mông Sơn tứ hữu.","nguon":["@c0309"]},{"id":"cot-sang-khoi-loi-thu","name":"Cột sáng khôi lỗi thú","cn":"","loai":"khac","loaiLabel":"Công kích khôi lỗi","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Đòn công kích đồng loạt từ các khôi lỗi thú của Hàn Lập.","detail":"Mười khôi lỗi thú đồng thời bắn cột sáng, có thể đánh ngã hoặc đẩy lùi đại hán yêu hóa khi hắn chưa kịp phòng bị, nhưng chưa đủ để tiêu diệt đối thủ.","nguon":["@c0309"]},{"id":"phu-bao-thi-phap","name":"Phù bảo thi pháp","cn":"","loai":"bi-thuat","loaiLabel":"Thi triển phù bảo","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Cách Hàn Lập vận công kích phát phù bảo khi pháp khí thông thường không đủ đối phó đại hán yêu hóa.","detail":"Hàn Lập giao Mông Sơn tứ hữu và khôi lỗi thú tạm chống đỡ, rồi lấy phù lục màu xanh ra, trịnh trọng cầm hai tay và vận công để thi triển.","nguon":["@c0309"]},{"id":"me-hon-huyen-sac-nhan","name":"Mê hồn Huyễn sắc nhãn","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật mê hồn","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Pháp thuật mê hồn được Hàn Lập dùng để khống chế tâm thần Tiểu vương gia sau khi cho đối phương uống dược vật.","detail":"Tại Tần trạch, Hàn Lập dùng Mê hồn Huyễn sắc nhãn để nắm tâm thần Tiểu vương gia, khiến đối phương như con rối và ngoan ngoãn khai hết bí mật Hắc Sát giáo.","nguon":["@c0310"]},{"id":"ma-cong-cua-tieu-vuong-gia","name":"Ma công của Tiểu vương gia","cn":"","loai":"cong-phap","loaiLabel":"Công pháp tà đạo","phamCap":"không rõ","hePhai":"Hắc Sát giáo","soHuu":["Tiểu vương gia"],"blurb":"Ma công tà đạo mà Tiểu vương gia từng tu luyện trong tuyến Hắc Sát giáo.","detail":"Tiểu vương gia từng tu luyện ma công và dùng nhiều tu sĩ để huyết tế. Đây là lý do Hàn Lập cho rằng hắn chết không oan sau khi bị thẩm vấn.","nguon":["@c0310"]},{"id":"hon-te","name":"Hồn tế","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật ma đạo","phamCap":"Không rõ","hePhai":"Ma Đạo","soHuu":["Ma Đạo"],"blurb":"Hồn tế là biến thể về sau của Huyết tế, nhắm vào hồn phách nguyên thần của người tu tiên thay vì trực tiếp thôn phệ tinh huyết. Bí pháp này tăng tu vi kém hơn, vẫn có giới hạn không thể Kết Đan và có nguy cơ cắn trả.","detail":"Hàn Lập giải thích Hồn tế do Ma Đạo sáng lập về sau, thuộc loại bí pháp chỉ một số cao tầng nắm giữ nên không truyền rộng. Nó tránh cách thôn phệ tinh huyết trực tiếp của Huyết tế nhưng vẫn không giúp người tu luyện vượt qua giới hạn Kết Đan, đồng thời cũng có khả năng phản phệ người sử dụng.","nguon":["@c0311"]},{"id":"sat-yeu-hoa-than","name":"Sát Yêu hóa thân","cn":"","loai":"than-thong","loaiLabel":"Thần thông biến hóa","phamCap":"Không rõ","hePhai":"Hắc Sát giáo","soHuu":["Thiết La"],"blurb":"Sát Yêu hóa thân là trạng thái biến hóa Thiết La từng vận dụng khi giao thủ với đối thủ mạnh. Nhờ hóa thành Sát Yêu, hắn giữ được mạng nhưng nguyên khí tổn thương nặng.","detail":"Thiết La nói đối thủ lần này khó nhằn đến mức hắn phải hóa thành Sát Yêu, nếu không có thể đã mất mạng. Sau khi trở về Hoàng Cung, hắn bị Băng Yêu nhận ra khí tức hư phù và cần khổ tu một thời gian mới có thể hồi phục.","nguon":["@c0311"]},{"id":"hoa-yeu-thuat","name":"Hóa Yêu thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật yêu hóa","phamCap":"không rõ","hePhai":"Hắc Sát giáo","soHuu":["Thiết La"],"blurb":"Bí thuật yêu hóa Thiết La từng thi triển, gây hao tổn nguyên khí. Sau khi hóa yêu, hắn khó khống chế thân thể tự nhiên và phải dựa vào trực giác để đào tẩu.","detail":"Hóa Yêu thuật là thủ đoạn khiến Thiết La bị thương tổn nguyên khí sau trận trước đó. Giáo chủ Hắc Sát giáo nhận định trạng thái hóa yêu khiến hắn không thể khống chế thân thể như thường, nên việc đào tẩu khi gặp Hàn Lập là lựa chọn sáng suốt.","nguon":["@c0312"]},{"id":"moc-ma-hoa-than","name":"Mộc Ma hóa thân","cn":"","loai":"than-thong","loaiLabel":"Hóa thân","phamCap":"không rõ","hePhai":"Hắc Sát giáo","soHuu":["Thanh Văn đạo sĩ"],"blurb":"Hóa thân của Thanh Văn, được giáo chủ Hắc Sát giáo đánh giá mạnh hơn Sát Yêu hóa thân của Thiết La. Nó được nhắc như thứ có phần nắm chắc hơn khi đối diện phù bảo của Hàn Lập.","detail":"Giáo chủ Hắc Sát giáo so sánh Mộc Ma hóa thân của Thanh Văn với Sát Yêu hóa thân của Thiết La, cho rằng nếu là Mộc Ma hóa thân thì còn có phần nắm chắc trước phù bảo của Hàn Lập. Chương này chỉ nêu đánh giá, chưa cho thấy hóa thân trực tiếp xuất chiến.","nguon":["@c0312"]},{"id":"ngu-khi-phi-hanh","name":"Ngự khí phi hành","cn":"","loai":"than-thong","loaiLabel":"Thần thông di chuyển","phamCap":"Không rõ","hePhai":"Tu tiên giới","soHuu":["Vũ Huyễn"],"blurb":"Thủ đoạn di chuyển bằng cách điều khiển pháp khí bay đi. Trong chương này Vũ Huyễn dùng cách này rời khỏi Tần phủ sau khi tuyên bố không tham gia hành động.","detail":"Vũ Huyễn rời khỏi phòng rồi trực tiếp ngự khí bay ra khỏi Tần phủ, thể hiện đây là phương thức di chuyển quen thuộc của tu sĩ Trúc Cơ khi cần rời địa điểm nhanh chóng.","nguon":["@c0314"]},{"id":"van-ti-thien-ha","name":"Vạn Ti thiên hạ","cn":"","loai":"than-thong","loaiLabel":"Thần thông/chiêu thức pháp khí","phamCap":"không rõ","hePhai":"Hoàng Phong Cốc","soHuu":["Tống Mông"],"blurb":"Chiêu thức Tống Mông thi triển phối hợp với Lam Ti kiếm. Kiếm quang màu lam bắn ra dày đặc, bao phủ phạm vi rộng và sát thương mạnh lên đám đệ tử Hắc Sát giáo.","detail":"Trong trận đánh Lãnh cung, Tống Mông dùng Lam Ti kiếm quay như bánh xe ánh sáng rồi phát ra vô số tia lam trong phạm vi hơn mười trượng. Chiêu này khiến phần lớn đệ tử Hắc Sát giáo bị xuyên thủng hoặc mất sức chiến đấu.","nguon":["@c0317"]},{"id":"thanh-moc-chan-trao","name":"Thanh Mộc chân tráo","cn":"","loai":"than-thong","loaiLabel":"Phòng hộ","phamCap":"Không rõ","hePhai":"Hắc Sát giáo","soHuu":["Thanh Văn đạo sĩ"],"blurb":"Hộ tráo phòng ngự của Thanh Văn đạo sĩ, tạo từ năm pháp khí màu xanh hình tròn xếp thành vòng ngũ giác quanh thân.","detail":"Thanh Văn dùng Thanh Mộc chân tráo khi bị Hàn Lập và Vương sư huynh giáp công trước Lãnh cung. Hộ tráo này chặn được kim xoa và kim nhận của Hàn Lập, khiến Thanh Văn tự tin nói rằng ngoài tu sĩ Kết Đan kỳ thì tu sĩ Trúc Cơ kỳ không thể gây tổn thương.","nguon":["@c0318"]},{"id":"cu-kiem-thuat","name":"Cự Kiếm thuật","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Chiêu thức trong Thanh Nguyên kiếm quyết","hePhai":"Hoàng Phong cốc","soHuu":["Hàn Lập"],"blurb":"Ngự kiếm thuật Hàn Lập có thể thi triển ở Trúc Cơ kỳ, hợp nhiều pháp khí thành một cự kiếm ba màu.","detail":"Trong trận với Thanh Văn đạo sĩ, Hàn Lập thu pháp khí lên không rồi thi triển Cự Kiếm thuật từ Thanh Nguyên kiếm quyết. Cự kiếm ba màu Kim, Hắc, Hồng phá Đồng thuẫn do Hoàng Đồng kính tạo thành và tiếp tục ép xuống Thanh Mộc chân tráo, buộc Thanh Văn phải dốc linh lực chống đỡ.","nguon":["@c0319"]},{"id":"thuat-an-than-cua-bang-yeu","name":"Thuật ẩn thân của Băng Yêu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Huyết thị bán yêu hóa","soHuu":["Băng Yêu"],"blurb":"Thần thông giúp Băng Yêu ẩn thân và thoắt ẩn thoắt hiện sau khi bán yêu hóa.","detail":"Băng Yêu dùng thuật này phối hợp tốc độ cao để giết Tuyết Hồng, áp chế cả nhóm tu sĩ Hoàng Phong Cốc và tập kích Vương sư huynh. Trong giao chiến với Hàn Lập, thuật ẩn thân bị nhìn thấu khiến Băng Yêu kinh hãi.","nguon":["@c0321"]},{"id":"yeu-hoa-bang-than","name":"Yêu hóa băng thân","cn":"","loai":"bi-thuat","loaiLabel":"Biến hóa","phamCap":"không rõ","hePhai":"Hắc Sát giáo","soHuu":["Băng Yêu"],"blurb":"Biến hóa của Băng Yêu khiến thân thể trở nên trong suốt và cứng rắn như băng.","detail":"Sau khi hóa thành thân thể băng hóa, Băng Yêu có băng trảo đủ cứng để chống đỡ ngân kiếm, nhưng cảm giác trở nên trì độn nên bị Hàn Lập lợi dụng ti tuyến quấn trúng lợi trảo.","nguon":["@c0323"]},{"id":"yeu-hoa-huyet-thi-mau-xanh-tham","name":"Yêu hóa Huyết thị màu xanh thẫm","cn":"","loai":"bi-thuat","loaiLabel":"Biến hóa","phamCap":"không rõ","hePhai":"Hắc Sát giáo","soHuu":["Thanh Văn đạo sĩ"],"blurb":"Trạng thái yêu hóa của Huyết thị Thanh Văn đạo sĩ sau khi phá khỏi quang kén máu.","detail":"Thanh Văn đạo sĩ chui ra khỏi quang kén trong dáng vẻ yêu vật, quanh thân có màn sáng xanh và thần trí mơ hồ điên cuồng; khi gặp Hỏa điểu Chân bảo thì lộ vẻ sợ hãi bỏ chạy.","nguon":["@c0323"]},{"id":"bien-than-pha-ken-cua-huyet-thi","name":"Biến thân phá kén của Huyết thị","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tà pháp Huyết thị","hePhai":"Hắc Sát giáo","soHuu":["Hai Huyết thị còn lại"],"blurb":"Thần thông biến thân của Huyết thị, tạo trạng thái phá kén sau khi thi triển. Trong chương này, hai Huyết thị vừa phá kén đã bị chân bảo hỏa điểu cuốn vào biển lửa.","detail":"Hai Huyết thị còn lại vừa biến thân, phá kén đi ra thì lập tức bị hỏa điểu đánh vào. Huyết quang của họ chỉ chống đỡ được trong chốc lát rồi tan rã, khiến hai bóng mơ hồ bị luyện hóa sạch.","nguon":["@c0324"]},{"id":"cong-phap-che-giau-tu-vi-phap-luc","name":"Công pháp che giấu tu vi/pháp lực","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Chưa rõ","hePhai":"Hoàng cung Việt quốc / phe Việt hoàng","soHuu":["Việt hoàng","Tiểu vương gia","Vương tổng quản"],"blurb":"Thủ đoạn giúp phe Việt hoàng che giấu pháp lực và tu vi trước sự dò xét của tu sĩ Hoàng Phong cốc.","detail":"Việt hoàng từng che giấu tu vi đến mức nhóm Hoàng Phong cốc không phát hiện. Hàn Lập liên tưởng đến Tiểu vương gia và Vương tổng quản khi mới gặp cũng không lộ chút pháp lực nào, cho thấy đây có thể là một thủ đoạn đồng hệ của phe hoàng cung.","nguon":["@c0325"]},{"id":"ta-cong-huyet-quang-hap-nap","name":"Tà công huyết quang hấp nạp","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Tà công / thần thông","phamCap":"Chưa rõ","hePhai":"Hoàng cung Việt quốc / phe Việt hoàng","soHuu":["Việt hoàng","Hắc Sát giáo chủ"],"blurb":"Tà công huyết quang cho phép Việt hoàng hấp nạp huyết quang và sinh cơ từ Lam bào nhân để trẻ lại và tăng cường sức mạnh.","detail":"Việt hoàng cắm tay vào ngực Lam bào nhân, nối huyết quang giữa hai bên rồi hấp nạp. Lam bào nhân teo rút, còn Việt hoàng trẻ lại và huyết quang trên người mạnh hơn, khiến cục diện trở nên quỷ dị và nguy hiểm hơn.","nguon":["@c0325"]},{"id":"hoa-he-phu-luc-phap-thuat","name":"Hỏa hệ phù lục pháp thuật","cn":"","aliases":[],"loai":"khac","loaiLabel":"Phù lục / pháp thuật","phamCap":"Cấp thấp","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Đợt pháp thuật Hỏa hệ do Hàn Lập kích phát từ hơn trăm phù lục để che mắt Việt hoàng.","detail":"Hàn Lập dùng hơn một hai trăm Hỏa hệ phù lục tạo hỏa xà, hỏa cầu che phủ Việt hoàng và Lam bào nhân. Mục đích chính của đợt công kích này là che giấu Thiên Lôi tử trong màn hỏa pháp quy mô lớn.","nguon":["@c0325"]},{"id":"ma-quang-ho-the","name":"Ma quang hộ thể","cn":"","loai":"than-thong","loaiLabel":"Thần thông hộ thể","phamCap":"Ma công","hePhai":"Hắc Sát giáo","soHuu":["Việt hoàng"],"blurb":"Lớp ma quang hộ thể của Việt Hoàng được Hàn Lập nhận định có khả năng ăn mòn pháp khí thông thường. Nó khiến các pháp khí của nhóm Tống Mông mất linh tính khi bị giữ trong huyết quang.","detail":"Trong trận với Hàn Lập và nhóm Tống Mông, lớp huyết quang quanh Việt Hoàng giữ lại kim thước, đôi quái nhận màu tím và trường kiếm màu xanh lam, làm chúng bất động như mất linh tính. Hàn Lập suy đoán ma quang hộ thể này chuyên khắc chế pháp khí phổ thông, chỉ một số pháp khí đặc biệt như Ô Long đoạt mới không sợ tà công ấy.","nguon":["@c0326"]},{"id":"huyet-linh-toan","name":"Huyết Linh Toản","cn":"","loai":"than-thong","loaiLabel":"Sát chiêu ma công","phamCap":"Ma công cao cấp","hePhai":"Hắc Sát giáo","soHuu":["Việt hoàng"],"blurb":"Sát chiêu do Việt Hoàng tích tụ và áp súc chân nguyên trong cơ thể trong thời gian dài. Một kích của nó xuyên thủng nhiều lớp phòng hộ và làm Hàn Lập trọng thương.","detail":"Huyết Linh Toản bắn ra thành hồng quang cực nhanh, xuyên thủng Bạch Lân thuẫn, Quy xác pháp khí rồi đánh tan Thanh Nguyên kiếm thuẫn của Hàn Lập. Chương cũng nêu việc luyện chiêu này đau đớn, lâu dài và số lượng còn lại trong người Việt Hoàng rất ít, khiến nó trở thành đòn sát thủ đáng sợ trong trận.","nguon":["@c0326"]},{"id":"thanh-nguyen-kiem-thuan","name":"Thanh Nguyên kiếm thuẫn","cn":"","loai":"than-thong","loaiLabel":"Phòng hộ pháp thuật","phamCap":"Không rõ","hePhai":"Thanh Nguyên kiếm quyết","soHuu":["Hàn Lập"],"blurb":"Lớp quang thuẫn màu xanh do Hàn Lập dùng để phòng hộ trong khoảnh khắc bị Huyết Linh Toản tập kích. Nó bị hồng quang đánh tan gần như ngay khi tiếp xúc.","detail":"Khi Huyết Linh Toản xuyên qua Bạch Lân thuẫn và Quy xác pháp khí, trên người Hàn Lập hiện ra Thanh Nguyên kiếm thuẫn để chống đỡ. Lớp phòng hộ này vẫn không chịu nổi sát chiêu của Việt Hoàng, khiến Hàn Lập bị khoan thủng vai phải.","nguon":["@c0326"]},{"id":"bi-phap-luyen-hoa-bang-huyet-quang","name":"Bí pháp luyện hóa bằng huyết quang","cn":"","loai":"bi-thuat","loaiLabel":"Bí pháp","phamCap":"Không rõ","hePhai":"Hắc Sát giáo","soHuu":["Việt hoàng"],"blurb":"Bí pháp Việt Hoàng định thúc giục sau khi dùng huyết quang bao phủ rừng trúc.","detail":"Khi truy sát nhóm Hàn Lập tới rừng trúc, Việt Hoàng dự định dựa vào huyết quang từ hộ thể ma quang để vây kín khu vực rồi dùng bí pháp luyện hóa toàn bộ người và trận pháp bên trong.","nguon":["@c0327"]},{"id":"chu-ngu-hoang-da-cua-viet-hoang","name":"Chú ngữ hoang dã của Việt Hoàng","cn":"","loai":"khac","loaiLabel":"Chú pháp","phamCap":"không rõ","hePhai":"Hắc Sát giáo","soHuu":["Việt Hoàng"],"blurb":"Chú pháp cổ xưa được Việt Hoàng niệm khi kích phát chuôi đao đen và tơ máu đen.","detail":"Việt Hoàng niệm chú khó hiểu, tiết tấu từ thong thả chuyển nhanh dần, làm hiện khí tức cổ xưa và thúc đẩy quá trình hình thành Hắc Huyết Đao từ chuôi đao đen.","nguon":["@c0328"]},{"id":"phap-thuat-cam-mau-cua-viet-hoang","name":"Pháp thuật cầm máu của Việt Hoàng","cn":"","loai":"khac","loaiLabel":"Pháp thuật","phamCap":"không rõ","hePhai":"Hắc Sát giáo","soHuu":["Việt Hoàng"],"blurb":"Pháp thuật khiến vết cắt ở hai cổ tay của Việt Hoàng cầm máu sau khi hắn dùng máu luyện đao.","detail":"Sau khi để máu dung nhập vào huyết quang, Việt Hoàng phun hai đạo hồng khí vào hai cổ tay, làm vết thương cầm máu, mờ dần rồi biến mất, đổi lại sắc mặt hắn trở nên tái nhợt.","nguon":["@c0328"]},{"id":"cam-doan-dai-tran","name":"Cấm đoạn đại trận","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Hoàng Phong Cốc","soHuu":["Hàn Lập"],"blurb":"Đại trận Hàn Lập dùng vây Việt hoàng, có cấm chế chuyển dời tức thời và phản xạ công kích.","detail":"Trận pháp thể hiện khả năng chuyển dời tức thời cả người trong trận lẫn địch nhân, khiến đòn chém trực diện rơi vào hư không. Công kích của địch bị nuốt mất, bị dịch chuyển hoặc bị bắn ngược, khiến Việt hoàng không thể tiếp cận Hàn Lập hay phá trận bằng đao mang. Đây là nền tảng giúp nhóm Hoàng Phong Cốc trói chân và diệt sát Việt hoàng.","congNang":["Chuyển dời tức thời người trong trận, khiến đòn chém trực diện rơi vào hư không (@c0329)","Nuốt, dịch chuyển hoặc bắn ngược công kích của địch (@c0329)"],"nguon":["@c0329"]},{"id":"hac-sat-tu-la-cong","name":"Hắc Sát Tu La công","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Hắc Sát giáo","soHuu":["Tiểu vương gia"],"blurb":"Công pháp của Hắc Sát giáo được ghi trong ngọc giản, chính là pháp môn Tiểu vương tử tu luyện.","detail":"Một trong các công pháp giáo chúng Hắc Sát giáo được ghi lại trong ngọc giản màu trắng xám. Ngọc giản cho biết Tiểu vương tử tu luyện chính là Hắc Sát Tu La công, cùng hệ với các công pháp tốc thành dựa vào Huyết tế của giáo phái.","nguon":["@c0330"]},{"id":"sat-yeu-quyet","name":"Sát Yêu quyết","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Hắc Sát giáo","soHuu":["Tứ đại huyết thị"],"blurb":"Công pháp của tứ đại huyết thị, dùng Huyết tế để tu nhanh và ngưng luyện nội đan giống yêu thú, nhưng không thể Kết đan thật.","detail":"Công pháp Hắc Sát giáo mà tứ đại huyết thị tu luyện. Người tu có thể trong cơ thể ngưng luyện ra một thứ giống nội đan yêu thú, nhờ đó biến thân thành sát yêu và tiến vào Trúc Cơ kỳ mà không cần phục dụng Trúc Cơ đan. Điểm ngưng luyện đó chính là Huyết ngưng ngũ hành đan. Tuy nhiên công pháp mang khuyết hãm trí mạng: tối cao chỉ đạt tới Trúc Cơ kỳ, không thể Kết đan thật.","congNang":["Dùng Huyết tế để tu luyện tốc thành (@c0330)","Ngưng luyện nội đan trong cơ thể, tạo ra Huyết ngưng ngũ hành đan (@c0330)","Giúp biến thân thành sát yêu và vào Trúc Cơ kỳ không cần Trúc Cơ đan (@c0330)"],"dacDiem":"Khuyết hãm trí mạng: chỉ đến Trúc Cơ kỳ, không thể Kết đan thật.","tabs":{"tienTrinh":[{"chuong":"@c0330","loai":"hé lộ tầng-chiêu","importance":"major","text":"Ngọc giản Hắc Sát giáo hé lộ Sát Yêu quyết là nguồn gốc khiến tứ đại huyết thị biến thân sát yêu và vào Trúc Cơ kỳ nhờ nội đan tự luyện.","anchor":"Mà Tứ đại huyết thị sở dĩ có thể biến thân thành sát yêu và cũng không cần phục dụng Trúc Cơ Đan có thể tiến vào Trúc Cơ kỳ, cũng là bởi vì duyên cớ kết thành nội đan này."}]},"nguon":["@c0330"]},{"id":"huyet-luyen-than-quang","name":"Huyết Luyện thần quang","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Hắc Sát giáo","soHuu":["Việt hoàng"],"blurb":"Công pháp Hắc Sát giáo mà Việt hoàng tu luyện, được ngọc giản ghi cùng hệ với các công pháp giáo phái.","detail":"Một công pháp trong ngọc giản Hắc Sát giáo. Ngọc giản chỉ rõ Việt hoàng tu luyện chính là Huyết Luyện thần quang, cùng hệ với Hắc Sát Tu La công và Sát Yêu quyết.","nguon":["@c0330"]},{"id":"huyen-am-kinh","name":"Huyền Âm Kinh","loai":"cong-phap","loaiLabel":"Kinh thư / Công pháp","phamCap":"Không rõ","hePhai":"Hắc Sát giáo","soHuu":[],"blurb":"Quyển kinh được các công pháp Hắc Sát giáo trong ngọc giản nhiều lần nhắc tới, nhưng không ghi nơi hạ lạc.","detail":"Trong ngọc giản, nhiều công pháp Hắc Sát giáo đều nhắc đến Huyền Âm Kinh, khiến Hàn Lập tò mò. Tuy vậy ngọc giản không hề ghi nơi hạ lạc của quyển kinh này, để lại một đầu mối công pháp Ma đạo còn bỏ ngỏ.","nguon":["@c0330"]},{"id":"sat-dan-thuat","name":"Sát Đan thuật","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Hắc Sát giáo","soHuu":[],"blurb":"Bí thuật cho tu sĩ Trúc Cơ hậu kỳ ăn Huyết ngưng ngũ hành đan để có một phần ba cơ hội kết thành Ngụy kim đan, đổi lại bị ăn mòn thần trí.","detail":"Bí thuật ghi trong ngọc giản Hắc Sát giáo. Tu sĩ Trúc Cơ hậu kỳ ăn Huyết ngưng ngũ hành đan sẽ có một phần ba cơ hội kết thành Ngụy kim đan (Sát Đan), uy lực gần với kim đan thật và tăng tuổi thọ. Cái giá là Sát Đan không thể tăng tiến, chỉ duy trì Kết Đan sơ kỳ, đồng thời phóng thích sát yêu chi khí ăn mòn thần trí khiến đầu óc trì độn dần ngu dốt. Vì hậu hoạn này mà Hàn Lập từ bỏ ý định tự dùng.","congNang":["Cho tu sĩ Trúc Cơ hậu kỳ một phần ba cơ hội kết thành Ngụy kim đan khi ăn Huyết ngưng ngũ hành đan (@c0330)"],"dacDiem":"Sát Đan tạo ra không thể tăng tiến và dần ăn mòn thần trí người dùng.","nguon":["@c0330"]},{"id":"than-ngoai-hoa-than","name":"Thân ngoại hóa thân","loai":"bi-thuat","loaiLabel":"Bí pháp","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":[],"blurb":"Bí pháp Ma đạo nổi danh được xem là bí mật tối cao; Hàn Lập tìm thấy trong ngọc giản và nhận ra đây là hướng dùng Huyết ngưng ngũ hành đan.","detail":"Bí pháp hóa thân trứ danh của Ma đạo, các tông phái coi là bí mật tối cao. Hàn Lập tìm thấy trong ngọc giản Hắc Sát giáo, mừng rỡ vì rốt cục tìm được chỗ sử dụng Huyết ngưng ngũ hành đan. Hắn cũng suy đoán Việt hoàng vốn định dùng đan cho pháp môn này, và Lam bào nhân từng chết dưới Thiên Lôi tử chính là hóa thân Việt hoàng tế luyện.","congNang":["Cho phép tế luyện hóa thân bên ngoài thân thể, dùng Huyết ngưng ngũ hành đan làm vật liệu (@c0330)"],"nguon":["@c0330"]},{"id":"khinh-cong","name":"Khinh công","cn":"","loai":"khac","loaiLabel":"Võ công giang hồ","phamCap":"Võ công thế tục","hePhai":"","soHuu":["Vị khách quý của nhóm Hạ thiếu gia"],"blurb":"Võ công giang hồ giúp người thi triển bước đi rất nhẹ, gần như không phát ra tiếng. Hàn Lập nhận ra dấu hiệu này khi đoàn khách mới lên lầu tại Hương gia tửu lâu.","detail":"Trong tiếng bước chân nặng nề của đoàn người lên lầu, Hàn Lập nghe rõ có một người bước rất nhẹ, phảng phất như không có. Hắn phán đoán đây là biểu hiện của người trong giang hồ có khinh công đạt đến một thành tựu nhất định.","dinhDanh":"goc","thuocTinh":"Thân pháp thế tục","congNang":["Giúp bước đi rất nhẹ, gần như không tiếng khi di chuyển @c0332"],"uyLuc":"Đủ khiến Hàn Lập chú ý giữa tiếng bước chân hỗn tạp trong tửu lâu.","dacDiem":"Không phải pháp thuật tu tiên, mà là võ công giang hồ thể hiện qua tiếng bước chân nhẹ.","nguoiTu":[{"ten":"Vị khách quý của nhóm Hạ thiếu gia","tuChuong":"@c0332","tangDatToi":"Có thành tựu nhất định","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0332","loai":"xuất hiện","importance":"normal","giaiDoan":"Dấu hiệu qua bước chân","text":"Hàn Lập nghe thấy trong đoàn khách lên lầu có một người bước rất nhẹ và nhận ra đó là dấu hiệu khinh công có thành tựu.","anchor":"Đây rõ ràng là người trong giang hồ có khinh công đạt đến một thành tựu nhất định"}]},"trangThai":"đang lưu truyền trong giang hồ","capNhatToi":"@c0332","nguon":["@c0332"]},{"id":"chan-linh-quyet","name":"Chân Linh quyết","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Pháp quyết","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Pháp quyết được Hàn Lập dùng để khiến độc tố trong cơ thể Tôn Nhị Cẩu hiện ra ngoài.","detail":"Hàn Lập phất tay đánh một đạo thanh quang vào cơ thể Tôn Nhị Cẩu rồi nói đây là Chân Linh quyết, có thể làm độc tố trong cơ thể biểu hiện ra ngoài để người trúng độc tự nhìn thấy dấu hiệu.","thuocTinh":"Thanh quang","uyLuc":"Có thể làm độc tố trong cơ thể người bị trúng độc biểu hiện ra ngoài.","dacDiem":"Được thi triển nhanh chóng bằng một đạo thanh quang.","congNang":["Làm độc tố trong cơ thể biểu hiện ra ngoài @c0334"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0334","tangDatToi":"Có thể thi triển","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0334","loai":"thi triển","importance":"normal","giaiDoan":"Hiển độc","text":"Hàn Lập dùng Chân Linh quyết khiến độc tố trong người Tôn Nhị Cẩu hiện ra ngoài.","anchor":"Đây là Chân Linh quyết, có thể làm cho độc tố trong cơ thể ngươi biểu hiện ra ngoài"}]},"capNhatToi":"@c0334","nguon":["@c0334"]},{"id":"cam-che-tren-khuc-hon","name":"Cấm chế trên Khúc Hồn","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Cấm chế khống chế","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Cấm chế từng được Hàn Lập hạ lên Khúc Hồn, vẫn còn tác dụng dù Khúc Hồn đã mất kiểm soát.","detail":"Hàn Lập suy đoán cấm chế cũ vẫn có tác dụng vì Khúc Hồn luôn tránh Tôn Nhị Cẩu khi người này mang Dẫn Hồn chung tới gần, trong khi người khác đến lại bị Khúc Hồn chống trả.","uyLuc":"Vẫn tạo ảnh hưởng khiến Khúc Hồn tránh người mang Dẫn Hồn chung.","dacDiem":"Liên hệ với Dẫn Hồn chung trong việc ảnh hưởng Khúc Hồn.","congNang":["Liên hệ với Dẫn Hồn chung để ảnh hưởng hoặc khống chế Khúc Hồn @c0334"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0334","tangDatToi":"Đã hạ cấm chế từ trước","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0334","loai":"nhắc tới","importance":"normal","giaiDoan":"Còn hiệu lực","text":"Hàn Lập nhận định cấm chế từng hạ lên Khúc Hồn vẫn còn tác dụng.","anchor":"nhưng rất hiển nhiên cấm chế ta hạ lúc trước vẫn có tác dụng"}]},"capNhatToi":"@c0334","nguon":["@c0334"]},{"id":"thuat-bang-truy","name":"Thuật băng trùy","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Pháp thuật băng hệ","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Thuật băng trùy là pháp thuật băng hệ Hàn Lập dùng khi đột nhập Lý phủ. Băng trùy trong suốt có thể xuyên tim mục tiêu và để lại băng sương trên thi thể.","detail":"Hàn Lập vung tay tạo băng trùy trong suốt, giết bốn thị vệ áo trắng canh cửa thiên viện không tiếng động. Sau khi trúng thuật, tim mỗi người đều cắm một cây băng trùy, thi thể còn phủ một tầng băng sương trắng.","congNang":["Tạo băng trùy trong suốt cắm vào tim mục tiêu, giết người không tiếng động @c0335"],"uyLuc":"Giết bốn hảo thủ võ công phàm tục trong khoảnh khắc mà không gây tiếng động.","dacDiem":"Băng trùy trong suốt, sau khi trúng đòn thi thể còn phủ băng sương trắng.","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0335","tangDatToi":"thi triển thực chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0335","loai":"thi triển","importance":"normal","giaiDoan":"Đột nhập Lý phủ","text":"Hàn Lập dùng băng trùy xuyên tim bốn thị vệ áo trắng trước thiên viện.","anchor":"trái tim của mỗi người đều cắm một cây băng trùy trong suốt, trên thi thể còn được bao bởi một tầng băng sương màu trắng"}]},"capNhatToi":"@c0335","nguon":["@c0335"]},{"id":"hoa-cau","name":"Hỏa cầu","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Hỏa cầu là pháp thuật Hàn Lập dùng để uy hiếp phụ tử Ngũ Sắc môn. Chỉ vài viên hỏa cầu đã khiến đối phương nhận ra hắn là tu tiên giả.","detail":"Hàn Lập giơ tay tạo ra vài viên hỏa cầu cỡ nắm tay, mang theo nhiệt khí, sau đó hỏa cầu còn phình lớn khi Mặc Ngọc Châu chắn trước mặt. Pháp thuật này được dùng chủ yếu để áp chế và đe dọa trong cuộc đối chất tại phủ Ngũ Sắc môn.","thuocTinh":"hỏa","uyLuc":"Đủ khiến phụ tử Ngũ Sắc môn kinh hãi và không dám tiếp tục đối kháng.","dacDiem":"Có thể hiện ra nhanh trong tay, tỏa nhiệt khí rõ rệt.","congNang":["Công kích hoặc đe dọa bằng nhiệt hỏa @c0336"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0336","tangDatToi":"thi triển hỏa cầu cỡ nắm tay","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0336","loai":"thi triển","importance":"normal","giaiDoan":"Uy hiếp phụ tử Ngũ Sắc môn","text":"Hàn Lập thi triển vài viên hỏa cầu để áp chế phụ tử Ngũ Sắc môn, khiến họ nhận ra hắn là tu tiên giả.","anchor":"vài viên hỏa cầu to bằng nắm tay, mang theo một cỗ nhiệt khí"}]},"dinhDanh":"goc","capNhatToi":"@c0336","nguon":["@c0336"]},{"id":"hon-khi","name":"Hồn khí","cn":"","aliases":[],"loai":"khac","loaiLabel":"Pháp khí phụ trợ thuật pháp","phamCap":"Không rõ","hePhai":"Liên quan Luyện Hồn thuật","soHuu":[],"blurb":"Loại khí vật được đồn là cần thiết cho người tu Luyện Hồn thuật, có liên hệ mật thiết với nguyên thần.","detail":"Theo hiểu biết của Khúc Hồn, người tu Luyện Hồn thuật nhất định sẽ luyện một Hồn khí tương liên chặt chẽ với nguyên thần để thi triển thuật. Vì Tụ Hồn Bát tỏa khí tức âm trầm và tác động nguyên thần, hắn nhầm vật này là Hồn khí của Hàn Lập.","thuocTinh":"Liên hệ nguyên thần","dacDiem":"Được mô tả qua lời đồn, chưa xác định là một pháp khí cụ thể trong tay Hàn Lập.","congNang":["Hỗ trợ người tu Luyện Hồn thuật thi triển thủ đoạn liên quan hồn phách @c0338"],"tabs":{"tienTrinh":[{"chuong":"@c0338","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc trong hiểu lầm của Khúc Hồn","text":"Khúc Hồn nhầm Tụ Hồn Bát là Hồn khí dùng cho Luyện Hồn thuật.","anchor":"nhất định sẽ tu luyện một cái gọi là “Hồn khí” tương liên rất mật thiết với nguyên thần của mình"}]},"capNhatToi":"@c0338","dinhDanh":"goc","nguon":["@c0338"]},{"id":"bi-phap-kich-phat-tu-vi-gia-ket-dan","name":"Bí pháp kích phát tu vi giả Kết Đan","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Chưa rõ","hePhai":"Ma đạo lục tông","soHuu":["Ma đạo lục tông","Tu sĩ Trúc Cơ kỳ giả Kết Đan"],"blurb":"Bí pháp được Khúc Hồn nói là có thể tạm kích phát tu vi Trúc Cơ lên ngang Kết Đan. Cái giá là người thi triển gần như chắc chắn chết vì kinh mạch đứt đoạn.","detail":"Khúc Hồn dùng bí pháp này để giải thích khả năng Ma đạo dàn dựng cái chết của tu sĩ Kết Đan trong trận tập kích, qua đó che giấu vai trò Linh Thú sơn. Bí pháp chỉ là thủ đoạn cưỡng ép tạm thời, không phải đột phá cảnh giới thật.","thuocTinh":"Kích phát tu vi cưỡng ép","yeuCau":"Tu sĩ Trúc Cơ kỳ","uyLuc":"Tạm khiến tu sĩ Trúc Cơ có tu vi ngang Kết Đan kỳ.","dacDiem":"Thi triển một lần thì kinh mạch đứt đoạn mà chết.","congNang":["Tạm nâng tu vi Trúc Cơ kỳ lên ngang Kết Đan kỳ @c0340"],"nguon":["@c0340"],"tabs":{"tienTrinh":[{"chuong":"@c0340","loai":"xuất hiện","importance":"normal","giaiDoan":"Khúc Hồn giải thích kế giả chết","text":"Khúc Hồn nói Ma đạo lục tông có bí pháp tạm kích phát tu vi Trúc Cơ lên ngang Kết Đan, dùng để lừa sáu phái về cái chết của tu sĩ Kết Đan.","anchor":"bí pháp có thể kích phát tu vi của tu sĩ Trúc Cơ kỳ lên ngang với Kết Đan kỳ"}]},"capNhatToi":"@c0340","dinhDanh":"goc"},{"id":"doat-xa-nguyen-than-xuat-khieu","name":"Đoạt xá / nguyên thần xuất khiếu","cn":"","aliases":["nguyên thần xuất khiếu"],"loai":"bi-thuat","loaiLabel":"Thủ đoạn nguyên thần","phamCap":"Chưa rõ","hePhai":"Tu tiên giới","soHuu":["Tu sĩ Ngự Linh Tông"],"blurb":"Thủ đoạn để nguyên thần rời thân rồi tìm thân xác khác chiếm cứ. Tu sĩ Ngự Linh Tông từng dùng cách này sau khi thân thể trọng thương ở Gia Nguyên thành.","detail":"Khi không tìm được tu sĩ thích hợp để đoạt xá, nguyên thần của tu sĩ Ngự Linh Tông thử nhập vào thân cương thi Khúc Hồn vốn không có nguyên thần. Việc này giúp hắn tồn tại trong một thân xác khác nhưng vẫn để lại nhiều nghi điểm.","thuocTinh":"Nguyên thần","uyLuc":"Cho phép nguyên thần rời thân để tìm thân xác khác.","dacDiem":"Có thể thất bại nếu không tìm được thân xác phù hợp; trường hợp nhập vào cương thi vô nguyên thần được nhắc như một lần liều lĩnh.","congNang":["Nguyên thần rời khỏi thân thể cũ để tìm đối tượng đoạt xá @c0340"],"nguon":["@c0340"],"tabs":{"tienTrinh":[{"chuong":"@c0340","loai":"nhắc tới","importance":"normal","giaiDoan":"Tu sĩ Ngự Linh Tông kể lại","text":"Tu sĩ Ngự Linh Tông nói khi thân thể trọng thương, hắn để nguyên thần xuất khiếu rồi tìm tu sĩ để đoạt xá.","anchor":"đành phải vội vàng để nguyên thần xuất khiếu, sau đó tìm kiếm chung quanh xem có tu sĩ nào có thể đoạt xá"}]},"capNhatToi":"@c0340","dinhDanh":"goc"},{"id":"luc-quang-tu-mieng-khuc-hon","name":"Lục quang từ miệng “Khúc Hồn”","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Chưa rõ","soHuu":["Khúc Hồn / tu sĩ Ngự Linh Tông chiếm cứ thi thể Khúc Hồn"],"blurb":"Thủ đoạn “Khúc Hồn” thi triển trong lúc nguy cấp, hé miệng bắn ra một đạo lục quang để chống đỡ công kích.","detail":"Khi Hàn Lập thúc Ô Long đoạt đánh toàn lực, “Khúc Hồn” trong tình thế nguy cấp há miệng phóng ra một đạo lục quang. Đạo lục quang này đủ để ngăn lại một kích toàn lực của Ô Long đoạt, cho thấy kẻ chiếm thân Khúc Hồn vẫn còn thủ đoạn phòng ngự hoặc phản kích ngoài dự tính của Hàn Lập.","nguon":["@c0342"]},{"id":"khong-than-cam-che","name":"Khống Thần cấm chế","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Cấm chế khống chế linh thú","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Khống Thần cấm chế là cấm chế Hàn Lập từng dùng tinh huyết hạ lên hai Bạch Tri chu. Khi trứng nở, hai nhện non thân cận hắn như cha mẹ, cho thấy cấm chế đã phát huy tác dụng.","detail":"Cấm chế này được dùng để khống chế hoặc khiến linh thú nhận chủ. Ở chương này, hiệu quả thể hiện rõ qua việc hai Bạch Tri chu non vừa nở đã lập tức thân cận Hàn Lập.","dinhDanh":"goc","thuocTinh":"Cấm chế tinh huyết","uyLuc":"Khiến Bạch Tri chu non thân cận Hàn Lập như cha mẹ.","dacDiem":"Tác dụng bộc lộ sau khi trứng Bạch Tri chu nở thành công.","congNang":["Khiến Bạch Tri chu nhận chủ và thân cận người hạ cấm chế @c0345"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0345","tangDatToi":"Đã thi triển lên Bạch Tri chu","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0345","loai":"xuất hiện","importance":"normal","giaiDoan":"Hiệu quả bộc lộ","text":"Khống Thần cấm chế do Hàn Lập hạ bằng tinh huyết phát huy tác dụng khi hai Bạch Tri chu nở và thân cận hắn.","anchor":"lúc trước dùng tinh huyết hạ Khống Thần cấm chế thật đúng là đã có tác dụng"}]},"capNhatToi":"@c0345","nguon":["@c0345"]},{"id":"cong-phap-tu-luyen-nguyen-than-cua-han-lap","name":"Công pháp tu luyện nguyên thần của Hàn Lập","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"chưa rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Công pháp Hàn Lập đang tu luyện có liên quan đến nguyên thần. Lệnh Hồ lão tổ chỉ nhìn qua đã nhận ra nguyên thần của hắn được rèn luyện không tồi.","detail":"Trong Nghị Sự điện, Lệnh Hồ lão tổ nhận ra nguyên thần Hàn Lập có dấu vết tu luyện đặc biệt và hỏi có phải được rèn luyện theo công pháp tu luyện nguyên thần hay không. Hàn Lập cung kính xác nhận công pháp mình đang tu luyện quả thật có quan hệ đến nguyên thần.","thuocTinh":"nguyên thần","congNang":["Rèn luyện nguyên thần của người tu luyện @c0346"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0346","tangDatToi":"chưa rõ","trangThai":"đang tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c0346","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị Lệnh Hồ lão tổ nhận ra","text":"Lệnh Hồ lão tổ nhìn ra nguyên thần Hàn Lập được rèn luyện nhờ công pháp liên quan nguyên thần, Hàn Lập cũng thừa nhận điều này.","anchor":"Công pháp tại hạ đang tu luyện quả thật có quan hệ đến nguyên thần"}]},"capNhatToi":"@c0346","nguon":["@c0346"]},{"id":"dai-tran-tien-tuyen-that-phai","name":"Đại trận tiền tuyến Thất phái","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"chưa rõ","hePhai":"Thất phái","soHuu":["Thất phái"],"blurb":"Đại trận phòng tuyến của Thất phái ở tiền phương. Linh Thú Sơn lợi dụng phiên cảnh giới để tự mở đại trận cho người Ma đạo tiến vào, khiến liên quân đại bại.","detail":"Theo lời Lệnh Hồ lão tổ, thất bại của liên quân Thất phái không chỉ vì chủ quan mà còn vì Linh Thú Sơn phản bội. Thế lực này nhân lúc đến lượt cảnh giới đã tự mở đại trận cho người Ma đạo tiến vào, trực tiếp dẫn đến đại bại tiền tuyến.","congNang":["Dùng để phòng giữ tiền tuyến của Thất phái @c0346"],"trangThai":"bị Linh Thú Sơn mở cho Ma đạo tiến vào","tabs":{"tienTrinh":[{"chuong":"@c0346","loai":"xuất hiện","importance":"major","giaiDoan":"Bị phản đồ mở cửa","text":"Linh Thú Sơn lợi dụng lượt cảnh giới để tự mở đại trận tiền tuyến Thất phái, tạo điều kiện cho người Ma đạo tiến vào và khiến liên quân đại bại.","anchor":"Bọn Linh Thú Sơn thừa dịp đến phiên cảnh giới liền tự mình mở đại trận cho người Ma đạo tiến vào."}]},"capNhatToi":"@c0346","nguon":["@c0346"]},{"id":"thien-hoa-thuat","name":"Thiên Hỏa thuật","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"Cao cấp trung giai","hePhai":"Ma đạo lục tông","soHuu":["Ma đạo lục tông"],"blurb":"Pháp thuật cao cấp trung giai tạo mây đỏ như dung nham trên trời và trút xuống các giọt dung nham tấn công diện rộng. Hoàng sư thúc nhận ra mỗi giọt dung nham có uy lực như một kích của tu sĩ Trúc Cơ kỳ.","detail":"Thiên Hỏa thuật được dùng trong cuộc phản phục kích đội Hoàng Phong Cốc. Pháp thuật bao phủ bầu trời bằng ráng đỏ như dung nham, buộc đội Hoàng Phong Cốc phải hợp lực dựng vòng bảo hộ màu lam chống đỡ cho tới khi pháp thuật kết thúc.","thuocTinh":"Hỏa","uyLuc":"Mỗi giọt dung nham rơi xuống như một kích của tu sĩ Trúc Cơ kỳ.","dacDiem":"Tấn công diện rộng từ trên không, gây tiêu hao linh lực lớn cho nhóm bị bao phủ.","congNang":["Tạo vùng mây đỏ như dung nham trên trời để đánh xuống diện rộng @c0348","Mỗi giọt dung nham có uy lực tương đương một kích của tu sĩ Trúc Cơ kỳ @c0348"],"nguoiTu":[{"ten":"Ma đạo lục tông","tuChuong":"@c0348","tangDatToi":"Thi triển trên chiến trường","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0348","loai":"thi triển","importance":"normal","giaiDoan":"Phản phục kích đội Hoàng Phong Cốc","text":"Thiên Hỏa thuật phủ mây đỏ như dung nham lên bầu trời và buộc đội Hoàng Phong Cốc hợp lực phòng hộ.","anchor":"Mỗi giọt dung nham kia rơi xuống như một kích của tu sĩ Trúc Cơ kỳ"}]},"capNhatToi":"@c0348","nguon":["@c0348"]},{"id":"tran-phap-phong-ho-noi-o-te-van-tieu","name":"Trận pháp phòng hộ nơi ở Tề Vân Tiêu","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Tề Vân Tiêu"],"blurb":"Trận pháp bảo vệ chỗ ở của Tề Vân Tiêu tại vùng núi phía tây Kim Mã Thành. Khi Hàn Lập tới nơi, trận đã bị địch nhân mạnh mẽ phá hỏng.","detail":"Trận pháp phòng hộ bao quanh nơi ở của Tề Vân Tiêu, gồm khu thạch ốc và nhà trúc trong thung lũng. Việc trận bị phá cho thấy chỗ ở này đã từng bị tập kích bởi đối thủ có thực lực đủ mạnh.","trangThai":"bị phá","dinhDanh":"goc","capNhatToi":"@c0349","tabs":{"tienTrinh":[{"chuong":"@c0349","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị phá hủy","text":"Hàn Lập phát hiện trận pháp phòng hộ nơi ở của Tề Vân Tiêu đã bị địch nhân mạnh mẽ phá hỏng.","anchor":"Trận pháp phòng hộ nơi này đã bị địch nhân mạnh mẽ phá hỏng đi"}]},"nguon":["@c0349"]},{"id":"truyen-tong-tran-o-nguyen-vu-quoc","name":"Truyền tống trận ở Nguyên Vũ Quốc","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Truyền tống trận tại Nguyên Vũ Quốc được Hàn Lập nhắm tới như đường lui khỏi chiến tranh. Hắn dự định kiểm tra xem trận còn khả năng sửa chữa và sử dụng hay không.","detail":"Sau khi rời khỏi vòng vây Ma đạo, Hàn Lập quyết định không quay về điểm tập hợp Hoàng Phong Cốc mà sang Nguyên Vũ Quốc. Mục tiêu của hắn là xem Truyền tống trận tại đây có thể chữa trị không, nếu tình hình không xấu sẽ dùng nó rời khỏi khu vực tranh đấu giữa Ma đạo và Minh đạo.","trangThai":"cần kiểm tra sửa chữa","dinhDanh":"goc","congNang":["Dịch chuyển người dùng tới địa phương khác nếu còn có thể sửa chữa và vận hành @c0349"],"capNhatToi":"@c0349","tabs":{"tienTrinh":[{"chuong":"@c0349","loai":"nhắc tới","importance":"normal","giaiDoan":"Được chọn làm đường lui","text":"Hàn Lập định tới Nguyên Vũ Quốc kiểm tra khả năng sửa chữa Truyền tống trận và dùng nó rời khỏi khu vực chiến tranh nếu tình hình thuận lợi.","anchor":"trước tiên hắn muốn đến Nguyên Vũ quốc xem thử cái Truyền tống trận kia có hay không có khả năng chữa trị"}]},"nguon":["@c0349"]},{"id":"tran-suong-mu-noi-o-tan-nhu-am","name":"Trận sương mù nơi ở Tân Như Âm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Tân Như Âm"],"blurb":"Trận pháp sương mù bao phủ tiểu sơn vô danh nơi Tân Như Âm ẩn cư. Khi nhận Truyền Âm phù, trận biến cảnh vật thành rừng đại thụ ảo hóa rồi mở thông đạo dẫn vào trong.","detail":"Trận sương mù che giấu nơi ở của Tân Như Âm, có khả năng tạo ảo cảnh quanh người tiến vào và mở đường khi được người bên trong cho phép.","thuocTinh":"sương mù, ảo hóa, dẫn lối","uyLuc":"Có thể biến cảnh quanh Hàn Lập thành rừng đại thụ ảo hóa trước khi mở thông đạo.","dacDiem":"Vừa che giấu chỗ ở vừa kiểm soát người được phép đi vào.","congNang":["Che giấu tiểu sơn vô danh nơi Tân Như Âm ở @c0350","Tạo ảo cảnh rừng đại thụ và mở thông đạo trong sương mù @c0350"],"nguoiTu":[{"ten":"Tân Như Âm","tuChuong":"@c0350","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0350","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở đường cho Hàn Lập","text":"Sau khi nhận Truyền Âm phù, trận sương mù biến cảnh quanh Hàn Lập thành rừng đại thụ ảo hóa rồi mở một thông đạo dẫn vào nơi ở Tân Như Âm.","anchor":"đại thụ ở bốn phía liền như ảo ảnh, biến trở thành lại đám sương mù"}]},"dinhDanh":"goc","capNhatToi":"@c0350","nguon":["@c0350"]},{"id":"dai-tran-ben-ngoai-cho-o-te-van-tieu","name":"Đại trận bên ngoài chỗ ở Tề Vân Tiêu","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Tề Vân Tiêu"],"blurb":"Đại trận phòng hộ bên ngoài chỗ ở Tề Vân Tiêu, từng ngăn Phó gia truy sát.","detail":"Khi Phó gia truy tới chỗ ở của Tề Vân Tiêu, đại trận này liên tiếp sát thương hơn mười tu sĩ trước khi Phó gia mời cao thủ Kết Đan kỳ tới phá sau nửa ngày công kích.","uyLuc":"Sát thương hơn mười tu sĩ Phó gia trước khi bị cao thủ Kết Đan kỳ phá.","congNang":["Phòng hộ và sát thương kẻ xâm nhập truy tới chỗ ở Tề Vân Tiêu @c0351"],"dinhDanh":"goc","capNhatToi":"@c0351","tabs":{"tienTrinh":[{"chuong":"@c0351","loai":"thi triển","importance":"normal","giaiDoan":"chống Phó gia truy sát","text":"Đại trận bên ngoài chỗ ở Tề Vân Tiêu liên tiếp sát thương hơn mười tu sĩ Phó gia trước khi bị cao thủ Kết Đan kỳ phá.","anchor":"tu sĩ Phó gia không lâu sau liền truy tìm được chỗ ở của hắn nhưng bị đại trận bên ngoài liên tiếp sát thương hơn mười vị"}]},"nguon":["@c0351"]},{"id":"huyen-tran-phia-sau-dai-tran","name":"Huyễn trận phía sau đại trận","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Tề Vân Tiêu"],"blurb":"Huyễn trận do Tề Vân Tiêu vội bày phía sau đại trận để thoát khỏi Phó gia.","detail":"Trong lúc bị truy sát, Tề Vân Tiêu vội vàng bày huyễn trận lợi hại phía sau đại trận, xuất kỳ bất ý tạm thời vây khốn cao thủ Kết Đan kỳ của Phó gia.","uyLuc":"Tạm thời vây khốn được tu sĩ Kết Đan kỳ của Phó gia.","congNang":["Dùng huyễn trận xuất kỳ bất ý để giữ chân cao thủ Kết Đan kỳ @c0351"],"dinhDanh":"goc","capNhatToi":"@c0351","tabs":{"tienTrinh":[{"chuong":"@c0351","loai":"thi triển","importance":"normal","giaiDoan":"giữ chân Kết Đan kỳ","text":"Tề Vân Tiêu dùng huyễn trận phía sau đại trận để tạm vây cao thủ Kết Đan kỳ của Phó gia, tạo cơ hội đào thoát.","anchor":"vội vàng bày ra một huyễn trận lợi hai phía sau đại trận, xuất kỳ bất ý tạm thời vây khốn vị tu sĩ Kết Đan kỳ này"}]},"nguon":["@c0351"]},{"id":"tam-huyet-tran-phap-cua-tan-nhu-am","name":"Tâm huyết trận pháp của Tân Như Âm","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Truyền thừa trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Tân Như Âm","Hàn Lập"],"blurb":"Truyền thừa trận pháp do Tân Như Âm tích lũy, được đặt trong hộp ngọc giao cho Hàn Lập.","detail":"Tân Như Âm đem toàn bộ tâm huyết về phương diện trận pháp cùng phần lớn sách liên quan đặt trong một hộp ngọc, trao cho Hàn Lập để đổi lấy lời hứa báo thù Phó gia.","nguonGoc":"Do Tân Như Âm tích lũy và biên soạn.","dacDiem":"Bao gồm toàn bộ tâm huyết trận pháp cá nhân cùng phần lớn sách liên quan.","nguoiTu":[{"ten":"Tân Như Âm","tuChuong":"@c0351","tangDatToi":"không rõ","trangThai":"nắm giữ"},{"ten":"Hàn Lập","tuChuong":"@c0351","tangDatToi":"chưa rõ","trangThai":"được giao truyền thừa"}],"dinhDanh":"goc","capNhatToi":"@c0351","tabs":{"tienTrinh":[{"chuong":"@c0351","loai":"xuất hiện","importance":"normal","giaiDoan":"chuyển giao truyền thừa","text":"Tân Như Âm giao toàn bộ tâm huyết trận pháp và phần lớn sách liên quan cho Hàn Lập trong một hộp ngọc.","anchor":"cái còn lại là tất cả tâm huyết của ta về phương diện trận pháp cùng phần lớn sách liên quan"}]},"nguon":["@c0351"]},{"id":"long-ngam-chi-chat","name":"Long ngâm chi chất","cn":"","loai":"khac","loaiLabel":"Thể chất tu chân đặc thù","phamCap":"Không rõ","hePhai":"","soHuu":["Tân Như Âm"],"blurb":"Long ngâm chi chất là thể chất đặc thù vốn thuộc nam giới nhưng xuất hiện trên thân Tân Như Âm. Khi nàng tu chân, thể chất này khiến kinh mạch dần khô héo và đe dọa trực tiếp sinh mệnh.","detail":"Tân Như Âm giải thích thể chất của mình là Long ngâm chi chất của nam giới, nhưng vì sinh trên thân nữ nên hễ tu chân thì kinh mạch bị tổn hại nghiêm trọng. Đến chương này, kinh mạch nàng đã khô héo và chỉ còn khoảng hai năm sinh mệnh.","thuocTinh":"Thể chất đặc thù","yeuCau":"Vốn thuộc nam giới","uyLuc":"Không phải thần thông tấn công mà là thể chất gây đại giá trí mạng khi tu chân trên thân nữ.","dacDiem":"Tu chân làm kinh mạch khô héo, khiến Tân Như Âm suy kiệt sinh mệnh.","congNang":["Gắn với thể chất tu chân đặc biệt của Tân Như Âm, nhưng biểu hiện đã thấy là gây tổn hại kinh mạch khi nàng tu luyện."],"nguoiTu":[{"ten":"Tân Như Âm","tuChuong":"@c0352","tangDatToi":"Không rõ","trangThai":"bị thể chất phản phệ"}],"tabs":{"tienTrinh":[{"chuong":"@c0352","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ thể chất","text":"Tân Như Âm nói mình mắc Long ngâm chi chất vốn thuộc nam giới, vì sinh trên thân nữ nên tu chân khiến kinh mạch khô héo và chỉ còn khoảng hai năm sinh mệnh.","anchor":"Thể chất của thiếp là loại “Long ngâm chi chất” của nam giới"}]},"dinhDanh":"goc","capNhatToi":"@c0352","nguon":["@c0352"]},{"id":"truyen-tong-tran-co-xua","name":"Truyền Tống trận cổ xưa","cn":"","aliases":["Truyền tống trận cổ xưa","Truyền tống trận"],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"cổ xưa","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận pháp cổ xưa được Tân Như Âm sửa xong phương án khôi phục cho Hàn Lập. Đây là một đường lui quan trọng trong lúc tình hình Việt quốc bất ổn.","detail":"Tân Như Âm cho biết nàng đã sửa chữa xong Truyền Tống trận cổ xưa và giao lại ngọc giản ghi đầy đủ phương pháp, các bước chữa trị. Hàn Lập chưa lập tức sử dụng nhưng coi nó là phương án thoát thân cần suy xét.","dinhDanh":"goc","congNang":["Dịch chuyển hoặc mở ra một đường lui cho Hàn Lập khi được khôi phục theo chỉ dẫn @c0356"],"trangThai":"đã có phương pháp khôi phục","capNhatToi":"@c0356","tabs":{"tienTrinh":[{"chuong":"@c0356","loai":"xuất hiện","importance":"major","giaiDoan":"Sửa xong phương án khôi phục","text":"Tân Như Âm báo đã sửa xong Truyền Tống trận cổ xưa và giao ngọc giản phương pháp cho Hàn Lập.","anchor":"Ta hôm qua vừa mới đem Truyền tống trận cổ xưa kia sửa chữa xong"}]},"nguon":["@c0356"]},{"id":"phuong-phap-sua-truyen-tong-tran-co-xua","name":"Phương pháp sửa Truyền Tống trận cổ xưa","cn":"","aliases":[],"loai":"khac","loaiLabel":"Ngọc giản trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Ngọc giản ghi phương pháp và các bước chữa trị Truyền Tống trận cổ xưa. Tân Như Âm giao vật này cho Hàn Lập sau khi hoàn thành nghiên cứu sửa trận.","detail":"Nội dung trong ngọc giản bao gồm phương pháp cùng các bước chữa trị rất đầy đủ, giúp Hàn Lập có thể theo chỉ dẫn để khôi phục Truyền Tống trận cổ xưa về trạng thái bình thường.","dinhDanh":"goc","congNang":["Hướng dẫn khôi phục Truyền Tống trận cổ xưa theo từng phương pháp và bước chữa trị @c0356"],"trangThai":"đã giao cho Hàn Lập","capNhatToi":"@c0356","tabs":{"tienTrinh":[{"chuong":"@c0356","loai":"xuất hiện","importance":"normal","giaiDoan":"Trao ngọc giản sửa trận","text":"Tân Như Âm giao cho Hàn Lập ngọc giản chứa phương pháp và các bước chữa trị Truyền Tống trận cổ xưa.","anchor":"quả nhiên có phương pháp và các bước chữa trị rất đầy đủ"}]},"nguon":["@c0356"]},{"id":"linh-thuat","name":"Linh thuật","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp/pháp thuật hệ Mộ Lan","phamCap":"Không rõ","hePhai":"Mộ Lan tộc","soHuu":["Pháp sĩ Mộ Lan tộc"],"blurb":"Hệ pháp thuật độc đáo của pháp sĩ Mộ Lan, hình thành từ ngũ hành đạo thuật kết hợp bí thuật thảo nguyên. Khi giao chiến cùng cấp, Linh thuật giúp pháp sĩ Mộ Lan có ưu thế nhất định.","detail":"Linh thuật là công pháp riêng của pháp sĩ Mộ Lan tộc, được hình thành do họ chuyên tâm nghiên cứu ngũ hành đạo thuật và bí thuật thảo nguyên thay vì quá lệ thuộc pháp khí, phù lục trước Kết Đan. Các thuật pháp này được mô tả là lợi hại và quỷ dị hơn, là nền tảng khiến pháp sĩ Mộ Lan nổi bật trong chiến đấu cùng cấp.","thuocTinh":"Ngũ hành đạo thuật kết hợp bí thuật thảo nguyên","nguonGoc":"Mộ Lan đại thảo nguyên","uyLuc":"Có thể giúp pháp sĩ Mộ Lan chiếm thế thượng phong khi giao chiến với tu sĩ cùng cấp.","dacDiem":"Lợi hại, quỷ dị, gắn với hệ thống tu luyện riêng của pháp sĩ Mộ Lan.","congNang":["Tăng năng lực chiến đấu của pháp sĩ Mộ Lan trong đối kháng cùng cấp @c0358"],"nguoiTu":[{"ten":"Pháp sĩ Mộ Lan tộc","tuChuong":"@c0358","tangDatToi":"","trangThai":"đang tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c0358","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới thiệu hệ pháp thuật Mộ Lan","text":"Linh thuật được giới thiệu là công pháp độc đáo do pháp sĩ Mộ Lan phát triển từ ngũ hành đạo thuật và bí thuật thảo nguyên.","anchor":"nghiên cứu tìm ra những loại pháp thuật mới lợi hại hơn, quỷ dị hơn, từ đó hình thành nên công pháp độc đáo riêng của chính mình gọi là “Linh thuật”"}]},"capNhatToi":"@c0358","dinhDanh":"goc","nguon":["@c0358"]},{"id":"tran-ky-huyen-hinh","name":"Trận kỳ huyễn hình","cn":"","loai":"khac","loaiLabel":"Trận cụ/trận pháp che giấu","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bộ trận kỳ được Hàn Lập dùng để che giấu cửa vào động quật chứa Truyền Tống trận cổ.","detail":"Hàn Lập dùng bộ trận kỳ mới nhận được để khiến cửa vào động quật dưới đất biến mất khỏi tầm mắt, tạo lớp che giấu trước khi tiếp tục tu bổ Truyền Tống trận cổ.","congNang":["Che giấu cửa vào động quật chứa Truyền Tống trận cổ @c0359"],"trangThai":"đang dùng","nguon":["@c0359"],"tabs":{"tienTrinh":[{"chuong":"@c0359","loai":"xuất hiện","importance":"normal","giaiDoan":"Che giấu động quật","text":"Hàn Lập dùng trận kỳ huyễn hình để che kín lối vào động quật chứa Truyền Tống trận cổ.","anchor":"đem cửa vào che giấu hoàn toàn"}]},"capNhatToi":"@c0359"},{"id":"ma-cong-ho-the-cua-thieu-chu-quy-linh-mon","name":"Ma công hộ thể của thiếu chủ Quỷ Linh môn","cn":"","loai":"than-thong","loaiLabel":"Ma công hộ thể","phamCap":"không rõ","hePhai":"Quỷ Linh môn","soHuu":["Vương Thiền"],"blurb":"Ma công hiện thành huyết vụ quanh Vương Thiền khi hắn truy đuổi Nam Cung Uyển.","detail":"Huyết vụ truy đuổi bạch quang khiến Hàn Lập liên tưởng tới ma công hộ thể quen thuộc của thiếu chủ Quỷ Linh môn, qua đó nhận ra thân phận Vương Thiền.","thuocTinh":"ma đạo","congNang":["Hộ thể và phối hợp phi độn dưới dạng huyết vụ @c0359"],"nguoiTu":[{"ten":"Vương Thiền","tuChuong":"@c0359","tangDatToi":"không rõ","trangThai":"đang dùng"}],"nguon":["@c0359"],"tabs":{"tienTrinh":[{"chuong":"@c0359","loai":"thi triển","importance":"normal","giaiDoan":"Truy đuổi Nam Cung Uyển","text":"Vương Thiền dùng huyết vụ khi truy đuổi Nam Cung Uyển, khiến Hàn Lập nhận ra dấu hiệu ma công hộ thể của thiếu chủ Quỷ Linh môn.","anchor":"ma công hộ thể của thiếu chủ Quỷ Linh môn sao"}]},"capNhatToi":"@c0359"},{"id":"huyen-nguyet-hap-am-cong","name":"Huyền Nguyệt Hấp Âm công","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật Hợp Hoan tông","phamCap":"không rõ","hePhai":"Hợp Hoan tông","soHuu":["Điền công tử"],"blurb":"Bí thuật song tu tà dị của Hợp Hoan tông được Vương Thiền nhắc đến khi bóc trần ý đồ của Điền công tử.","detail":"Theo lời Vương Thiền, bí thuật này cho phép nam tu thông qua song tu hấp nạp một phần nguyên âm của nữ tử. Điền công tử muốn nhắm vào nguyên âm của tu sĩ Kết Đan như Nam Cung Uyển để phá bình cảnh tiến vào Trúc Cơ hậu kỳ.","thuocTinh":"song tu, hấp âm","congNang":["Hấp nạp nguyên âm nữ tử thông qua song tu @c0359","Hỗ trợ Điền công tử mưu phá bình cảnh lên Trúc Cơ hậu kỳ @c0359"],"nguoiTu":[{"ten":"Điền công tử","tuChuong":"@c0359","tangDatToi":"dự định dùng","trangThai":"đang mưu tính"}],"nguon":["@c0359"],"tabs":{"tienTrinh":[{"chuong":"@c0359","loai":"nhắc tới","importance":"normal","giaiDoan":"Bóc trần mưu đồ","text":"Vương Thiền nói Điền công tử muốn dùng Huyền Nguyệt Hấp Âm công để hấp nạp nguyên âm của Nam Cung Uyển và phá bình cảnh.","anchor":"thông qua song tu chi thuật, đem nguyên âm của nữ tử"}]},"capNhatToi":"@c0359"},{"id":"kiem-quang-trang-cua-nam-cung-uyen","name":"Kiếm quang trắng của Nam Cung Uyển","cn":"","loai":"than-thong","loaiLabel":"Thần thông/kiếm thuật","phamCap":"không rõ","hePhai":"Yểm Nguyệt tông","soHuu":["Nam Cung Uyển"],"blurb":"Đòn kiếm quang trắng xóa do Nam Cung Uyển phóng ra khi phẫn nộ trước sự uy hiếp của hai tu sĩ Ma đạo.","detail":"Nam Cung Uyển tung một mảng kiếm quang trắng mênh mông với khí thế mạnh, khiến Vương Thiền và Điền công tử kinh hãi muốn lùi tránh.","thuocTinh":"kiếm quang","uyLuc":"Khiến hai tu sĩ Ma đạo Trúc Cơ đang truy kích nàng phải kinh hãi thoái lui.","congNang":["Công kích diện rộng bằng kiếm quang trắng xóa @c0359"],"nguoiTu":[{"ten":"Nam Cung Uyển","tuChuong":"@c0359","tangDatToi":"không rõ","trangThai":"đang dùng"}],"nguon":["@c0359"],"tabs":{"tienTrinh":[{"chuong":"@c0359","loai":"thi triển","importance":"normal","giaiDoan":"Phản kích truy binh","text":"Nam Cung Uyển phóng kiếm quang trắng xóa khiến Vương Thiền và Điền công tử kinh hãi lùi tránh.","anchor":"một mảng kiếm quang mênh mông trắng toát bắn ra"}]},"capNhatToi":"@c0359"},{"id":"bi-thuat-hao-nguyen-khi-cua-nam-cung-uyen","name":"Bí thuật hao nguyên khí của Nam Cung Uyển","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Nam Cung Uyển"],"blurb":"Bí thuật Nam Cung Uyển dùng khi trọng thương để cưỡng ép kích phát linh lực còn lại.","detail":"Bí thuật này tổn hao nhiều nguyên khí, giúp Nam Cung Uyển cường hành gia tăng một phần tiềm lực trong cơ thể để ngự khí bỏ chạy sau trận đại chiến nặng nề.","thuocTinh":"Hao tổn nguyên khí","uyLuc":"Cưỡng ép kích phát linh lực còn lại trong tình trạng trọng thương.","dacDiem":"Tác dụng cứu nguy nhưng phải trả giá bằng nguyên khí.","congNang":["Kích phát linh lực để bỏ chạy trong lúc pháp lực gần cạn @c0360"],"nguoiTu":[{"ten":"Nam Cung Uyển","tuChuong":"@c0360","tangDatToi":"","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c0360","loai":"thi triển","importance":"normal","giaiDoan":"Cứu nguy khi trọng thương","text":"Nam Cung Uyển vận dụng bí thuật tổn hao nguyên khí để cường hành kích phát linh lực bỏ chạy.","anchor":"vận dụng một loại bí thuật tổn hao nhiều nguyên khí, cường hành gia tăng một bộ phận tiềm lực trong cơ thể"}]},"capNhatToi":"@c0360","nguon":["@c0360"]},{"id":"ao-tran-cot-da","name":"Ảo trận cột đá","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Ảo trận xuất hiện giữa rừng, dùng để vây khốn Vương Thiền và Điền công tử khi truy kích Hàn Lập.","detail":"Ảo trận khiến cảnh rừng biến mất trong mắt truy binh, thay bằng vô số cột đá cực lớn, nhờ đó Hàn Lập kéo dài thời gian và thoát khỏi vòng vây.","thuocTinh":"Ảo trận vây khốn","uyLuc":"Có thể khiến truy binh tưởng như lao vào mục tiêu nhưng rơi vào không gian đầy cột đá.","dacDiem":"Không gian trong trận hiện ra vô số cột đá cao lớn.","congNang":["Vây khốn truy binh và che giấu đường thoát của Hàn Lập @c0360"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0360","tangDatToi":"","trangThai":"đã sử dụng"}],"tabs":{"tienTrinh":[{"chuong":"@c0360","loai":"xuất hiện","importance":"normal","giaiDoan":"Dụ địch vào trận","text":"Hàn Lập dụ Vương Thiền và Điền công tử lao vào ảo trận cột đá trong lúc rút lui cùng Nam Cung Uyển.","anchor":"Bốn phía đâu còn là rừng cây, tự nhiên xuất hiện vô số cột đá cực lớn"}]},"capNhatToi":"@c0360","nguon":["@c0360"]},{"id":"huyet-vu-cua-vuong-thien","name":"Huyết vụ của Vương Thiền","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Ma công/thần thông","phamCap":"Không rõ","hePhai":"Quỷ Linh môn","soHuu":["Vương Thiền"],"blurb":"Thần thông huyết vụ Vương Thiền triển khai để truy kích Hàn Lập sau khi Nam Cung Uyển được cứu.","detail":"Huyết vụ trên người Vương Thiền nhanh chóng phình lớn, bao phủ phạm vi hơn hai, ba mươi trượng và tỏa mùi máu tanh, dùng làm thế công truy sát trên diện rộng.","thuocTinh":"Huyết vụ ma công","uyLuc":"Bao phủ không gian hơn hai, ba mươi trượng với khí thế hung hãn.","dacDiem":"Mang mùi máu tanh rõ rệt khi mở rộng.","congNang":["Bao phủ diện rộng để truy kích và áp chế mục tiêu @c0360"],"nguoiTu":[{"ten":"Vương Thiền","tuChuong":"@c0360","tangDatToi":"","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c0360","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát Hàn Lập","text":"Vương Thiền triển khai huyết vụ để truy kích Hàn Lập và Nam Cung Uyển xuống rừng.","anchor":"đảo mắt đã che kín không gian hơn hai, ba mươi trượng, mùi máu tanh xộc lên"}]},"capNhatToi":"@c0360","nguon":["@c0360"]},{"id":"khong-tuoc-phan-hong-tu-sao-ngoc","name":"Khổng tước phấn hồng từ sáo ngọc","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông/pháp thuật","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Điền công tử"],"blurb":"Pháp thuật công kích do Điền công tử dùng sáo ngọc thi triển, hóa hào quang và âm thanh thành khổng tước phấn hồng.","detail":"Điền công tử huy động sáo ngọc, khiến âm thanh và hào quang hòa lẫn rồi biến thành một con khổng tước phấn hồng bay thẳng đến Hàn Lập trong cuộc truy sát.","thuocTinh":"Âm thanh và hào quang","uyLuc":"Tạo hình khổng tước phấn hồng để công kích mục tiêu đang bỏ chạy.","dacDiem":"Thi triển thông qua sáo ngọc của Điền công tử.","congNang":["Hóa âm thanh và hào quang thành khổng tước phấn hồng để truy sát @c0360"],"nguoiTu":[{"ten":"Điền công tử","tuChuong":"@c0360","tangDatToi":"","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c0360","loai":"thi triển","importance":"normal","giaiDoan":"Công kích Hàn Lập","text":"Điền công tử dùng sáo ngọc hóa thành khổng tước phấn hồng để công kích Hàn Lập.","anchor":"hào quang cùng âm thanh tương hỗ lẫn nhau, biến thành một con khổng tước mà phấn hồng"}]},"capNhatToi":"@c0360","nguon":["@c0360"]},{"id":"huyen-tran-don-gian","name":"Huyễn trận đơn giản","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận pháp đơn giản do Hàn Lập bố trí để tạm vây hai người bên Quỷ Linh Môn.","detail":"Hàn Lập tự nhận huyễn trận này không thể vây khốn hai người thiếu chủ Quỷ Linh Môn lâu, nên chỉ dùng nó như thủ đoạn kéo dài thời gian để rút lui.","dinhDanh":"goc","congNang":["Tạm vây địch trong thời gian ngắn @c0361"],"trangThai":"đã dùng","capNhatToi":"@c0361","tabs":{"tienTrinh":[{"chuong":"@c0361","loai":"xuất hiện","importance":"normal","giaiDoan":"Tạm vây Quỷ Linh Môn","text":"Hàn Lập dùng huyễn trận đơn giản để tạm giữ hai người bên Quỷ Linh Môn, nhưng biết trận này không thể kéo dài lâu.","anchor":"Dù sao hắn bố trí một huyễn trận đơn giản tuyệt không thể vây khốn được hai người thiếu chủ Quỷ Linh Môn lâu được"}]},"nguon":["@c0361"]},{"id":"ma-cong","name":"Ma Công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"","soHuu":["Đổng Huyên Nhi"],"blurb":"Công pháp được Đổng Huyên Nhi vận dụng trong lúc đối phó Hàn Lập.","detail":"Đổng Huyên Nhi dung hợp Ma Công với Hỏa Phượng Cân để tạo thành vòng bảo hộ cường đại trước thế công của Hàn Lập.","dinhDanh":"goc","congNang":["Hợp với pháp khí để tạo hộ tráo cường đại @c0361"],"nguoiTu":[{"ten":"Đổng Huyên Nhi","tuChuong":"@c0361","tangDatToi":"","trangThai":"đang dùng"}],"capNhatToi":"@c0361","tabs":{"tienTrinh":[{"chuong":"@c0361","loai":"thi triển","importance":"normal","giaiDoan":"Hộ thân trước hư chiêu","text":"Đổng Huyên Nhi vận Ma Công phối hợp Hỏa Phượng Cân để dựng vòng bảo hộ khi Hàn Lập giả vờ công kích toàn lực.","anchor":"Hỏa Phượng Cân” cùng với “Ma Công” dung hợp tạo thành một vòng bảo hộ cường đại này"}]},"nguon":["@c0361"]},{"id":"luan-hoi-chan-quyet","name":"Luân hồi chân quyết","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Bí thuật Yểm Nguyệt Tông","hePhai":"Yểm Nguyệt Tông","soHuu":["Nam Cung Bình"],"blurb":"Luân hồi chân quyết là công pháp của Yểm Nguyệt Tông từng hút chân nguyên của Hàn Lập trong tình thế đặc biệt. Công pháp có thể bù phần chân nguyên hao tổn nhưng điều kiện thi triển cực kỳ hà khắc.","detail":"Khi người thi triển hao tổn chân nguyên nghiêm trọng và gặp nguy cơ rơi vào tay địch, Luân hồi chân quyết có thể phát động để hút chân nguyên của người khác theo cơ chế linh lực xoắn ốc. Nếu không có chân nguyên bổ sung, người thi triển có nguy cơ tự bạo; phần chân nguyên hút được chỉ bù lại hao tổn trước đó, không giúp tăng thêm tu vi.","thuocTinh":"Hút chân nguyên, bù hao tổn","nguonGoc":"Bí thuật của Yểm Nguyệt Tông","yeuCau":"Chỉ phát động trong tình thế đặc biệt khi chân nguyên hao tổn nghiêm trọng","uyLuc":"Có thể hấp thu chân nguyên từ ngoại nhân đang đưa linh lực vào thân thể người thi triển.","dacDiem":"Điều kiện hà khắc, gần như bán tự sát và không dùng để tăng tu vi vượt phần đã hao tổn.","congNang":["Hút chân nguyên người khác để bù phần chân nguyên đã hao tổn @c0362"],"nguoiTu":[{"ten":"Nam Cung Bình","tuChuong":"@c0362","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0362","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ tên và cơ chế","text":"Luân hồi chân quyết được giải thích là công pháp đã hút chân nguyên của Hàn Lập, có cơ chế hấp thu linh lực trong điều kiện nguy cấp và chỉ bù phần hao tổn.","anchor":"liền cắn răng phát động công pháp “Luân hồi chân quyết”"}]},"trangThai":"đã lộ cơ chế","capNhatToi":"@c0362","dinhDanh":"goc","nguon":["@c0362"]}]};
